#[cfg(all(feature = "dataforts", feature = "cortex"))]
impl MeshNode {
    /// Send an overflow push nudge to `target_node_id`. The
    /// chunk bytes themselves don't ride this RPC — the
    /// nudge tells the receiver to open the chunk channel
    /// against its local Redex with replication armed; the
    /// existing per-chunk replication runtime pulls the
    /// bytes from any holder advertising `causal:<hash>`
    /// (typically this node, since we're shedding it).
    ///
    /// `Ok(OverflowPushAck::Accepted)` means the receiver
    /// accepted + opened the chunk channel. The sender still
    /// has to observe the durability watermark (the target's
    /// `causal:<hash>` advertisement) before deleting the
    /// local copy — that's the safe-delete gate. Per the
    /// overflow plan, this two-phase pattern lets a failed
    /// open on the receive side (network blip during chunk
    /// pull) keep the bytes alive on the sender.
    ///
    /// Maps non-`Ok` results to typed [`BlobError`] so the
    /// controller's `push_errors` counter bumps uniformly.
    /// See [`super::dataforts::blob::overflow::OverflowPushAck`]
    /// for the variant breakdown.
    ///
    /// [`BlobError`]: super::dataforts::blob::BlobError
    pub async fn send_overflow_push(
        self: &Arc<Self>,
        target_node_id: u64,
        blob_hash: [u8; 32],
        size_bytes: u64,
    ) -> Result<super::dataforts::blob::overflow::OverflowPushAck, super::dataforts::blob::BlobError>
    {
        use super::dataforts::blob::overflow::{
            OverflowPush, OverflowPushAck, OVERFLOW_PUSH_SERVICE,
        };
        use super::dataforts::blob::BlobError;

        let request = OverflowPush {
            blob_hash,
            size_bytes,
            sender_node_id: self.node_id(),
        };
        let body = postcard::to_allocvec(&request)
            .map_err(|e| BlobError::Backend(format!("overflow push: encode failed: {e}")))?;
        let reply = self
            .call(
                target_node_id,
                OVERFLOW_PUSH_SERVICE,
                bytes::Bytes::from(body),
                super::mesh_rpc::CallOptions::default(),
            )
            .await
            .map_err(|e| BlobError::Backend(format!("overflow push: RPC failed: {e}")))?;
        let ack: OverflowPushAck = postcard::from_bytes(&reply.body)
            .map_err(|e| BlobError::Backend(format!("overflow push: decode ack failed: {e}")))?;
        Ok(ack)
    }

    /// Register the receive-side overflow-push handler on
    /// this node. The handler reads live local caps + the
    /// capability index on each request, runs admission,
    /// and on Admit opens the chunk channel against
    /// `adapter` via [`super::dataforts::blob::adapter::BlobAdapter::prefetch`].
    ///
    /// Returns the [`super::mesh_rpc::ServeHandle`] the
    /// operator drops to deregister the handler. Multiple
    /// calls on the same node would conflict on the service
    /// name; the second call returns
    /// [`super::mesh_rpc::ServeError::AlreadyServing`].
    pub fn serve_overflow_push(
        self: &Arc<Self>,
        adapter: Arc<super::dataforts::blob::MeshBlobAdapter>,
    ) -> Result<super::mesh_rpc::ServeHandle, super::mesh_rpc::ServeError> {
        use super::dataforts::blob::overflow::{OverflowPushHandler, OVERFLOW_PUSH_SERVICE};
        let handler = Arc::new(OverflowPushHandler::new(Arc::clone(self), adapter));
        self.serve_rpc(OVERFLOW_PUSH_SERVICE, handler)
    }

    /// Rebroadcast the local capability set with the
    /// `dataforts.blob.overflow` tag set to match `adapter`'s
    /// current `overflow_enabled()` state. Convenience for
    /// operators who flip [`super::dataforts::blob::MeshBlobAdapter::set_overflow_enabled`]
    /// at runtime: the boolean lives on the adapter, but the
    /// capability index reads from this node's announced caps,
    /// so peers only observe the change after the next
    /// announce. Without this helper, every toggle path needs a
    /// matching `announce_capabilities` call — easy to forget,
    /// and the symptom (sender keeps round-tripping pushes that
    /// reject `SenderNotOverflowing`) is non-obvious.
    ///
    /// Snapshots the current user caps, sets / clears the
    /// presence tag based on `adapter.overflow_enabled()`, and
    /// announces the updated set. Returns the
    /// [`AdapterError`] from the inner `announce_capabilities`
    /// if the announce fails (rate-limited, transport down,
    /// etc.).
    pub async fn announce_blob_overflow_state(
        &self,
        adapter: &super::dataforts::blob::MeshBlobAdapter,
    ) -> Result<(), super::AdapterError> {
        use super::behavior::{BlobCapability, Tag, TaxonomyAxis};
        let mut caps = self.user_caps_snapshot();
        let enabled = adapter.overflow_enabled();
        let present = BlobCapability::from_capability_set(&caps).overflow_enabled;
        if enabled == present {
            // Snapshot already matches the adapter's runtime
            // state — nothing to broadcast. Still re-announce
            // to push any caller-supplied caps that may have
            // landed via a different path; cheap (rate-limited
            // upstream).
            return self.announce_capabilities(caps).await;
        }
        let target = Tag::AxisPresent {
            axis: TaxonomyAxis::Dataforts,
            key: "blob.overflow".to_string(),
        };
        if enabled {
            caps.tags.insert(target);
        } else {
            caps.tags.remove(&target);
        }
        self.announce_capabilities(caps).await
    }
}

#[cfg(feature = "dataforts")]
impl MeshNode {
    /// Install the blob-transfer engine over `adapter` (FairScheduler
    /// transport plan). After this, the node serves on-demand chunk
    /// fetches (the `SUBPROTOCOL_BLOB_TRANSFER` control branch + the
    /// transfer-stream data divert route to the engine) and can issue
    /// them via [`Self::transfer_fetch_chunk`]. Idempotent — re-install
    /// replaces the engine.
    ///
    /// Returns the installed engine handle — the same one stored on the
    /// node — so callers (e.g. the `blob.transfers` RPC install) can serve
    /// introspection over the exact registry that's doing the fetches.
    pub fn serve_blob_transfer(
        self: &Arc<Self>,
        adapter: Arc<super::dataforts::blob::MeshBlobAdapter>,
    ) -> Arc<super::dataforts::blob::transfer::BlobTransferEngine> {
        let engine = Arc::new(super::dataforts::blob::transfer::BlobTransferEngine::new(
            self, adapter,
        ));
        *self.blob_transfer_engine.write() = Some(engine.clone());
        engine
    }

    /// Fetch the chunk addressed by `hash` from `holder` over a
    /// reliable, scheduled transfer stream — bytes move over the
    /// FairScheduler-managed stream transport, not RedEX replication or
    /// nRPC. Returns the BLAKE3-verified bytes, or
    /// [`BlobError::NotFound`] on a holder miss / timeout (so the caller
    /// can fail over to another advertised holder).
    ///
    /// [`BlobError`]: super::dataforts::blob::BlobError
    /// [`BlobError::NotFound`]: super::dataforts::blob::BlobError::NotFound
    pub async fn transfer_fetch_chunk(
        self: &Arc<Self>,
        holder: u64,
        hash: [u8; 32],
    ) -> Result<bytes::Bytes, super::dataforts::blob::BlobError> {
        use super::dataforts::blob::transfer::{next_transfer_stream_id, TransferControl};
        use super::dataforts::blob::BlobError;

        let engine = self.blob_transfer_engine.read().clone().ok_or_else(|| {
            BlobError::Backend("blob transfer: engine not installed (serve_blob_transfer?)".into())
        })?;
        let stream_id = next_transfer_stream_id();
        let (tx, rx) = tokio::sync::oneshot::channel();
        engine.register_pending(stream_id, holder, hash, tx);

        // Open the receive stream RELIABLE up front so it tracks SACK and
        // NACKs lost sequences. The holder sends RELIABLE data; the
        // requester must mirror that reliability to recover drops —
        // otherwise the receive stream (auto-created on first packet, or
        // by the control send below) defaults to fire-and-forget and
        // never asks for a retransmit. Receiver-only, so no scheduled
        // flag / fairness weight is needed.
        let _ = self.open_stream(
            holder,
            stream_id,
            StreamConfig::new().with_reliability(super::Reliability::Reliable),
        );

        if let Err(e) = self
            .send_transfer_control(holder, stream_id, &TransferControl::Request { hash })
            .await
        {
            engine.cancel_pending(stream_id);
            return Err(BlobError::Backend(format!(
                "blob transfer: send request failed: {e}"
            )));
        }

        match tokio::time::timeout(std::time::Duration::from_secs(30), rx).await {
            Ok(Ok(result)) => result,
            Ok(Err(_canceled)) => {
                engine.cancel_pending(stream_id);
                Err(BlobError::Backend(
                    "blob transfer: engine dropped the reply".into(),
                ))
            }
            Err(_elapsed) => {
                engine.cancel_pending(stream_id);
                Err(BlobError::NotFound(format!(
                    "blob transfer: timed out fetching mesh://{}",
                    Self::blob_hex(&hash)
                )))
            }
        }
    }

    /// Fetch the chunk addressed by `hash` from whichever connected
    /// peer holds it, without the caller naming a holder. Probes peers
    /// in turn over the transfer transport: a peer that lacks the chunk
    /// replies `NotFound` promptly (so misses are cheap), and the first
    /// peer that serves the BLAKE3-verified bytes wins. Returns
    /// [`BlobError::NotFound`] if no connected peer has it (the caller
    /// may then fall back to its own backend or fail the read).
    ///
    /// This is the usable "fetch by content hash" entry point that
    /// [`Self::transfer_fetch_chunk`] (which requires a known holder)
    /// can't be on its own.
    ///
    /// **Discovery model (deliberate).** v1 probes connected peers
    /// directly rather than consulting the capability fold for
    /// `causal:<hash>` advertisers. The per-chunk `causal:<hex64>` tag
    /// is a single-datagram advertisement that caps at ~15-20
    /// chunks/node, so it does not scale as a per-chunk holder index —
    /// which is exactly why the directory transfer
    /// ([`super::dataforts::dir`]) pulls from a *known* source instead.
    /// Probing sidesteps the ceiling entirely: the holder's prompt
    /// `NotFound` is the membership test. A future optimization can use
    /// a node-level "serves blobs" capability (one tag, no ceiling) or a
    /// dedicated zero-byte probe frame to ORDER / prune candidates and
    /// to stay robust against a silent peer; today each probe is bounded
    /// by [`DISCOVERY_PROBE_TIMEOUT`] so one unresponsive peer can't
    /// stall the whole search.
    ///
    /// [`BlobError::NotFound`]: super::dataforts::blob::BlobError::NotFound
    /// [`DISCOVERY_PROBE_TIMEOUT`]: Self::transfer_fetch_chunk_discovered
    pub async fn transfer_fetch_chunk_discovered(
        self: &Arc<Self>,
        hash: [u8; 32],
    ) -> Result<bytes::Bytes, super::dataforts::blob::BlobError> {
        use super::dataforts::blob::BlobError;

        // Generous enough for a max-chunk (≤4 MiB) transfer from a
        // healthy holder, tight enough that a silent peer only costs
        // this once before the search moves on. A miss returns its
        // `NotFound` long before this fires.
        const DISCOVERY_PROBE_TIMEOUT: Duration = Duration::from_secs(10);

        let candidates: Vec<u64> = self.peers.iter().map(|e| *e.key()).collect();
        if candidates.is_empty() {
            return Err(BlobError::NotFound(format!(
                "blob transfer: no connected peers to discover mesh://{}",
                Self::blob_hex(&hash)
            )));
        }
        for peer in candidates {
            match tokio::time::timeout(
                DISCOVERY_PROBE_TIMEOUT,
                self.transfer_fetch_chunk(peer, hash),
            )
            .await
            {
                // First holder to serve the verified bytes wins.
                Ok(Ok(bytes)) => return Ok(bytes),
                // Peer doesn't have it / transient error / went silent —
                // try the next candidate.
                Ok(Err(_)) | Err(_) => continue,
            }
        }
        Err(BlobError::NotFound(format!(
            "blob transfer: no connected peer served mesh://{}",
            Self::blob_hex(&hash)
        )))
    }

    /// Send a blob-transfer control packet (subprotocol-tagged, tiny)
    /// to `peer` on `stream_id`. Goes straight to the socket — control
    /// is a single small packet; reliability is the requester's
    /// timeout-and-retry, not per-packet retransmit.
    async fn send_transfer_control(
        &self,
        peer: u64,
        stream_id: u64,
        control: &super::dataforts::blob::transfer::TransferControl,
    ) -> Result<(), super::AdapterError> {
        let (dest_addr, session) = match self.peers.get(&peer) {
            Some(p) => (p.value().addr, p.value().session.clone()),
            None => {
                return Err(super::AdapterError::Connection(format!(
                    "transfer control: no session for {peer:#x}"
                )))
            }
        };
        let bytes = bytes::Bytes::from(postcard::to_allocvec(control).map_err(|e| {
            super::AdapterError::Connection(format!("transfer control: encode failed: {e}"))
        })?);
        let pool = session.thread_local_pool();
        let mut builder = pool.get();
        let seq = session.get_or_create_stream(stream_id).next_tx_seq();
        let events = [bytes];
        let packet = builder.build_subprotocol(
            stream_id,
            seq,
            &events,
            PacketFlags::RELIABLE,
            super::dataforts::blob::SUBPROTOCOL_BLOB_TRANSFER,
        );
        self.socket.send_to(&packet, dest_addr).await.map_err(|e| {
            super::AdapterError::Connection(format!("transfer control: send failed: {e}"))
        })?;
        Ok(())
    }
}

#[cfg(feature = "net")]
impl MeshNode {
    /// Install (or replace) the `SUBPROTOCOL_REDEX` inbound
    /// router. Used by `Redex` to register a per-node router
    /// that owns the per-channel runtime registry; the mesh
    /// dispatch hot-path consults this router on every inbound
    /// `SUBPROTOCOL_REDEX` frame.
    ///
    /// Passing `None` un-installs the router — every subsequent
    /// inbound replication frame is dropped silently until a new
    /// router is installed.
    #[cfg(feature = "redex")]
    pub fn set_replication_inbound_router(
        &self,
        router: Option<Arc<dyn super::redex::ReplicationInboundRouter>>,
    ) {
        *self.replication_inbound_router.write() = router;
    }

    /// Install (or replace) the `SUBPROTOCOL_MESHDB` inbound
    /// router. The MeshDB transport installs one of these to
    /// receive federated-query traffic — both inbound requests
    /// (routed to the server-side query handler) and inbound
    /// responses (routed to the matching in-flight caller).
    ///
    /// Passing `None` un-installs the router — subsequent
    /// inbound MeshDB frames are dropped silently until a new
    /// router is installed.
    ///
    /// Idempotent — re-installing replaces the previous handle.
    /// Hot-path cost is one `parking_lot::RwLock` read per
    /// inbound `SUBPROTOCOL_MESHDB` frame.
    #[cfg(feature = "meshdb")]
    pub fn set_meshdb_inbound_router(
        &self,
        router: Option<Arc<dyn super::behavior::meshdb::MeshDbInboundRouter>>,
    ) {
        *self.meshdb_inbound_router.write() = router;
    }

    /// True iff a MeshDB inbound router is currently installed.
    /// Useful for tests and the operator surface to confirm the
    /// install landed.
    #[cfg(feature = "meshdb")]
    pub fn has_meshdb_inbound_router(&self) -> bool {
        self.meshdb_inbound_router.read().is_some()
    }

    /// Install (or uninstall) the fold-framework channel router.
    /// Absent router = fold packets dropped silently.
    /// Idempotent; re-installing replaces the previous handle.
    pub fn set_fold_router(
        &self,
        router: Option<Arc<dyn super::behavior::fold::FoldChannelRouter>>,
    ) {
        *self.fold_router.write() = router;
    }

    /// True iff a fold-framework channel router is currently
    /// installed. Useful for tests and the operator surface to
    /// confirm the install landed.
    pub fn has_fold_router(&self) -> bool {
        self.fold_router.read().is_some()
    }

    /// Aggregated [`super::behavior::fold::FoldStats`] for every
    /// fold the installed router addresses. The
    /// `net-mesh fold list` CLI command and the Deck FOLDS panel
    /// call this once per scrape tick. Returns an empty `Vec`
    /// when no router is installed.
    pub fn fold_stats(&self) -> Vec<super::behavior::fold::FoldStats> {
        let guard = self.fold_router.read();
        let Some(router) = guard.as_ref() else {
            return Vec::new();
        };
        router.stats()
    }

    /// Install (or uninstall) the greedy-LRU observer. `Redex`
    /// calls this from
    /// [`Redex::enable_greedy_dataforts`](super::redex::Redex)
    /// to wire the inbound dispatch fanout. `None` uninstalls;
    /// subsequent standard-event packets fall through the
    /// observer hook untouched.
    ///
    /// Idempotent — re-installing replaces the previous handle.
    /// Hot-path cost is unchanged when called with the same Arc.
    #[cfg(feature = "dataforts")]
    pub fn set_greedy_observer(&self, observer: Option<Arc<dyn super::dataforts::GreedyObserver>>) {
        *self.greedy_observer.write() = observer;
    }

    /// True iff a greedy observer is currently installed. Useful
    /// for tests and for the operator surface to confirm the
    /// install landed.
    #[cfg(feature = "dataforts")]
    pub fn has_greedy_observer(&self) -> bool {
        self.greedy_observer.read().is_some()
    }

    /// Return every node currently advertising any `causal:<hex>*`
    /// variant for `origin_hash`. Includes this node when self-
    /// indexed. Sorted by ascending RTT from this node where the
    /// proximity graph has measurements, with self at the front
    /// and unmeasured peers (no recent ping) at the back; among
    /// equally-measured peers, ties broken by ascending NodeId.
    ///
    /// Reads the capability fold directly; no broadcast.
    pub fn find_chain_holders(&self, origin_hash: u64) -> Vec<u64> {
        let hex = Self::chain_hex(origin_hash);
        let mut holders: Vec<u64> = self.capability_fold.with_state(|state| {
            let mut seen: std::collections::HashSet<u64> = std::collections::HashSet::new();
            for entry in state.entries.values() {
                if seen.contains(&entry.node_id) {
                    continue;
                }
                if entry
                    .payload
                    .tags
                    .iter()
                    .any(|t| Self::is_causal_for_str(t, &hex))
                {
                    seen.insert(entry.node_id);
                }
            }
            seen.into_iter().collect::<Vec<u64>>()
        });

        // Proximity sort: self first (RTT == 0), then peers with
        // measured RTT in ascending order, then unmeasured peers,
        // ties broken by lex NodeId. Mirrors the
        // `REDEX_DISTRIBUTED_PLAN.md` §4 `elect()` ordering.
        let self_id = self.node_id;
        let proximity = self.proximity_graph.clone();
        let rtt_of = |node: u64| -> Option<std::time::Duration> {
            if node == self_id {
                Some(std::time::Duration::ZERO)
            } else {
                let graph_id = node_id_to_graph_id(node);
                proximity.nearest_rtt(|n| n.node_id == graph_id)
            }
        };
        holders.sort_by(|&a, &b| {
            let rtt_a = rtt_of(a);
            let rtt_b = rtt_of(b);
            match (rtt_a, rtt_b) {
                (Some(da), Some(db)) => match da.cmp(&db) {
                    std::cmp::Ordering::Equal => a.cmp(&b),
                    other => other,
                },
                (Some(_), None) => std::cmp::Ordering::Less,
                (None, Some(_)) => std::cmp::Ordering::Greater,
                (None, None) => a.cmp(&b),
            }
        });
        holders
    }

    /// Query the capability fold. Returns node ids (including our
    /// own `node_id`) whose latest announcement matches `filter`.
    /// Routes through `capability_bridge::find_nodes_matching` so
    /// post-query predicates (memory, vram, GPU) execute in-memory
    /// alongside the fold's tag-based intersection.
    pub fn find_nodes_by_filter(&self, filter: &CapabilityFilter) -> Vec<u64> {
        super::behavior::fold::capability_bridge::find_nodes_matching(&self.capability_fold, filter)
    }

    /// Scoped variant of [`Self::find_nodes_by_filter`]. Filters
    /// candidates through `scope` (derived from each peer's
    /// `scope:*` reserved tags) on top of the capability filter.
    /// `SubnetLocal` peers and the [`ScopeFilter::SameSubnet`]
    /// filter resolve same-subnet membership against
    /// `peer_subnets`.
    ///
    /// **Warm-up rule.** When a peer's subnet is unknown:
    /// - **With** a `local_subnet_policy`, the candidate is
    ///   admitted (a fresh peer's announcement may not have
    ///   landed yet — the policy will resolve it on receipt).
    /// - **Without** a `local_subnet_policy`, `peer_subnets`
    ///   stays permanently empty (the dispatch handler only
    ///   writes it when a policy is installed), so "unknown"
    ///   means "will never resolve" — admitting unknowns there
    ///   leaks every peer through `SameSubnet`. The candidate
    ///   is excluded.
    pub fn find_nodes_by_filter_scoped(
        &self,
        filter: &CapabilityFilter,
        scope: &ScopeFilter<'_>,
    ) -> Vec<u64> {
        let my_subnet = self.local_subnet;
        let peer_subnets = self.peer_subnets.clone();
        let local_node_id = self.node_id;
        // See doc-comment: without a policy, an unresolvable
        // "unknown" cannot be admitted as same-subnet.
        let policy_installed = self.local_subnet_policy.is_some();
        super::behavior::fold::capability_bridge::find_nodes_matching_scoped(
            &self.capability_fold,
            filter,
            scope,
            |nid| {
                if nid == local_node_id {
                    return true;
                }
                match peer_subnets.get(&nid).map(|e| *e.value()) {
                    Some(s) => s == my_subnet,
                    None => policy_installed,
                }
            },
        )
    }

    /// Read a peer's most recently advertised public reflex
    /// `SocketAddr` from the capability index. `None` before the
    /// peer has sent a stage-2 announcement, or when the peer was
    /// compiled without `nat-traversal`.
    ///
    /// Stage 3 (rendezvous) reads this field to resolve the punch
    /// target's public address. Exposed for observability and for
    /// tests that want to verify capability-announcement propagation
    /// of the reflex field.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub fn peer_reflex_addr(&self, peer_node_id: u64) -> Option<std::net::SocketAddr> {
        super::behavior::fold::reflex_addr_for(&self.capability_fold, peer_node_id)
    }

    /// Read a peer's most recently advertised NAT classification
    /// from the capability index. Parses the `nat:*` tag on the
    /// peer's announcement. Returns `NatClass::Unknown` when the
    /// peer has not indexed (we've never received an announcement),
    /// or the announcement carried no `nat:*` tag (peer was
    /// compiled without `nat-traversal`, or hasn't classified yet).
    ///
    /// Consumed by the pair-type matrix (plan §3) — `connect_direct`
    /// reads this to decide whether to attempt a punch or
    /// short-circuit to the routed path.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub fn peer_nat_class(&self, peer_node_id: u64) -> super::traversal::classify::NatClass {
        use super::traversal::classify::NatClass;
        self.capability_fold.with_state(|state| {
            let Some(keys) = state.by_node.get(&peer_node_id) else {
                return NatClass::Unknown;
            };
            for key in keys {
                let Some(entry) = state.entries.get(key) else {
                    continue;
                };
                for tag in entry.payload.tags.iter() {
                    if let Some(class) = NatClass::from_tag(tag) {
                        return class;
                    }
                }
            }
            NatClass::Unknown
        })
    }

    /// Cumulative traversal counters — punch attempts, successes,
    /// and relay fallbacks. Returns a consistent point-in-time
    /// snapshot.
    ///
    /// See [`super::traversal::TraversalStatsSnapshot`] for the
    /// field semantics. The base counters are monotonic and never
    /// reset, so deltas between snapshots are safe — with two
    /// exceptions: `punches_failed` is DERIVED at snapshot time
    /// (`attempted - succeeded`) and can decrease when an in-flight
    /// punch lands, and `port_mapping_renewals` resets to zero on
    /// each fresh mapping install. Compute rates from the base
    /// counters, not the derived/resettable fields.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub fn traversal_stats(&self) -> super::traversal::TraversalStatsSnapshot {
        self.traversal_stats.snapshot()
    }

    /// Whether the session to `peer_id` reachable at `addr` is
    /// **relay-routed** rather than direct. Signal: `addr_to_node[addr]`
    /// — the node owning that transport address — is someone *other
    /// than* `peer_id` (a relay), or the address isn't registered at
    /// all. A direct session's address is owned by the peer itself. An
    /// unknown address counts as relayed — the conservative default
    /// that makes the upgrade loop re-examine it and coordinator
    /// selection exclude it. Single source of truth for the
    /// relayed-vs-direct test shared by [`Self::select_punch_coordinator`],
    /// [`Self::attempt_direct_upgrade`], and
    /// [`Self::upgrade_is_loop_candidate`], so the three can't drift
    /// apart on the default or the ownership rule.
    #[cfg(feature = "nat-traversal")]
    fn is_relayed_peer(&self, peer_id: u64, addr: &SocketAddr) -> bool {
        self.addr_to_node
            .get(addr)
            .map(|owner| *owner != peer_id)
            .unwrap_or(true)
    }

    /// Pick a rendezvous coordinator for a punch to `target`, without
    /// the caller having to name one (`NAT_TRAVERSAL_V2_PLAN.md`
    /// decision 5). Four tiers, graceful degradation:
    ///
    /// 1. **Routing next-hop.** For a relay-reached target, the peer
    ///    currently forwarding to it demonstrably has live sessions
    ///    with both ends — the highest-probability coordinator, and no
    ///    discovery needed.
    /// 2. **`relay-capable` direct peer.** A mutual direct peer that
    ///    advertised `RELAY_CAPABLE_TAG`. Picked at random from the
    ///    tier's candidates (not lowest-`node_id`): a deterministic
    ///    pick would funnel every requester's punches through one peer,
    ///    making it a mesh-wide coordinator hotspot and single point of
    ///    failure.
    /// 3. **Any direct peer.** Best-effort; the chosen peer may lack a
    ///    session with the target, in which case its coordinator
    ///    rejects with `NoSessionWithTarget` and the caller falls back.
    /// 4. **None.** No candidate — the caller surfaces
    ///    `RendezvousNoRelay` and stays on the routed path.
    ///
    /// Never fails a connection: a `None` here only means the punch
    /// optimization isn't attempted, never that the peer is
    /// unreachable.
    #[cfg(feature = "nat-traversal")]
    pub fn select_punch_coordinator(&self, target: u64) -> Option<u64> {
        // Tier 1: the relay currently forwarding to the target. Only
        // yields a distinct node for a relay-reached target — for a
        // direct peer the next hop is the target itself (excluded).
        if let Some(next_hop) = self.router.routing_table().lookup(target) {
            if let Some(nid) = self.addr_to_node.get(&next_hop).map(|e| *e.value()) {
                if nid != target && nid != self.node_id && self.peers.contains_key(&nid) {
                    return Some(nid);
                }
            }
        }

        // Tiers 2 & 3: collect the direct mutual peers (excluding self
        // and the target), then split into relay-capable and any.
        // Collected (not min-reduced) so the pick can be spread across
        // the tier's candidates — see `spread_pick`.
        let mut any: Vec<u64> = Vec::new();
        for entry in self.peers.iter() {
            let nid = *entry.key();
            if nid == target || nid == self.node_id {
                continue;
            }
            // Only genuinely DIRECT peers qualify (cubic P2): the peer
            // table also holds relay-routed sessions whose `addr` is the
            // relay's. A routed "coordinator" is doubly wrong — our
            // PunchRequest would land at the relay's address (whose
            // session can't decrypt it), and even if it arrived, the
            // coordinator's anti-reflection guard would reject the
            // routed pair anyway.
            if self.is_relayed_peer(nid, &entry.value().addr) {
                continue;
            }
            any.push(nid);
        }
        // Relay-capable subset, resolved in ONE fold lock for the whole
        // candidate batch — the prior code took the fold lock and
        // allocated a tag `Vec` for every candidate just to test one tag.
        let relay_capable_set = super::behavior::fold::nodes_with_capability_tag(
            &self.capability_fold,
            &any,
            super::behavior::capability::RELAY_CAPABLE_TAG,
        );

        // Tier 2 preferred, tier 3 fallback, else tier 4 (None). Spread
        // the pick within the chosen tier so load doesn't concentrate.
        if !relay_capable_set.is_empty() {
            let relay_capable: Vec<u64> = any
                .iter()
                .copied()
                .filter(|nid| relay_capable_set.contains(nid))
                .collect();
            Self::spread_pick(&relay_capable)
        } else {
            Self::spread_pick(&any)
        }
    }

    /// Pick one node id from `pool` at random, spread across calls so
    /// rendezvous-coordination load doesn't concentrate on one peer.
    /// Uses a freshly-seeded [`RandomState`] hash for per-call entropy
    /// (the same OS-entropy trick as `adapter::dedup_state`) — cheap,
    /// dependency-free, and varies both across requesters and across a
    /// single requester's retries, so no node becomes a coordinator
    /// hotspot / SPOF. Returns `None` only for an empty pool.
    ///
    /// [`RandomState`]: std::collections::hash_map::RandomState
    #[cfg(feature = "nat-traversal")]
    fn spread_pick(pool: &[u64]) -> Option<u64> {
        use std::hash::BuildHasher;
        if pool.is_empty() {
            return None;
        }
        let salt = std::collections::hash_map::RandomState::new().hash_one(pool.len() as u64);
        pool.get((salt % pool.len() as u64) as usize).copied()
    }

    /// Like [`Self::connect_direct`], but auto-selects the rendezvous
    /// coordinator via [`Self::select_punch_coordinator`] instead of
    /// taking one from the caller — the ergonomic entry point for
    /// "just give me the best path to this peer."
    ///
    /// - `Direct` pairs don't need a coordinator (the peer is publicly
    ///   reachable), so this delegates straight through.
    /// - `SinglePunch` / `SkipPunch` pairs need one; if no candidate
    ///   exists, returns [`super::traversal::TraversalError::RendezvousNoRelay`]
    ///   — the tier-4 skip. The caller stays on the routed-handshake
    ///   path (connectivity is never at risk; the punch is the
    ///   optimization).
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn connect_direct_auto(
        &self,
        peer_node_id: u64,
        peer_pubkey: &[u8; 32],
    ) -> Result<u64, super::traversal::TraversalError> {
        use super::traversal::classify::{pair_action, PairAction};
        use super::traversal::TraversalError;

        let action = pair_action(self.nat_class(), self.peer_nat_class(peer_node_id));
        match action {
            // Direct pairs ignore the coordinator entirely; pass a
            // sentinel `0` — the Direct arm never reads it.
            PairAction::Direct => self.connect_direct(peer_node_id, peer_pubkey, 0).await,
            PairAction::SinglePunch | PairAction::SkipPunch => {
                match self.select_punch_coordinator(peer_node_id) {
                    Some(coord) => self.connect_direct(peer_node_id, peer_pubkey, coord).await,
                    None => {
                        self.traversal_stats.record_rendezvous_no_relay();
                        Err(TraversalError::RendezvousNoRelay)
                    }
                }
            }
        }
    }

    /// Establish a direct session to `peer_node_id`, using the
    /// pair-type matrix (plan §3) to decide between a direct
    /// handshake, a rendezvous-coordinated single-shot punch, or
    /// a routed-only fallback.
    ///
    /// # Flow
    ///
    /// 1. Read local + remote NAT classifications (self
    ///    `nat_class()` + `peer_nat_class`). Unknown sides are
    ///    handled per the matrix — never treated as "don't attempt"
    ///    (plan decision 8).
    /// 2. Resolve the peer's reflex address from the local
    ///    capability index. Fails with
    ///    [`super::traversal::TraversalError::PeerNotReachable`] if no reflex is
    ///    cached (peer hasn't announced yet).
    /// 3. Apply the matrix:
    ///    - `Direct` → connect via the routing table's
    ///      first-hop; `coordinator` is not consulted and its
    ///      reachability is irrelevant. `relay_fallbacks`
    ///      increments (we didn't attempt a punch).
    ///    - `SkipPunch` → connect via `coordinator` as the
    ///      relay; symmetric pairs have no better option.
    ///      Fails with `PeerNotReachable` if `coordinator`
    ///      isn't a live peer.
    ///    - `SinglePunch` → ask `coordinator` to mediate via
    ///      [`Self::request_punch`]. On successful introduction,
    ///      increment `punches_attempted` + `punches_succeeded`
    ///      and connect to `peer_reflex`. On failure, increment
    ///      `punches_attempted` + `relay_fallbacks` and fall
    ///      back to connecting via the coordinator — the plan's
    ///      framing treats punch-failed as "optimization missed,"
    ///      not a connectivity failure.
    ///
    /// # Scope note
    ///
    /// Stage 3c wires the orchestration + stats end-to-end but
    /// always establishes the session via the routed handshake
    /// through `coordinator` — the framing "traffic rides the
    /// relay until a direct punch upgrades it" matches the plan's
    /// "optimization, not correctness" contract. Stage 3d lands
    /// the keep-alive train + `PunchAck` round-trip, at which
    /// point a successful `SinglePunch` outcome upgrades to a
    /// direct session; failed punches (or matrix-skipped pairs)
    /// continue to resolve on the routed path as they do today.
    ///
    /// Stats are set on the stage-3c semantics already:
    /// `punches_attempted` increments when the matrix picks
    /// `SinglePunch` and the coordinator mediates; stage 3d
    /// refines `punches_succeeded` / `relay_fallbacks` against
    /// the real keep-alive outcome.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn connect_direct(
        &self,
        peer_node_id: u64,
        peer_pubkey: &[u8; 32],
        coordinator: u64,
    ) -> Result<u64, super::traversal::TraversalError> {
        use super::traversal::classify::{pair_action, PairAction};
        use super::traversal::TraversalError;

        // NOTE: `peer_reflex` and `coordinator` are deliberately
        // NOT resolved here. Two separate cubic P1 reviews
        // flagged that eager lookups + `PeerNotReachable` fast-
        // fails at the top broke branches that didn't actually
        // need those inputs — `Direct` doesn't need the
        // coordinator, and `SkipPunch` / `SinglePunch` don't need
        // the peer's reflex (SinglePunch gets it from the
        // coordinator's `PunchIntroduce`; SkipPunch rides the
        // coordinator relay and doesn't probe the peer directly).
        // Both lookups now happen lazily inside the arms that
        // actually consume them.

        let local_class = self.nat_class();
        let remote_class = self.peer_nat_class(peer_node_id);
        let action = pair_action(local_class, remote_class);

        // Resolve `coordinator` into a wire address. Only call
        // from the SkipPunch / SinglePunch arms — `Direct`
        // routes via the routing table (below).
        let coordinator_addr = || {
            self.peer_addrs
                .get(&coordinator)
                .map(|e| *e.value())
                .ok_or(TraversalError::PeerNotReachable)
        };

        // Helper: `true` iff we already have a session with
        // `peer_node_id` whose transport points at `want_addr`.
        // Used by the branches below to decide whether to
        // short-circuit (session is already on the path we want)
        // vs. re-handshake to upgrade (session exists but on the
        // wrong path — typically a relayed session that a fresh
        // direct/punched attempt should replace).
        // Unconditionally short-circuiting on any existing session
        // would leave callers stuck on the relay forever,
        // defeating the optimization.
        let session_matches = |want_addr: std::net::SocketAddr| {
            self.peers
                .get(&peer_node_id)
                .map(|e| e.value().addr == want_addr)
                .unwrap_or(false)
        };

        // Helper: open a session directly to `target_addr` by
        // wrapping msg1 in a routing header and sending straight
        // to the peer. Works for `Direct` (target_addr = peer_reflex)
        // and for post-punch upgrade (same). Uses the dispatch-
        // loop pending_handshakes path via `connect_via`, which
        // avoids recv-loop contention on a post-`start()` node.
        let connect_on_direct_path = |target_addr: std::net::SocketAddr| async move {
            let id = if session_matches(target_addr) {
                peer_node_id
            } else {
                self.connect_via(target_addr, peer_pubkey, peer_node_id)
                    .await
                    .map_err(|e| TraversalError::Transport(e.to_string()))?
            };
            // After a successful direct upgrade (either an
            // already-matching session or a fresh `connect_via`
            // landing), point `addr_to_node` at the upgraded
            // session's wire addr. `connect_via` deliberately does
            // NOT touch `addr_to_node` so that *relayed* sessions
            // keep mapping to the relay's own node_id — but a
            // direct upgrade has a known peer reflex on the wire
            // and should benefit from the dispatch fast path
            // (`addr_to_node.get(&source) → peers.get(nid)`).
            // Without this insert the dispatcher misses on
            // `target_addr` and falls back to a linear
            // `peers.iter().find` per packet for the upgraded
            // session. (#9)
            self.addr_to_node.insert(target_addr, peer_node_id);
            Ok::<u64, TraversalError>(id)
        };

        // Helper: open a relayed session via `coord_addr`. Short-
        // circuits only when an existing session is already on
        // exactly that coordinator's path. An unrelated session
        // (stale, dead, on a different hop) is NOT treated as
        // success — a `contains_key`-based short-circuit here
        // would mask a failed direct attempt behind whatever
        // stale session happened to still be in the peers map,
        // so `connect_direct` would report "success" without
        // actually establishing the intended path. The handshake
        // runs unless we can confirm the existing session is
        // already the one this call was asked to resolve.
        let connect_via_coordinator = |coord_addr: std::net::SocketAddr| async move {
            if session_matches(coord_addr) {
                return Ok(peer_node_id);
            }
            self.connect_via(coord_addr, peer_pubkey, peer_node_id)
                .await
                .map_err(|e| TraversalError::Transport(e.to_string()))
        };

        match action {
            PairAction::Direct => {
                // `Direct` pairs (Open/Open, Open/Cone,
                // Open/Unknown, Unknown/Unknown, etc.) don't
                // need the coordinator — the peer is publicly
                // reachable at its advertised reflex. Send the
                // routed-handshake packet straight to
                // `peer_reflex`; the peer's dispatch loop sees
                // `dest == self` and completes locally. Only
                // when that direct attempt fails do we try the
                // routing table's first-hop as a fallback
                // (pingwave-installed routes, etc.). Always
                // going via the routing table would add an
                // unnecessary relay hop when a direct path is
                // available.
                //
                // Stats note: `record_relay_fallback` fires only
                // when we actually fall back to the routed path
                // — not on entry. A successful direct connect is
                // not a fallback; attributing it as one breaks
                // `TraversalStats.relay_fallbacks`'s documented
                // meaning ("ended up on the routed-
                // handshake path") and makes the counter useless
                // for assessing NAT-traversal effectiveness.
                // `Direct` is the one branch that genuinely
                // needs the peer's reflex — it's the wire target
                // for the direct-handshake attempt. Resolve it
                // lazily here (cubic P1): putting this lookup
                // at the top of the function used to reject
                // `SkipPunch` pairs (which don't need a reflex
                // at all) with `PeerNotReachable`.
                let peer_reflex = self
                    .peer_reflex_addr(peer_node_id)
                    .ok_or(TraversalError::PeerNotReachable)?;

                match connect_on_direct_path(peer_reflex).await {
                    Ok(id) => Ok(id),
                    Err(_) => {
                        // Direct handshake on `peer_reflex` failed.
                        // Run the routing-table fallback
                        // *unconditionally* — cubic P2 flagged
                        // that short-circuiting on "any session
                        // exists" would mask the failed direct
                        // attempt behind a stale / unrelated
                        // session, preventing the upgrade this
                        // API is meant to attempt. If
                        // `connect_routed` itself finds the
                        // existing session is already on a valid
                        // first-hop it'll succeed quickly; if no
                        // route is cached it returns an honest
                        // error the caller can observe.
                        //
                        // Stats ordering (cubic P2):
                        // `record_relay_fallback` only fires
                        // *after* `connect_routed` actually
                        // succeeds. Bumping it before the
                        // fallback runs would overcount — if
                        // the routing-table path also fails,
                        // the call returns Err and the counter
                        // would still have moved, breaking
                        // `relay_fallbacks`'s documented meaning
                        // ("resolutions that stayed on the
                        // routed path").
                        let id = self
                            .connect_routed(peer_pubkey, peer_node_id)
                            .await
                            .map_err(|e| TraversalError::Transport(e.to_string()))?;
                        self.traversal_stats.record_relay_fallback();
                        Ok(id)
                    }
                }
            }
            PairAction::SkipPunch => {
                // Symmetric × Symmetric (and Symmetric ×
                // Unknown). Punch can't land; the coordinator
                // is the only way to relay. Fail fast if the
                // caller's coordinator isn't reachable — there
                // is no viable fallback in this branch.
                //
                // Stats note (cubic P2): `record_relay_fallback`
                // runs only *after* `connect_via_coordinator`
                // actually succeeds. A failed coordinator
                // handshake returns Err without bumping, so
                // `relay_fallbacks` continues to mean "ended
                // up on the routed-handshake path" — not "the
                // matrix picked the routed path but the
                // handshake also failed."
                let coord = coordinator_addr()?;
                let id = connect_via_coordinator(coord).await?;
                self.traversal_stats.record_relay_fallback();
                Ok(id)
            }
            PairAction::SinglePunch => {
                // Punch requires the coordinator for rendezvous
                // mediation. Resolve it here (not eagerly at the
                // top) so Direct-path callers with no active
                // coordinator peer can still succeed.
                let coord = coordinator_addr()?;
                let self_reflex = self.reflex_addr().unwrap_or_else(|| self.local_addr());

                // Install the PunchAck waiter BEFORE firing the
                // request so a fast round-trip can't beat us to
                // the correlation map. Generation-stamped so
                // cleanup paths below only evict our own entry,
                // not a racing concurrent call.
                let (ack_tx, ack_rx) = oneshot::channel();
                let ack_gen = self
                    .next_waiter_gen
                    .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                // Bind to `coordinator` — the node that will
                // forward the counterpart's ack to us. The
                // dispatch arm requires the session peer to match
                // this id before completing the oneshot.
                self.pending_punch_acks
                    .insert(peer_node_id, (ack_gen, coordinator, ack_tx));

                let punch_outcome = self
                    .request_punch(coordinator, peer_node_id, self_reflex)
                    .await;

                // Stats ordering (cubic P2): `record_punch_attempt`
                // fires only when `request_punch` returns Ok —
                // i.e., the coordinator mediated the introduction,
                // which proves the send succeeded and the intro
                // arrived. Bumping before knowing the outcome
                // would overcount cases where no wire activity
                // actually happened (coordinator unreachable,
                // socket send failed). Similarly, the relay-
                // fallback counters below only fire after the
                // fallback handshake itself lands.
                let intro = match punch_outcome {
                    Ok(intro) => {
                        self.traversal_stats.record_punch_attempt();
                        intro
                    }
                    Err(_) => {
                        // Coordinator mediation failed — no
                        // point waiting for an ack that will
                        // never come. Evict the waiter only if
                        // it's still ours (a concurrent call may
                        // have replaced it; cubic P1). No
                        // `record_punch_attempt` — the wire
                        // punch didn't happen. The relay-
                        // fallback counter is bumped only after
                        // `connect_via_coordinator` actually
                        // succeeds.
                        self.pending_punch_acks
                            .remove_if(&peer_node_id, |_, (g, _, _)| *g == ack_gen);
                        let id = connect_via_coordinator(coord).await?;
                        self.traversal_stats.record_relay_fallback();
                        return Ok(id);
                    }
                };

                // Await the counterpart's PunchAck, forwarded by
                // the coordinator. On success we try a direct
                // handshake to the peer's advertised reflex —
                // that's the whole point of the punch, and
                // without it this code path is a fancy way of
                // doing a relayed connect while lying in stats
                // that a punch happened. On ack-timeout or
                // direct-handshake failure we fall back to relay
                // so the caller still gets a usable session.
                let deadline = self.traversal_config.punch_deadline;
                match tokio::time::timeout(deadline, ack_rx).await {
                    Ok(Ok(_ack)) => {
                        match connect_on_direct_path(intro.peer_reflex).await {
                            Ok(id) => {
                                self.traversal_stats.record_punch_success();
                                Ok(id)
                            }
                            Err(_) => {
                                // Punch opened but direct
                                // handshake failed (NAT rebound
                                // between ack and handshake, or
                                // the peer's socket buffer
                                // filled). Relay fallback — bump
                                // `relay_fallbacks` only after
                                // the coordinator handshake
                                // actually lands.
                                let id = connect_via_coordinator(coord).await?;
                                self.traversal_stats.record_relay_fallback();
                                Ok(id)
                            }
                        }
                    }
                    Ok(Err(_)) => {
                        // Our sender was replaced by a concurrent
                        // call — the map entry is now theirs, do
                        // NOT remove. Fall through to relay on
                        // our side.
                        let id = connect_via_coordinator(coord).await?;
                        self.traversal_stats.record_relay_fallback();
                        Ok(id)
                    }
                    Err(_) => {
                        self.pending_punch_acks
                            .remove_if(&peer_node_id, |_, (g, _, _)| *g == ack_gen);
                        // Ack-wait deadline elapsed: the introduce
                        // arrived but the counterpart's PunchAck never
                        // did — the punch's one timeout for this flow
                        // (the introduce wait resolved Ok, so
                        // `request_punch` didn't count one).
                        self.traversal_stats.record_punch_timeout();
                        let id = connect_via_coordinator(coord).await?;
                        self.traversal_stats.record_relay_fallback();
                        Ok(id)
                    }
                }
            }
        }
    }

    /// Rank peers for a scored requirement. Returns the best-
    /// scoring node's id, or `None` if no peer matches.
    ///
    /// Phase 3b note: scoring runs against a tag-only
    /// [`CapabilitySet`](super::behavior::capability::CapabilitySet)
    /// synthesized from the fold (the fold's
    /// [`CapabilityMembership`](super::behavior::fold::CapabilityMembership)
    /// doesn't carry the full legacy hardware/models projection).
    /// Hardware- and model-based preference weights (memory,
    /// vram, tokens/sec, loaded) read zero, so this method
    /// degrades to "any matching candidate, lex-sorted by
    /// node_id." That's the same shape as the cap-propagation-
    /// race fallback; production has no rich-scoring caller per
    /// the Phase 3b survey.
    pub fn find_best_node(
        &self,
        req: &super::behavior::capability::CapabilityRequirement,
    ) -> Option<u64> {
        let candidates = super::behavior::fold::capability_bridge::find_nodes_matching(
            &self.capability_fold,
            &req.filter,
        );
        Self::best_by_score(&self.capability_fold, candidates, req)
    }

    /// Scoped variant of [`Self::find_best_node`]. See
    /// [`Self::find_nodes_by_filter_scoped`] for the scope
    /// resolution semantics; selection picks the highest-scoring
    /// candidate within the scoped set.
    ///
    /// Phase 3b note: same scoring caveat as
    /// [`Self::find_best_node`] — the fold's
    /// [`CapabilityMembership`](super::behavior::fold::CapabilityMembership)
    /// doesn't carry the legacy hardware/models projection, so
    /// scoring degrades to "any matching candidate, lex-sorted."
    pub fn find_best_node_scoped(
        &self,
        req: &super::behavior::capability::CapabilityRequirement,
        scope: &ScopeFilter<'_>,
    ) -> Option<u64> {
        let candidates = self.find_nodes_by_filter_scoped(&req.filter, scope);
        Self::best_by_score(&self.capability_fold, candidates, req)
    }

    /// Pick the highest-scoring candidate against `req`. Synthesizes
    /// each candidate's [`CapabilitySet`] from the fold exactly once
    /// (sort by score key, lex-tiebreak on `node_id` for stable
    /// output), instead of re-synthesizing twice per
    /// `max_by` comparison.
    fn best_by_score(
        fold: &Arc<super::behavior::fold::Fold<super::behavior::fold::CapabilityFold>>,
        candidates: Vec<u64>,
        req: &super::behavior::capability::CapabilityRequirement,
    ) -> Option<u64> {
        let mut scored: Vec<(u64, f32)> = candidates
            .into_iter()
            .map(|node_id| {
                let caps = super::behavior::fold::capability_bridge::synthesize_capability_set(
                    fold, node_id,
                );
                (node_id, req.score(&caps))
            })
            .collect();
        // Sort by descending score, lex-asc node_id tiebreak —
        // matches `find_nodes_matching`'s sort ordering when scores
        // tie (which they always do today, per the docstring's
        // "scoring degrades to lex-sorted" caveat) so the result
        // is byte-stable across runs.
        scored.sort_by(|(na, sa), (nb, sb)| {
            sb.partial_cmp(sa)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| na.cmp(nb))
        });
        scored.into_iter().next().map(|(node_id, _)| node_id)
    }

    /// Shared reference to the capability fold — the canonical
    /// capability-state surface. Used by operator dashboards,
    /// the rendezvous coordinator (reflex lookup), and the
    /// dataforts-blob overflow handler.
    pub fn capability_fold(
        &self,
    ) -> &Arc<super::behavior::fold::Fold<super::behavior::fold::CapabilityFold>> {
        &self.capability_fold
    }

    /// Shared reference to the reservation fold. Always present
    /// (allocated at construction even when the node never
    /// publishes a reservation) so the aggregator surface +
    /// future scheduler callers don't have to discriminate on
    /// presence.
    pub fn reservation_fold(
        &self,
    ) -> &Arc<super::behavior::fold::Fold<super::behavior::fold::ReservationFold>> {
        &self.reservation_fold
    }

    /// Shared reference to the island-topology fold (Thunderdome
    /// gang-claim scheduler). Always present; the scheduler's
    /// match→claim pipeline reads it alongside
    /// [`Self::capability_fold`] for the live numeric-filter step.
    pub fn island_fold(
        &self,
    ) -> &Arc<super::behavior::fold::Fold<super::behavior::fold::IslandTopologyFold>> {
        &self.island_fold
    }

    /// Match islands for a gang job by reading this node's capability +
    /// island folds (Thunderdome §2 steps 1–3). Pure read; returns the
    /// candidate islands in claim order. The node-level entry to the
    /// match→claim pipeline.
    pub fn match_islands(
        &self,
        criteria: &super::behavior::gang::MatchCriteria,
    ) -> Vec<super::behavior::fold::IslandId> {
        let down = self.liveness_down.load();
        super::behavior::gang::match_islands(
            &self.capability_fold,
            &self.island_fold,
            criteria,
            &down,
        )
    }

    /// Replace the set of hosts the gang matcher treats as down. The
    /// runtime feeds this each liveness tick from
    /// `scheduler_bridge::project_liveness(meshos).down` (MeshOS ↔
    /// Scheduler Projection 4); [`Self::match_islands`] then prunes those
    /// hosts so a dead node's islands / capabilities are never offered.
    /// Lock-free swap — safe to call from the liveness / reconcile loop
    /// concurrently with matching.
    pub fn set_liveness_down(
        &self,
        down: std::collections::HashSet<super::behavior::fold::NodeId>,
    ) {
        self.liveness_down.store(Arc::new(down));
    }

    /// Reserve `island` under this node's identity: apply the
    /// `Reserved` transition to the local reservation fold — this
    /// node's optimistic AP view (locked decision 2) — and broadcast
    /// it to peers. Returns the local CAS outcome (`Won` if the
    /// island was free/unheld in this node's view, `Lost` if already
    /// held). `until_unix_us` is the takeover deadline.
    pub async fn reserve_island(
        &self,
        island: super::behavior::fold::IslandId,
        until_unix_us: u64,
    ) -> Result<super::behavior::gang::ClaimOutcome, AdapterError> {
        self.apply_and_broadcast_reservation(
            island,
            super::behavior::fold::ReservationState::Reserved {
                holder: self.node_id,
                until_unix_us,
            },
        )
        .await
    }

    /// Release `island` this node holds: apply `Free` locally and
    /// broadcast. Returns `Lost` if this node wasn't the holder.
    ///
    /// We gate on holder identity first: a `Free` write to an island
    /// with no local entry would `Insert` and falsely report `Won`
    /// (leaving a spurious `Free` entry), so a non-holder release is
    /// reported `Lost` without touching the fold or the wire (review #5).
    pub async fn release_island(
        &self,
        island: super::behavior::fold::IslandId,
    ) -> Result<super::behavior::gang::ClaimOutcome, AdapterError> {
        use super::behavior::fold::ReservationQuery;
        let held_by_us = self
            .reservation_fold
            .query(ReservationQuery::State(island))
            .first()
            .and_then(|(_, state)| state.holder())
            == Some(self.node_id);
        if !held_by_us {
            return Ok(super::behavior::gang::ClaimOutcome::Lost);
        }
        self.apply_and_broadcast_reservation(island, super::behavior::fold::ReservationState::Free)
            .await
    }

    /// Match islands by `criteria` and reserve the first available, all
    /// under this node's identity — the node-level "schedule a single-
    /// island gang against my own folds" loop (the `Reserved` reject
    /// walks to the next candidate). Returns the claimed island, or
    /// `None` when nothing matched or every match was contended in this
    /// node's view.
    pub async fn claim_island(
        &self,
        criteria: &super::behavior::gang::MatchCriteria,
        until_unix_us: u64,
    ) -> Result<Option<super::behavior::fold::IslandId>, AdapterError> {
        for island in self.match_islands(criteria) {
            if matches!(
                self.reserve_island(island, until_unix_us).await?,
                super::behavior::gang::ClaimOutcome::Won
            ) {
                return Ok(Some(island));
            }
        }
        Ok(None)
    }

    /// Build a signed reservation transition, apply it to the local
    /// reservation fold for the optimistic CAS outcome, and broadcast
    /// it. Shared by [`Self::reserve_island`] / [`Self::release_island`].
    async fn apply_and_broadcast_reservation(
        &self,
        island: super::behavior::fold::IslandId,
        state: super::behavior::fold::ReservationState,
    ) -> Result<super::behavior::gang::ClaimOutcome, AdapterError> {
        use super::behavior::fold::{ApplyOutcome, FoldKind, ReservationFold};
        let gen = self.next_fold_generation(ReservationFold::KIND_ID, island);
        let meta = super::behavior::fold::EnvelopeMeta {
            announced_at: super::current_timestamp_micros(),
            ..Default::default()
        };
        let ann = super::behavior::fold::SignedAnnouncement::sign(
            &self.identity,
            ReservationFold::KIND_ID,
            0,
            self.node_id,
            gen,
            meta,
            super::behavior::fold::ReservationAnnouncement {
                resource_id: island,
                state,
            },
        )
        .map_err(|e| AdapterError::Connection(format!("reservation: sign failed: {e}")))?;
        // Local optimistic CAS (this node's AP view), then propagate.
        let outcome = self
            .reservation_fold
            .apply(ann.clone())
            .map_err(|e| AdapterError::Connection(format!("reservation: apply failed: {e}")))?;
        // The broadcast is best-effort gossip (the local CAS already
        // decided the AP outcome), but don't silently drop a failed
        // propagation: the returned ClaimOutcome reflects only the local
        // view, so a dropped error hides "won locally, peers not told"
        // (review #10).
        if let Err(e) = self.publish_fold_broadcast(&ann).await {
            tracing::warn!(
                island,
                error = %e,
                "reservation broadcast failed; local CAS applied but peers not notified",
            );
        }
        Ok(match outcome {
            ApplyOutcome::Inserted | ApplyOutcome::Replaced => {
                super::behavior::gang::ClaimOutcome::Won
            }
            ApplyOutcome::Rejected => super::behavior::gang::ClaimOutcome::Lost,
        })
    }

    /// Test-only helper — translate a legacy
    /// [`CapabilityAnnouncement`] into the fold-shaped envelope
    /// and apply it. Mirrors the inbound dispatch path's
    /// behavior without going through the wire, so test fixtures
    /// can prime a node's capability view in one line.
    #[doc(hidden)]
    pub fn test_inject_capability_announcement(
        &self,
        ann: super::behavior::capability::CapabilityAnnouncement,
    ) {
        let fold_ann = super::behavior::fold::capability_bridge::translate_announcement(&ann);
        let _ = self.capability_fold.apply(fold_ann);
    }

    /// Test-only helper — does the fold know about an entry
    /// keyed on `node_id`? Mirrors the legacy
    /// `CapabilityIndex::get(node_id).is_some()` check.
    #[doc(hidden)]
    pub fn test_capability_fold_has(&self, node_id: u64) -> bool {
        self.capability_fold
            .with_state(|state| state.by_node.contains_key(&node_id))
    }

    /// Test-only helper — synthesize a legacy `CapabilitySet`
    /// for `node_id` from the fold's tag state. Mirrors the
    /// legacy `CapabilityIndex::get(node_id).unwrap_or_default()`.
    #[doc(hidden)]
    pub fn test_capability_fold_get(
        &self,
        node_id: u64,
    ) -> super::behavior::capability::CapabilitySet {
        super::behavior::fold::capability_bridge::synthesize_capability_set(
            &self.capability_fold,
            node_id,
        )
    }

    /// Resolve a wire `origin_hash` to its publisher's `node_id`,
    /// or `None` when no publisher has claimed it yet. Post-
    /// `WIRE_ORIGIN_HASH_64BIT` the wire hash is the full
    /// `EntityId::origin_hash()` u64; accidental collisions are
    /// 2^-32 (effectively impossible). The map is populated
    /// first-write-wins, so an adversary grinding a colliding
    /// keypair (~2^32 work) cannot displace an established
    /// claimant.
    pub fn get_node_by_origin_hash(&self, origin_hash: u64) -> Option<u64> {
        self.origin_hash_to_node.get(&origin_hash).map(|v| *v)
    }

    /// Push the currently-stored local announcement (if any) to
    /// `peer_addr`. Called from the end of `connect` / `accept` so
    /// late joiners don't have to wait for a re-announce. No-op
    /// when we haven't yet announced anything.
    async fn push_local_announcement(&self, peer_addr: SocketAddr) {
        let Some(ann) = self.local_announcement.load_full() else {
            return;
        };
        let bytes = ann.to_bytes();
        if let Err(e) = self
            .send_subprotocol(peer_addr, SUBPROTOCOL_CAPABILITY_ANN, &bytes)
            .await
        {
            tracing::trace!(
                peer = %peer_addr,
                error = %e,
                "capability: session-open push failed"
            );
        }
    }

    // ── Stream API ─────────────────────────────────────────────────────

    /// Open (or look up) a logical stream to a connected peer.
    ///
    /// A stream is one ordered, independently reliability-configured
    /// channel inside the encrypted session to `peer_node_id`. Multiple
    /// streams share one session, one cipher, and one UDP socket, but
    /// have independent sequence numbers and reliability state. See
    /// [`Stream`] for the full contract.
    ///
    /// **Idempotent:** repeated calls for the same `(peer_node_id,
    /// stream_id)` return handles backed by the same underlying state;
    /// a config argument that differs from the first call's is ignored
    /// with a warning log. Close + re-open to change a stream's config.
    pub fn open_stream(
        &self,
        peer_node_id: u64,
        stream_id: u64,
        config: StreamConfig,
    ) -> Result<Stream, AdapterError> {
        let peer = self.peers.get(&peer_node_id).ok_or_else(|| {
            AdapterError::Connection(format!(
                "open_stream: no session for peer {:#x}",
                peer_node_id
            ))
        })?;
        let reliable = config.reliability.is_reliable();
        // Capture the freshly-allocated (or existing, on idempotent
        // re-open) epoch so the returned `Stream` handle can later
        // reject stale sends after a close+reopen.
        let epoch = peer.session.open_stream_full(
            stream_id,
            reliable,
            config.fairness_weight,
            config.window_bytes,
        );
        // Propagate the weight to the router's fair scheduler so
        // forwarded traffic on this stream (e.g., multi-hop relays
        // where we're an intermediate) respects the weight too. v1
        // caveat: local outbound sends via `send_on_stream` bypass the
        // scheduler; the weight only becomes observable on the wire
        // when a packet with this stream_id transits *this* node as
        // a forwarder. Documented in STREAM_MULTIPLEXING_PLAN.md.
        self.router
            .scheduler()
            .set_stream_weight(stream_id, config.fairness_weight);
        // Opportunistic eviction: if this open just pushed us over the
        // cap, trim via the same path as close_stream (idle==0 means
        // only the cap-exceeded pass runs).
        if peer.session.stream_count() > self.config.max_streams {
            peer.session.evict_idle_streams(
                Duration::from_nanos(u64::MAX),
                self.config.max_streams,
                "cap_exceeded",
            );
        }
        Ok(Stream {
            peer_node_id,
            stream_id,
            epoch,
            config,
        })
    }

    /// Close a stream: drop its `StreamState` from the session, ending
    /// delivery of any buffered inbound events for the stream and
    /// dropping outbound packets that haven't hit the wire yet.
    /// Idempotent. `CloseBehavior::DrainThenClose` is honored only to
    /// the extent the router's scheduler has already flushed; there is
    /// no wire "drain-then-close" signal in v1.
    pub fn close_stream(&self, peer_node_id: u64, stream_id: u64) {
        if let Some(peer) = self.peers.get(&peer_node_id) {
            peer.session.close_stream(stream_id);
        }
    }

    /// Close a reliable stream **gracefully** (H-7, `DrainThenClose`):
    /// wait until the reliability layer has no unacked packets — i.e. the
    /// receiver has acked everything (with H-9 ack-pruning, `pending`
    /// empties as grants arrive) — or `timeout` elapses, then close. Use
    /// after the last bytes of a reliable send so retransmit can still
    /// fill gaps before teardown; closing eagerly (`close_stream`) drops
    /// the retransmit window and can strand a lost tail packet on a lossy
    /// link. A fire-and-forget stream (nothing tracked) drains instantly.
    pub async fn close_stream_graceful(
        &self,
        peer_node_id: u64,
        stream_id: u64,
        timeout: Duration,
    ) {
        let deadline = std::time::Instant::now() + timeout;
        loop {
            let drained = match self.peers.get(&peer_node_id) {
                Some(p) => p
                    .session
                    .try_stream(stream_id)
                    .map(|s| !s.with_reliability(|r| r.has_pending()))
                    .unwrap_or(true), // stream already gone → nothing to drain
                None => true, // peer gone → nothing to drain
            };
            if drained || std::time::Instant::now() >= deadline {
                break;
            }
            tokio::time::sleep(Duration::from_millis(2)).await;
        }
        self.close_stream(peer_node_id, stream_id);
    }

    /// Send a batch of events on an explicit stream.
    ///
    /// Uses the stream's reliability mode from its original `open_stream`
    /// config. Returns `Backpressure` when the stream's in-flight count
    /// (`tx_inflight`) would exceed its configured `tx_window`; the event
    /// was not enqueued — the caller decides what to do (drop, retry,
    /// or buffer at the app layer). `tx_window == 0` disables the check
    /// and preserves pre-backpressure behavior. `Transport` is returned
    /// for underlying socket send failures.
    ///
    /// Returns `NotConnected` when the stream was never opened or has
    /// been closed since (`close_stream`, idle eviction, cap-exceeded
    /// LRU). A previously-closed `Stream` handle is inert by design —
    /// reusing it does NOT silently re-create the stream with default
    /// config; the caller must explicitly re-open.
    pub async fn send_on_stream(
        &self,
        stream: &Stream,
        events: &[Bytes],
    ) -> Result<(), StreamError> {
        let peer = self
            .peers
            .get(&stream.peer_node_id)
            .ok_or(StreamError::NotConnected)?;
        let peer_addr = peer.addr;
        let session = peer.session.clone();
        drop(peer);

        if self.partition_filter.contains(&peer_addr) {
            return Ok(()); // matches send_to_peer's silent drop
        }

        let stream_id = stream.stream_id;
        let reliable = stream.config.reliability.is_reliable();
        // Opt-in: bulk-transfer streams route their originating sends
        // through the FairScheduler (T-0.5) instead of straight to the
        // socket, so they participate in per-stream weighted fairness.
        // Default streams keep the direct path (zero blast radius).
        let scheduled = stream.config.scheduled;

        // Refuse to send on a stream that isn't currently open, OR
        // whose live state has a different epoch than the handle. The
        // second case covers the subtle "close + reopen with the same
        // id" bug: the handle's epoch was captured at its original
        // open, but a reopen allocates a fresh `StreamState` with a
        // new epoch. A naive existence-only check would silently
        // reroute the send onto the new stream — wrong config, wrong
        // stats, wrong tx_window accounting.
        match session.try_stream(stream_id) {
            None => return Err(StreamError::NotConnected),
            Some(state) if state.epoch() != stream.epoch => {
                return Err(StreamError::NotConnected);
            }
            // Congestion gate (H-6): if in-flight is already at the
            // congestion window, back-pressure — the caller's
            // `send_with_retry` retries as acks open the window, pacing
            // the stream to its cwnd under loss. Loss-free streams never
            // hit this (cwnd grows past the in-flight count), so normal
            // and low-volume (nRPC) traffic is unaffected.
            Some(state) if reliable && !state.with_reliability(|r| r.can_send()) => {
                return Err(StreamError::Backpressure);
            }
            Some(_) => {}
        }

        let pool = session.thread_local_pool();
        let mut builder = pool.get();

        let mut current_batch: Vec<Bytes> = Vec::with_capacity(64);
        let mut current_size = 0usize;

        // Each socket send acquires byte credit from the stream's
        // `tx_credit_remaining`. On success we `commit()` the guard —
        // the bytes now belong to the receiver, which will refund via
        // `StreamWindow` grants once it drains them. On any failure
        // (socket error, cancellation, `close_stream` race) the guard
        // drops without commit and refunds the bytes — the bytes
        // never hit the wire, so pretending they did would strand
        // credit. `NotConnected` is surfaced when the stream
        // disappears mid-call.
        let flags = if reliable {
            PacketFlags::RELIABLE
        } else {
            PacketFlags::NONE
        };

        // #19 atomicity: once ANY packet of this call has been committed
        // (put on the wire / handed to the scheduler), the call is past
        // the point of no return. Surfacing `Backpressure` to the caller
        // after a partial commit is unsafe: `send_with_retry` replays the
        // WHOLE `events` slice under fresh sequence numbers, so the
        // already-committed packets would be delivered twice. So we only
        // return `Backpressure` while `committed_any == false` (the caller
        // may safely retry the whole slice — nothing has been sent and any
        // consumed seq was rolled back). After the first commit, a flush
        // that meets backpressure retries *internally* with backoff until
        // it clears, so the batch is sent exactly once, in order.
        let mut committed_any = false;

        for event in events {
            let frame_size = EventFrame::LEN_SIZE + event.len();
            if current_size + frame_size > protocol::MAX_PAYLOAD_SIZE && !current_batch.is_empty() {
                self.flush_stream_batch(
                    &session,
                    &mut builder,
                    stream,
                    stream_id,
                    peer_addr,
                    scheduled,
                    flags,
                    &current_batch,
                    current_size,
                    &mut committed_any,
                )
                .await?;
                current_batch.clear();
                current_size = 0;
            }
            current_batch.push(event.clone());
            current_size += frame_size;
        }

        if !current_batch.is_empty() {
            self.flush_stream_batch(
                &session,
                &mut builder,
                stream,
                stream_id,
                peer_addr,
                scheduled,
                flags,
                &current_batch,
                current_size,
                &mut committed_any,
            )
            .await?;
        }

        drop(builder);
        session.touch();
        Ok(())
    }

    /// Flush one built batch of a [`Self::send_on_stream`] call: acquire
    /// byte credit + a sequence, build the packet, deliver it, commit the
    /// credit, and register the reliable retransmit descriptor.
    ///
    /// Backpressure handling is the delicate part (bug-audit #19). The
    /// sequence is allocated atomically with the byte credit (so a
    /// close+reopen race can't cross-contaminate accounting across stream
    /// lifetimes), but `deliver_stream_packet` can *still* fail with
    /// `Backpressure` AFTER the seq was consumed — a full FairScheduler
    /// queue on a `scheduled` stream. The fix has two halves:
    ///
    /// * **No permanent gap.** On the scheduler-backpressure failure path
    ///   the guard's `Drop` refunds the byte credit, and we additionally
    ///   roll back the just-consumed sequence via
    ///   [`NetSession::try_rollback_tx_seq`] (a CAS that only reclaims the
    ///   most-recently-issued seq). The packet was never on the wire, so
    ///   reclaiming the seq leaves no hole for the receiver to NACK
    ///   forever.
    /// * **No duplicate replay.** `*committed_any` tracks whether an
    ///   earlier flush in the same call already put a packet on the wire.
    ///   Before the first commit, backpressure propagates as
    ///   `StreamError::Backpressure` (the caller's `send_with_retry` may
    ///   safely replay the whole slice). After the first commit, this
    ///   flush instead retries internally with exponential backoff until
    ///   it clears, so the committed prefix is never re-sent under new
    ///   seqs — bounded by [`COMMITTED_FLUSH_STALL_BUDGET`]: a receiver
    ///   that grants no credit by then is treated as dead and a terminal
    ///   `StreamError::Transport` is surfaced (which the caller does NOT
    ///   replay), so a permanently-stalled peer can't hang the sender.
    #[allow(clippy::too_many_arguments)]
    async fn flush_stream_batch(
        &self,
        session: &Arc<NetSession>,
        builder: &mut super::pool::ThreadLocalPooledBuilder<'_>,
        stream: &Stream,
        stream_id: u64,
        peer_addr: SocketAddr,
        scheduled: bool,
        flags: PacketFlags,
        batch: &[Bytes],
        batch_size: usize,
        committed_any: &mut bool,
    ) -> Result<(), StreamError> {
        // Charge the **wire size** (Net header + AEAD tag + payload)
        // rather than just the event-frame payload so the byte window
        // matches the bandwidth the sender actually pumps onto the link.
        // Both ends add the same fixed per-packet overhead, so sender and
        // receiver accounting stay symmetric.
        let needed = wire_bytes_for_payload(batch_size);
        let mut delay = Duration::from_millis(5);
        let cap = Duration::from_millis(200);
        // Bound the post-commit internal retry so a stalled (but not
        // closed) receiver that never grants credit can't hang the
        // sender forever (#4 follow-up). Only consulted on the committed
        // path; pre-commit backpressure still returns immediately.
        let stall_deadline = tokio::time::Instant::now() + COMMITTED_FLUSH_STALL_BUDGET;
        loop {
            // `TxAdmit::Acquired` returns credit + sequence under the
            // same DashMap lookup — a close+reopen race can't slip a
            // stale sequence from the old lifetime onto the new state.
            let (guard, seq) =
                match session.try_acquire_tx_credit_matching_epoch(stream_id, stream.epoch, needed)
                {
                    TxAdmit::Acquired { guard, seq } => (guard, seq),
                    TxAdmit::WindowFull => {
                        if *committed_any {
                            // Already committed earlier packets this call —
                            // a return would trigger a whole-slice replay.
                            // Wait for a receiver grant to free credit, but
                            // give up (terminal error, no replay) once the
                            // stall budget is exhausted.
                            await_credit_or_stall(&mut delay, cap, stall_deadline).await?;
                            continue;
                        }
                        return Err(StreamError::Backpressure);
                    }
                    TxAdmit::StreamClosed => return Err(StreamError::NotConnected),
                };
            let packet = builder.build(stream_id, seq, batch, flags);
            match self
                .deliver_stream_packet(scheduled, &packet, peer_addr, stream_id)
                .await
            {
                Ok(()) => {
                    guard.commit(); // accepted (socket or scheduler) — bytes are the receiver's now
                    Self::register_retransmit(session, stream_id, stream.epoch, seq, batch, flags);
                    *committed_any = true;
                    return Ok(());
                }
                Err(StreamError::Backpressure) => {
                    // Scheduler queue full: the packet did NOT reach the
                    // wire. Drop the guard (refunds the byte credit) and
                    // roll back the consumed sequence so no receiver gap
                    // is left behind, then either retry internally (if a
                    // prefix is already committed) or surface backpressure
                    // for a safe whole-slice replay.
                    drop(guard);
                    session.try_rollback_tx_seq(stream_id, stream.epoch, seq);
                    if *committed_any {
                        await_credit_or_stall(&mut delay, cap, stall_deadline).await?;
                        continue;
                    }
                    return Err(StreamError::Backpressure);
                }
                Err(e) => {
                    // Transport/other error: the guard's Drop refunds the
                    // credit. Roll back the seq too — the packet never
                    // reached the wire, so the sequence is unused.
                    drop(guard);
                    session.try_rollback_tx_seq(stream_id, stream.epoch, seq);
                    return Err(e);
                }
            }
        }
    }

    /// Register a just-sent reliable packet for retransmit (STREAM_RETRANSMIT
    /// plan D-1). Stashing the pre-encryption descriptor (not the wire
    /// bytes) lets the NACK / timeout retransmit paths rebuild the packet
    /// with a fresh AEAD counter — a stale-counter replay would be
    /// rejected by the receiver's replay window. No-op for unreliable
    /// streams. The epoch guard skips registration if a close+reopen
    /// raced and replaced the stream state since the credit was acquired.
    ///
    /// Clock note (T-4): `on_send` stamps `sent_at = Instant::now()` here,
    /// at enqueue time. For a `scheduled` stream the packet may then sit
    /// in the FairScheduler queue before the router's send loop ships it,
    /// so a deep scheduler backlog starts the RTT/RTO clock slightly
    /// before the packet is on the wire — biasing the adaptive-RTO sample
    /// low and risking a marginally early timeout-driven resend. This
    /// self-corrects (the next clean RTT sample re-converges) and the
    /// scheduler queue is shallow in practice; stamping at dequeue would
    /// need the descriptor visible in the router send loop, which it
    /// isn't, so the enqueue-time stamp is accepted.
    fn register_retransmit(
        session: &Arc<NetSession>,
        stream_id: u64,
        epoch: u64,
        seq: u64,
        events: &[Bytes],
        flags: PacketFlags,
    ) {
        if !flags.contains(PacketFlags::RELIABLE) {
            return;
        }
        let descriptor = Arc::new(super::RetransmitDescriptor {
            seq,
            stream_id,
            events: events.to_vec(),
            flags,
        });
        if let Some(state) = session.try_stream(stream_id) {
            if state.epoch() == epoch {
                state.with_reliability(|r| r.on_send(descriptor));
            }
        }
    }

    /// Deliver one built stream packet, either straight to the socket
    /// (the default direct path) or — when the stream is `scheduled`
    /// (T-0.5) — by enqueueing it on the router's
    /// [`FairScheduler`](super::router::FairScheduler) so the router's
    /// send loop ships it under per-stream weighted fairness.
    ///
    /// A full scheduler queue surfaces as [`StreamError::Backpressure`]
    /// (same shape as a tx-credit `WindowFull`), so `send_with_retry`
    /// rides it. Scheduled sends pay one `Bytes` copy (the build pool
    /// buffer is reused after the call); bulk transfer absorbs it.
    async fn deliver_stream_packet(
        &self,
        scheduled: bool,
        packet: &[u8],
        peer_addr: SocketAddr,
        stream_id: u64,
    ) -> Result<(), StreamError> {
        if scheduled {
            let queued = super::router::QueuedPacket {
                data: Bytes::copy_from_slice(packet),
                dest: peer_addr,
                stream_id,
                // Bulk data rides non-priority; the scheduler's
                // priority lane is reserved for control/interactive.
                priority: false,
                queued_at: std::time::Instant::now(),
            };
            if self.router.scheduler().enqueue(queued) {
                Ok(())
            } else {
                Err(StreamError::Backpressure)
            }
        } else {
            self.socket
                .send_to(packet, peer_addr)
                .await
                .map(|_| ())
                .map_err(|e| StreamError::Transport(format!("send failed: {}", e)))
        }
    }

    /// Send `events` on `stream`, retrying on `Backpressure` with
    /// exponential backoff (5 ms → 200 ms, doubling) up to `max_retries`
    /// times. Transport failures are returned immediately — they're a
    /// real error, not a pressure signal, and retrying would just mask
    /// them. Returns the final `Backpressure` error if the stream stays
    /// saturated across every attempt.
    pub async fn send_with_retry(
        &self,
        stream: &Stream,
        events: &[Bytes],
        max_retries: usize,
    ) -> Result<(), StreamError> {
        let mut delay = Duration::from_millis(5);
        let cap = Duration::from_millis(200);
        let mut last_backpressure: Option<StreamError> = None;
        for _ in 0..max_retries.saturating_add(1) {
            match self.send_on_stream(stream, events).await {
                Ok(()) => return Ok(()),
                Err(StreamError::Backpressure) => {
                    last_backpressure = Some(StreamError::Backpressure);
                    tokio::time::sleep(delay).await;
                    delay = (delay * 2).min(cap);
                }
                Err(e) => return Err(e),
            }
        }
        Err(last_backpressure.unwrap_or(StreamError::Backpressure))
    }

    /// Convenience wrapper around [`send_with_retry`](Self::send_with_retry)
    /// with a generous retry count. Blocks the calling task until the
    /// send succeeds or a transport error occurs. Use when you'd rather
    /// wait than drop; prefer `send_with_retry` if you need a concrete
    /// upper bound on retry attempts.
    pub async fn send_blocking(
        &self,
        stream: &Stream,
        events: &[Bytes],
    ) -> Result<(), StreamError> {
        // 4096 retries × 200 ms cap = ~13 minutes in the worst case,
        // effectively "block until the network lets up or something is
        // actually wrong." Callers that need a tighter bound should use
        // `send_with_retry` directly.
        self.send_with_retry(stream, events, 4096).await
    }

    /// Snapshot of per-stream stats for a single stream.
    ///
    /// Returns `None` if either the peer or the stream doesn't exist.
    pub fn stream_stats(&self, peer_node_id: u64, stream_id: u64) -> Option<StreamStats> {
        let peer = self.peers.get(&peer_node_id)?;
        let state = peer.session.get_stream(stream_id)?;
        Some(StreamStats {
            tx_seq: state.current_tx_seq(),
            rx_seq: state.current_rx_seq(),
            inbound_pending: state.inbound_len() as u64,
            last_activity_ns: state.last_activity_ns(),
            active: state.is_active(),
            backpressure_events: state.backpressure_events(),
            tx_credit_remaining: state.tx_credit_remaining(),
            tx_window: state.tx_window(),
            credit_grants_received: state.credit_grants_received(),
            credit_grants_sent: state.credit_grants_sent(),
        })
    }

    /// Snapshot of per-stream stats for every stream in the session to
    /// `peer_node_id`. Empty vec if the peer doesn't exist.
    pub fn all_stream_stats(&self, peer_node_id: u64) -> Vec<(u64, StreamStats)> {
        let peer = match self.peers.get(&peer_node_id) {
            Some(p) => p,
            None => return Vec::new(),
        };
        let session = peer.session.clone();
        drop(peer);
        session
            .stream_ids()
            .into_iter()
            .filter_map(|sid| {
                let state = session.get_stream(sid)?;
                Some((
                    sid,
                    StreamStats {
                        tx_seq: state.current_tx_seq(),
                        rx_seq: state.current_rx_seq(),
                        inbound_pending: state.inbound_len() as u64,
                        last_activity_ns: state.last_activity_ns(),
                        active: state.is_active(),
                        backpressure_events: state.backpressure_events(),
                        tx_credit_remaining: state.tx_credit_remaining(),
                        tx_window: state.tx_window(),
                        credit_grants_received: state.credit_grants_received(),
                        credit_grants_sent: state.credit_grants_sent(),
                    },
                ))
            })
            .collect()
    }

    /// Connect to a peer whose first hop on the wire is `relay_addr`.
    ///
    /// The handshake is an ordinary Net packet with the `HANDSHAKE` flag
    /// plus a routing header addressed to `dest_node_id`. The routing
    /// layer forwards it hop-by-hop (like any other packet); the
    /// responder's msg2 comes back the same way. There's no separate
    /// subprotocol, no per-hop re-encryption — Noise NKpsk0 provides
    /// end-to-end confidentiality and authenticity, and the prologue
    /// binds `(src_node_id, dest_node_id)` so a relay that rewrites
    /// either identity in the routing header fails the responder's MAC
    /// check on msg1.
    ///
    /// `start()` must have been called before `connect_via` — the
    /// receive loop has to be running to deliver msg2 back to us.
    /// One attempt of the routed-handshake protocol: register a
    /// pending-initiator slot, send msg1, await msg2. On any
    /// error path the pending slot is cleared so a retry from
    /// the caller (or a fresh `connect_via` invocation) sees a
    /// clean entry. Returns the negotiated [`SessionKeys`] on
    /// success — the caller installs the peer (NetSession +
    /// router + peers + addr_to_node).
    async fn try_connect_via_once(
        &self,
        relay_addr: SocketAddr,
        dest_pubkey: &[u8; 32],
        dest_node_id: u64,
    ) -> Result<SessionKeys, AdapterError> {
        // Build msg1. Prologue uses *routing-identity* (32-bit) versions
        // of (self, dest) — that's what a malicious relay could see and
        // rewrite in the routing header, so binding those bits into the
        // Noise transcript catches tampering. The FULL u64 self.node_id
        // is carried inside the msg1 payload (Noise-AEAD-authenticated),
        // so the responder learns it after decryption and can address
        // msg2 back to the correct u64 identity.
        let pending_key = routing_id(dest_node_id);
        let prologue = handshake_prologue(routing_id(self.node_id), pending_key);
        let mut noise =
            NoiseHandshake::initiator_with_prologue(&self.config.psk, dest_pubkey, &prologue)
                .map_err(|e| AdapterError::Fatal(format!("handshake init failed: {}", e)))?;
        let msg1 = noise
            .write_message(&self.node_id.to_le_bytes())
            .map_err(|e| AdapterError::Connection(format!("write_message failed: {}", e)))?;

        // Register pending-initiator state so the dispatch loop can
        // complete the handshake when msg2 arrives. Keyed by the
        // 32-bit routing identity because msg2's routing header carries
        // the truncated src_id — that's the only key the dispatch loop
        // has when it tries to find the matching initiator.
        let (tx, rx) = oneshot::channel();
        match self.pending_handshakes.entry(pending_key) {
            dashmap::mapref::entry::Entry::Occupied(_) => {
                return Err(AdapterError::Connection(format!(
                    "connect_via: handshake already in flight for peer {:#x}",
                    dest_node_id
                )));
            }
            dashmap::mapref::entry::Entry::Vacant(v) => {
                v.insert(PendingHandshake { noise, tx });
            }
        }

        // Wrap msg1 in a Net handshake packet + routing header and
        // send to the first hop. No session encryption — the handshake
        // payload is the raw Noise bytes, authenticated/confidential
        // by Noise itself.
        let inner = {
            let mut builder = PacketBuilder::new(&[0u8; 32], 0);
            builder.build_handshake(&msg1)
        };
        let routing = RoutingHeader::new(dest_node_id, self.node_id as u32, DEFAULT_HANDSHAKE_TTL);
        let mut routed = bytes::BytesMut::with_capacity(ROUTING_HEADER_SIZE + inner.len());
        routed.extend_from_slice(&routing.to_bytes());
        routed.extend_from_slice(&inner);
        if let Err(e) = self.socket.send_to(&routed, relay_addr).await {
            self.pending_handshakes.remove(&pending_key);
            return Err(AdapterError::Connection(format!("send failed: {}", e)));
        }

        // Wait for the dispatch loop to complete msg2.
        let keys = match tokio::time::timeout(self.config.handshake_timeout, rx).await {
            Ok(Ok(Ok(k))) => k,
            Ok(Ok(Err(e))) => {
                self.pending_handshakes.remove(&pending_key);
                return Err(AdapterError::Fatal(format!("handshake failed: {}", e)));
            }
            Ok(Err(_)) => {
                self.pending_handshakes.remove(&pending_key);
                return Err(AdapterError::Connection("handshake channel dropped".into()));
            }
            Err(_) => {
                self.pending_handshakes.remove(&pending_key);
                return Err(AdapterError::Connection("handshake timeout".into()));
            }
        };
        Ok(keys)
    }

    /// Connect to `dest_node_id` via a routed handshake through
    /// `relay_addr`. Unlike [`Self::connect`] (which requires the
    /// responder to pre-`accept()` this initiator's node_id before
    /// `start()`), this path embeds the initiator's full node_id
    /// inside the Noise msg1 payload and routes the packet through
    /// the dispatch loop's `handle_routed_handshake` Case 2 — so a
    /// daemon that's already `start()`ed accepts msg1 from a brand-
    /// new initiator without prior coordination.
    ///
    /// When `relay_addr == final destination` (the CLI remote-attach
    /// case), the routed path is degenerate one-hop. The post-
    /// handshake peer install populates `addr_to_node[relay_addr]`
    /// via `entry().or_insert(...)` so address-keyed sends resolve
    /// the peer; in a true multi-hop scenario the relay's prior
    /// mapping stays intact.
    ///
    /// Retries up to [`MeshNodeConfig::handshake_retries`] (default
    /// 3) — a single UDP drop on msg1 or msg2 should not surface
    /// as a typed error.
    pub async fn connect_via(
        &self,
        relay_addr: SocketAddr,
        dest_pubkey: &[u8; 32],
        dest_node_id: u64,
    ) -> Result<u64, AdapterError> {
        // Retry the msg1-send + msg2-await `handshake_retries` times
        // (mirrors `handshake_initiator` for the direct path). Routed
        // handshakes ride a UDP relay path that can drop msg1 or msg2
        // independently; a single packet loss should not surface as a
        // typed error to the operator. Per-attempt cleanup happens
        // inside `try_connect_via_once`, so each retry starts fresh.
        let mut attempt = 0;
        let keys = loop {
            attempt += 1;
            match self
                .try_connect_via_once(relay_addr, dest_pubkey, dest_node_id)
                .await
            {
                Ok(keys) => break keys,
                Err(e) if attempt < self.config.handshake_retries => {
                    tracing::warn!(
                        attempt,
                        error = %e,
                        "mesh routed handshake failed, retrying"
                    );
                    tokio::time::sleep(Duration::from_millis(100 * attempt as u64)).await;
                }
                Err(e) => return Err(e),
            }
        };

        // Shared peer install. Routed-mode preserves any prior
        // `addr_to_node[relay_addr]` entry (a true multi-hop
        // relay keeps its own peer_id; degenerate single-hop
        // installs the destination). Routed handshakes
        // intentionally skip the post-install pingwave /
        // failure_detector / announcement push — see
        // `connect`'s wiring for the direct-handshake-only
        // bookkeeping.
        self.install_peer(
            dest_node_id,
            relay_addr,
            keys,
            AddrInstallMode::RoutedPreserve,
        );

        Ok(dest_node_id)
    }

    /// Handshake to `target_addr` and install the resulting session
    /// with a compare-and-swap against `expected_prior_session_id`
    /// (`NAT_TRAVERSAL_V2_PLAN.md` C2). Same retrying handshake as
    /// [`Self::connect_via`], but the install proceeds only if the
    /// peer's current session_id still matches — so a background
    /// direct-path upgrade never clobbers a racing rotation.
    ///
    /// Returns `Ok(true)` if the session was installed, `Ok(false)` if
    /// the CAS lost (a racing handshake won — the caller leaves the
    /// current session, typically the working relay path, intact), or
    /// `Err` on handshake failure (nothing was mutated, so the relay
    /// session is likewise untouched).
    #[cfg(feature = "nat-traversal")]
    async fn connect_via_cas(
        &self,
        target_addr: SocketAddr,
        dest_pubkey: &[u8; 32],
        dest_node_id: u64,
        expected_prior_session_id: u64,
        addr_mode: AddrInstallMode,
    ) -> Result<bool, AdapterError> {
        let mut attempt = 0;
        let keys = loop {
            attempt += 1;
            match self
                .try_connect_via_once(target_addr, dest_pubkey, dest_node_id)
                .await
            {
                Ok(keys) => break keys,
                Err(e) if attempt < self.config.handshake_retries => {
                    tracing::debug!(attempt, error = %e, "upgrade handshake retry");
                    tokio::time::sleep(Duration::from_millis(100 * attempt as u64)).await;
                }
                Err(e) => return Err(e),
            }
        };
        Ok(self.install_peer_cas(
            dest_node_id,
            target_addr,
            keys,
            addr_mode,
            Some(expected_prior_session_id),
        ))
    }

    // ── Background direct-path upgrade (Stage 3) ─────────────────────────

    /// `true` if a fresh upgrade attempt for `peer_id` is allowed right
    /// now — no cache entry, or an entry that isn't `done` and whose
    /// backoff/defer window has elapsed.
    #[cfg(feature = "nat-traversal")]
    fn upgrade_should_attempt(&self, peer_id: u64) -> bool {
        match self.upgrade_cache.get(&peer_id) {
            None => true,
            Some(e) => !e.done && Instant::now() >= e.next_eligible,
        }
    }

    /// Lease an attempt: push `next_eligible` out so the scan loop won't
    /// re-spawn a second attempt for this peer while one is in flight.
    /// The attempt's outcome recorder overwrites this.
    #[cfg(feature = "nat-traversal")]
    fn upgrade_lease(&self, peer_id: u64, lease: Duration) {
        let mut e = self
            .upgrade_cache
            .entry(peer_id)
            .or_insert(UpgradeCacheEntry {
                next_eligible: Instant::now(),
                failures: 0,
                done: false,
            });
        e.next_eligible = Instant::now() + lease;
    }

    /// Record a terminal outcome: the session is direct (or can't be
    /// upgraded) — stop attempting.
    #[cfg(feature = "nat-traversal")]
    fn upgrade_record_done(&self, peer_id: u64) {
        let mut e = self
            .upgrade_cache
            .entry(peer_id)
            .or_insert(UpgradeCacheEntry {
                next_eligible: Instant::now(),
                failures: 0,
                done: false,
            });
        e.done = true;
    }

    /// Record a busy-defer: retry after a short delay, without counting
    /// it as a failure (the session is healthy, just carrying traffic).
    #[cfg(feature = "nat-traversal")]
    fn upgrade_record_defer(&self, peer_id: u64, delay: Duration) {
        let mut e = self
            .upgrade_cache
            .entry(peer_id)
            .or_insert(UpgradeCacheEntry {
                next_eligible: Instant::now(),
                failures: 0,
                done: false,
            });
        e.next_eligible = Instant::now() + delay;
    }

    /// Record a failed attempt: exponential backoff on the retry.
    #[cfg(feature = "nat-traversal")]
    fn upgrade_record_failure(&self, peer_id: u64) {
        const BASE: Duration = Duration::from_secs(2);
        const MAX_SHIFT: u32 = 5; // cap backoff at BASE << 5 = 64 s
        let mut e = self
            .upgrade_cache
            .entry(peer_id)
            .or_insert(UpgradeCacheEntry {
                next_eligible: Instant::now(),
                failures: 0,
                done: false,
            });
        e.failures = e.failures.saturating_add(1);
        let backoff = BASE.saturating_mul(1u32 << e.failures.min(MAX_SHIFT));
        e.next_eligible = Instant::now() + backoff;
    }

    /// Attempt a single background direct-path upgrade of a
    /// relay-routed session to `peer_id` (`NAT_TRAVERSAL_V2_PLAN.md`
    /// Stage 3). Best-effort throughout: on any failure the working
    /// relay session is left intact (the whole feature is an
    /// optimization). Enforces the migration contract:
    ///
    /// - **C3 initiator busy gate:** if the local session has open
    ///   streams or unacked in-flight data, defer — a swap would drop
    ///   it. Retried once quiescent.
    /// - **C2 CAS install:** the punched session installs only if the
    ///   peer's session_id hasn't changed since we snapshotted it, so a
    ///   racing inbound rotation wins instead of being clobbered.
    ///
    /// (C1 — only the lower-node-id end initiates — is enforced by the
    /// scan loop before this is called.)
    ///
    /// This landing upgrades **`Direct` pairs** (the peer is directly
    /// reachable at its reflex). Coordinated-punch (`SinglePunch`)
    /// upgrades reuse the same install machinery and are a follow-up;
    /// `SkipPunch` pairs can never punch. `SkipPunch` is marked
    /// terminal (`done`) so the scan stops revisiting it, but
    /// `SinglePunch` is only *deferred*: a later reflex-drift
    /// reclassification can flip the pair to `Direct`, and a permanent
    /// `done` would pin the session to the relay for the rest of the
    /// process's life. The per-peer cache entry is also dropped when
    /// the peer is evicted (heartbeat sweep), so a session that
    /// regresses direct→relay and reconnects starts from a clean slate.
    #[cfg(feature = "nat-traversal")]
    async fn attempt_direct_upgrade(&self, peer_id: u64) {
        use super::traversal::classify::{pair_action, PairAction};

        // Re-evaluate a not-yet-upgradable `SinglePunch` pair after
        // this long, so a NAT reclassification that makes it `Direct`
        // gets picked up instead of being cached off permanently.
        const SINGLEPUNCH_RECHECK: Duration = Duration::from_secs(30);

        // Snapshot the current session.
        let Some((relay_addr, prior_sid, pubkey, busy)) = self.peers.get(&peer_id).map(|e| {
            let v = e.value();
            (
                v.addr,
                v.session.session_id(),
                v.remote_static_pub,
                v.session.has_open_streams() || v.session.has_unacked(),
            )
        }) else {
            return;
        };

        // Still relay-routed? A direct session is already on the best
        // path — nothing to upgrade.
        if !self.is_relayed_peer(peer_id, &relay_addr) {
            self.upgrade_record_done(peer_id);
            return;
        }

        // C3 initiator busy gate.
        if busy {
            self.traversal_stats.record_upgrade_deferred_busy();
            self.upgrade_record_defer(peer_id, Duration::from_secs(1));
            return;
        }

        let action = pair_action(self.nat_class(), self.peer_nat_class(peer_id));
        let target_addr = match action {
            PairAction::Direct => match self.peer_reflex_addr(peer_id) {
                Some(addr) => addr,
                // No cached reflex yet — retry with backoff once the
                // peer's announcement lands.
                None => {
                    self.upgrade_record_failure(peer_id);
                    return;
                }
            },
            // `SkipPunch` can never punch — terminal, stop scanning.
            PairAction::SkipPunch => {
                self.upgrade_record_done(peer_id);
                return;
            }
            // `SinglePunch` upgrades aren't wired yet, but the pair may
            // become `Direct` after a reclassification. Defer instead
            // of marking terminal so the scan revisits it.
            PairAction::SinglePunch => {
                self.upgrade_record_defer(peer_id, SINGLEPUNCH_RECHECK);
                return;
            }
        };

        // Guard against "upgrading" to the very path we're already on.
        if target_addr == relay_addr {
            self.upgrade_record_done(peer_id);
            return;
        }

        self.traversal_stats.record_upgrade_attempt();
        match self
            .connect_via_cas(
                target_addr,
                &pubkey,
                peer_id,
                prior_sid,
                AddrInstallMode::DirectOverwrite,
            )
            .await
        {
            Ok(true) => {
                self.traversal_stats.record_upgrade_success();
                self.upgrade_record_done(peer_id);
            }
            // CAS lost to a racing rotation, or handshake failed — the
            // existing session is untouched. Back off and re-evaluate;
            // if the race made the session direct, the next attempt's
            // relayed-check marks it done.
            Ok(false) | Err(_) => {
                self.upgrade_record_failure(peer_id);
            }
        }
    }

    /// Test hook: drive a single [`Self::attempt_direct_upgrade`]
    /// synchronously, bypassing the background scan loop's timing so
    /// integration tests are deterministic under parallel load. The
    /// caller is responsible for the C1 lower-node-id check the loop
    /// normally enforces.
    #[doc(hidden)]
    #[cfg(feature = "nat-traversal")]
    pub async fn attempt_direct_upgrade_for_test(&self, peer_id: u64) {
        self.attempt_direct_upgrade(peer_id).await;
    }

    /// Whether the scan loop should consider `peer_id` for a background
    /// upgrade this tick: the local node is the lower-id initiator (C1),
    /// the session is relay-routed (not already direct), and the
    /// per-peer throttle window has elapsed.
    #[cfg(feature = "nat-traversal")]
    fn upgrade_is_loop_candidate(&self, peer_id: u64) -> bool {
        let Some(addr) = self.peers.get(&peer_id).map(|e| e.value().addr) else {
            return false;
        };
        self.upgrade_is_loop_candidate_at(peer_id, addr)
    }

    /// As [`Self::upgrade_is_loop_candidate`] but with the peer's
    /// session `addr` already in hand — lets the scan loop test each
    /// peer straight from the `peers` iterator entry instead of doing a
    /// redundant `peers.get` shard-lookup on the map it is iterating.
    #[cfg(feature = "nat-traversal")]
    fn upgrade_is_loop_candidate_at(&self, peer_id: u64, addr: SocketAddr) -> bool {
        // C1: only the lower-node-id end initiates.
        if self.node_id >= peer_id {
            return false;
        }
        // Relay-routed only — a direct session has nothing to upgrade.
        if !self.is_relayed_peer(peer_id, &addr) {
            return false;
        }
        self.upgrade_should_attempt(peer_id)
    }

    /// Test hook for [`Self::upgrade_is_loop_candidate`] — lets
    /// integration tests assert the C1 / relay-routed filter
    /// deterministically without racing the loop's cadence.
    #[doc(hidden)]
    #[cfg(feature = "nat-traversal")]
    pub fn upgrade_is_loop_candidate_for_test(&self, peer_id: u64) -> bool {
        self.upgrade_is_loop_candidate(peer_id)
    }

    /// Test hook: whether the direct-path upgrade throttle cache holds
    /// an entry for `peer_id`. Pins that a failed peer's entry is
    /// dropped so the cache can't grow without bound under churn.
    #[doc(hidden)]
    #[cfg(feature = "nat-traversal")]
    pub fn upgrade_cache_contains_for_test(&self, peer_id: u64) -> bool {
        self.upgrade_cache.contains_key(&peer_id)
    }

    /// Test hook: the `done` (terminal) flag of `peer_id`'s throttle
    /// entry, or `None` if there is no entry. `SkipPunch` is terminal
    /// (`Some(true)`); a deferred `SinglePunch` is not (`Some(false)`).
    #[doc(hidden)]
    #[cfg(feature = "nat-traversal")]
    pub fn upgrade_entry_is_done_for_test(&self, peer_id: u64) -> Option<bool> {
        self.upgrade_cache.get(&peer_id).map(|e| e.done)
    }

    /// Spawn the background direct-path upgrade scan loop (Stage 3).
    /// Every tick, find relay-routed peers for which this node is the
    /// lower-id initiator (C1) and whose throttle window has elapsed,
    /// and fire a per-peer `attempt_direct_upgrade`. No-op
    /// unless `MeshNodeConfig::auto_direct_upgrade` is set; exits on
    /// `shutdown_notify`.
    ///
    /// The task holds only a [`Weak`](std::sync::Weak) self-ref
    /// (upgraded transiently per tick), never `Arc::clone(self)`. A
    /// strong self-ref held for the task's lifetime would stop
    /// [`MeshNode::drop`] — the path that sets `shutdown` — from ever
    /// running for an `Arc<MeshNode>` dropped without an explicit
    /// `shutdown()`: the loop would then spin forever and leak the
    /// node, its socket, and every other background task. Same
    /// `Weak`-then-`upgrade()` contract as
    /// `spawn_capability_reannounce_loop`.
    #[cfg(feature = "nat-traversal")]
    pub fn spawn_direct_upgrade_loop(self: &Arc<Self>) -> JoinHandle<()> {
        const SCAN_INTERVAL: Duration = Duration::from_secs(1);
        const ATTEMPT_LEASE: Duration = Duration::from_secs(10);

        let weak = Arc::downgrade(self);
        let shutdown = self.shutdown.clone();
        let shutdown_notify = self.shutdown_notify.clone();

        tokio::spawn(async move {
            // Feature off → nothing to do. Transient upgrade only to
            // read the flag; the strong ref is dropped with the match.
            match weak.upgrade() {
                Some(node) if node.config.auto_direct_upgrade => {}
                _ => return,
            }
            let mut tick = tokio::time::interval(SCAN_INTERVAL);
            tick.tick().await; // skip the immediate tick
            while !shutdown.load(Ordering::Acquire) {
                tokio::select! {
                    _ = shutdown_notify.notified() => {
                        if shutdown.load(Ordering::Acquire) {
                            return;
                        }
                    }
                    _ = tick.tick() => {}
                }

                // Upgrade transiently for this tick; if the node is
                // gone, exit. The strong ref lives only across the
                // synchronous scan below — never across an await — so
                // it can't keep the node alive past a `drop`.
                let Some(node) = weak.upgrade() else { break };

                // Snapshot eligible peers without holding a shard guard
                // across the spawned attempts. Test each peer straight
                // from the iterator entry (id + addr in hand) so the
                // filter doesn't re-`get` the map it's iterating.
                let candidates: Vec<u64> = node
                    .peers
                    .iter()
                    .filter(|entry| {
                        node.upgrade_is_loop_candidate_at(*entry.key(), entry.value().addr)
                    })
                    .map(|entry| *entry.key())
                    .collect();

                for peer_id in candidates {
                    // Lease before spawning so the next scan doesn't
                    // double-fire while this attempt is in flight.
                    node.upgrade_lease(peer_id, ATTEMPT_LEASE);
                    let n = node.clone();
                    tokio::spawn(async move {
                        n.attempt_direct_upgrade(peer_id).await;
                    });
                }
            }
        })
    }

    /// Connect to a peer by node id, using the routing table to pick the
    /// first hop. Fails with `Connection("no route to ...")` if the
    /// routing table doesn't have a route to the destination yet — in
    /// which case the caller can retry once pingwaves have propagated.
    pub async fn connect_routed(
        &self,
        dest_pubkey: &[u8; 32],
        dest_node_id: u64,
    ) -> Result<u64, AdapterError> {
        let first_hop = self
            .router
            .routing_table()
            .lookup(dest_node_id)
            .ok_or_else(|| {
                AdapterError::Connection(format!(
                    "connect_routed: no route to peer {:#x}",
                    dest_node_id
                ))
            })?;
        self.connect_via(first_hop, dest_pubkey, dest_node_id).await
    }

    // ── Handshake helpers ───────────────────────────────────────────────

    async fn handshake_initiator(
        &self,
        peer_addr: SocketAddr,
        peer_pubkey: &[u8; 32],
        peer_node_id: u64,
    ) -> Result<SessionKeys, AdapterError> {
        let mut attempt = 0;
        loop {
            attempt += 1;
            match self
                .try_handshake_initiator(peer_addr, peer_pubkey, peer_node_id)
                .await
            {
                Ok(keys) => return Ok(keys),
                Err(e) if attempt < self.config.handshake_retries => {
                    tracing::warn!(attempt, error = %e, "mesh handshake failed, retrying");
                    tokio::time::sleep(Duration::from_millis(100 * attempt as u64)).await;
                }
                Err(e) => return Err(e),
            }
        }
    }

    async fn try_handshake_initiator(
        &self,
        peer_addr: SocketAddr,
        peer_pubkey: &[u8; 32],
        peer_node_id: u64,
    ) -> Result<SessionKeys, AdapterError> {
        let timeout = self.config.handshake_timeout;

        // Prologue uses the 32-bit `routing_id` projection of the node
        // ids — the same projection routed handshakes use, so the two
        // paths share one prologue convention. Direct handshakes don't
        // traverse the routing plane, but the unified convention
        // simplifies reasoning and future code reuse.
        let prologue = handshake_prologue(routing_id(self.node_id), routing_id(peer_node_id));
        let mut handshake =
            NoiseHandshake::initiator_with_prologue(&self.config.psk, peer_pubkey, &prologue)
                .map_err(|e| AdapterError::Fatal(format!("handshake init failed: {}", e)))?;

        let msg1 = handshake
            .write_message(&[])
            .map_err(|e| AdapterError::Connection(format!("write_message failed: {}", e)))?;

        let mut builder = PacketBuilder::new(&[0u8; 32], 0);
        let packet = builder.build_handshake(&msg1);

        // Polling `socket_arc.recv_from` directly would race
        // `spawn_receive_loop`'s consumer post-`start()` (tokio
        // dispatches a UDP datagram to exactly one waiter), so:
        //   - Pre-`start()`: use `recv_from`; the dispatcher isn't
        //     running, so there's no race. This preserves the
        //     existing init-time ordering where `connect()` is
        //     called before `start()`.
        //   - Post-`start()`: register an oneshot in
        //     `pending_direct_initiators`, then send msg1, then
        //     await the oneshot. The dispatcher's direct-handshake
        //     branch forwards the parsed payload bytes through.
        // Concurrent direct connects on the same node also work
        // — each registers under its own peer_addr.
        let payload_bytes = if self.started.load(Ordering::Acquire) {
            let (tx, rx) = oneshot::channel::<Bytes>();
            // Register BEFORE sending msg1 so we can't miss a
            // fast responder that replies before we'd otherwise
            // be ready to receive. `insert` replaces any prior
            // entry for the same `peer_addr` — last writer wins.
            self.pending_direct_initiators.insert(peer_addr, tx);

            if let Err(e) = self.socket.send_to(&packet, peer_addr).await {
                self.pending_direct_initiators.remove(&peer_addr);
                return Err(AdapterError::Connection(format!("send failed: {}", e)));
            }

            match tokio::time::timeout(timeout, rx).await {
                Ok(Ok(payload)) => payload,
                Ok(Err(_)) => {
                    // Sender dropped — the dispatcher removed our
                    // entry without forwarding. Should not happen
                    // unless start() shut down; treat as timeout.
                    self.pending_direct_initiators.remove(&peer_addr);
                    return Err(AdapterError::Connection("handshake channel dropped".into()));
                }
                Err(_) => {
                    // Timeout — the responder never replied or its
                    // reply arrived for a different source. Clean up.
                    self.pending_direct_initiators.remove(&peer_addr);
                    return Err(AdapterError::Connection("handshake timeout".into()));
                }
            }
        } else {
            // Pre-start fallback: dispatcher is not running, so
            // there's nothing to forward through the registry.
            // Poll the socket directly — no race exists yet.
            let socket_arc = self.socket.socket_arc();
            self.socket
                .send_to(&packet, peer_addr)
                .await
                .map_err(|e| AdapterError::Connection(format!("send failed: {}", e)))?;

            let parsed = tokio::time::timeout(timeout, async {
                loop {
                    let mut recv_buf = bytes::BytesMut::with_capacity(protocol::MAX_PACKET_SIZE);
                    recv_buf.resize(protocol::MAX_PACKET_SIZE, 0);

                    let (n, source) = socket_arc
                        .recv_from(&mut recv_buf)
                        .await
                        .map_err(|e| AdapterError::Connection(format!("recv failed: {}", e)))?;

                    if source != peer_addr {
                        continue;
                    }

                    recv_buf.truncate(n);
                    let data = recv_buf.freeze();

                    if let Some(p) = ParsedPacket::parse(data, source) {
                        if p.header.flags.is_handshake() {
                            return Ok::<_, AdapterError>(p);
                        }
                    }
                }
            })
            .await
            .map_err(|_| AdapterError::Connection("handshake timeout".into()))??;
            parsed.payload
        };

        handshake
            .read_message(&payload_bytes)
            .map_err(|e| AdapterError::Connection(format!("read_message failed: {}", e)))?;

        handshake
            .into_session_keys()
            .map_err(|e| AdapterError::Fatal(format!("key extraction failed: {}", e)))
    }

    async fn handshake_responder(
        &self,
        peer_node_id: u64,
    ) -> Result<(SessionKeys, SocketAddr), AdapterError> {
        let mut attempt = 0;
        loop {
            attempt += 1;
            match self.try_handshake_responder(peer_node_id).await {
                Ok(result) => return Ok(result),
                Err(e) if attempt < self.config.handshake_retries => {
                    tracing::warn!(attempt, error = %e, "mesh accept failed, retrying");
                    tokio::time::sleep(Duration::from_millis(100 * attempt as u64)).await;
                }
                Err(e) => return Err(e),
            }
        }
    }

    async fn try_handshake_responder(
        &self,
        peer_node_id: u64,
    ) -> Result<(SessionKeys, SocketAddr), AdapterError> {
        let timeout = self.config.handshake_timeout;
        let socket_arc = self.socket.socket_arc();

        // Wait for initiator's handshake
        let (parsed, source) = tokio::time::timeout(timeout, async {
            loop {
                let mut recv_buf = bytes::BytesMut::with_capacity(protocol::MAX_PACKET_SIZE);
                recv_buf.resize(protocol::MAX_PACKET_SIZE, 0);

                let (n, source) = socket_arc
                    .recv_from(&mut recv_buf)
                    .await
                    .map_err(|e| AdapterError::Connection(format!("recv failed: {}", e)))?;

                recv_buf.truncate(n);
                let data = recv_buf.freeze();

                if let Some(p) = ParsedPacket::parse(data, source) {
                    if p.header.flags.is_handshake() {
                        return Ok::<_, AdapterError>((p, source));
                    }
                }
            }
        })
        .await
        .map_err(|_| AdapterError::Connection("handshake timeout".into()))??;

        // Direct responder: mirror the initiator's `routing_id`-based
        // prologue so direct and routed share one convention.
        let prologue = handshake_prologue(routing_id(peer_node_id), routing_id(self.node_id));
        let mut handshake = NoiseHandshake::responder_with_prologue(
            &self.config.psk,
            &self.static_keypair,
            &prologue,
        )
        .map_err(|e| AdapterError::Fatal(format!("handshake init failed: {}", e)))?;

        handshake
            .read_message(&parsed.payload)
            .map_err(|e| AdapterError::Connection(format!("read_message failed: {}", e)))?;

        let msg2 = handshake
            .write_message(&[])
            .map_err(|e| AdapterError::Connection(format!("write_message failed: {}", e)))?;

        let mut builder = PacketBuilder::new(&[0u8; 32], 0);
        let packet = builder.build_handshake(&msg2);

        self.socket
            .send_to(&packet, source)
            .await
            .map_err(|e| AdapterError::Connection(format!("send failed: {}", e)))?;

        let keys = handshake
            .into_session_keys()
            .map_err(|e| AdapterError::Fatal(format!("key extraction failed: {}", e)))?;

        Ok((keys, source))
    }

    // ── NAT traversal ──────────────────────────────────────────────────
    //
    // `SUBPROTOCOL_REFLEX` client. The handler half lives in the
    // packet-dispatch loop (`process_local_packet`, in the
    // `SUBPROTOCOL_REFLEX` branch) and echoes the observed UDP
    // source back as a `ReflexResponse`. This method is the
    // requester side: send an empty-body request, await the
    // pending-oneshot, return the observed `SocketAddr`.
    //
    // Remember: reflex discovery is an optimization, not a
    // connectivity guarantee. A `ReflexTimeout` or `PeerNotReachable`
    // doesn't mean the peers can't talk; it means this specific
    // address-discovery path didn't resolve.

    /// Send one reflex probe to `peer_node_id` and return the
    /// public `SocketAddr` the peer observed on the probe's UDP
    /// envelope.
    ///
    /// Waits up to [`super::traversal::TraversalConfig::reflex_timeout`] (default
    /// 3 s) for the response. Fails with [`super::traversal::TraversalError::ReflexTimeout`]
    /// on timeout, [`super::traversal::TraversalError::PeerNotReachable`] if the peer
    /// has no active session, or [`super::traversal::TraversalError::Transport`] on
    /// a socket-level send failure.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn probe_reflex(
        &self,
        peer_node_id: u64,
    ) -> Result<std::net::SocketAddr, super::traversal::TraversalError> {
        use super::traversal::{reflex, TraversalError};

        let peer_addr = self
            .peer_addrs
            .get(&peer_node_id)
            .map(|e| *e.value())
            .ok_or(TraversalError::PeerNotReachable)?;

        // Install the pending-oneshot BEFORE sending so an
        // improbably-fast response can still complete it. A
        // previously-in-flight probe to the same peer is
        // overwritten — its waiter will hit ReflexTimeout, which
        // matches the "one probe per peer in flight" contract.
        //
        // Stamp each waiter with a unique generation so our
        // timeout cleanup only evicts *our* entry, not a racing
        // replacement. See `next_waiter_gen` doc for the race.
        let (tx, rx) = oneshot::channel();
        let gen = self
            .next_waiter_gen
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        self.pending_reflex_probes.insert(peer_node_id, (gen, tx));

        // Empty-body event frame on the reflex subprotocol.
        let body = reflex::encode_request();
        if let Err(e) = self
            .send_subprotocol(peer_addr, super::traversal::SUBPROTOCOL_REFLEX, &body)
            .await
        {
            self.pending_reflex_probes
                .remove_if(&peer_node_id, |_, (g, _)| *g == gen);
            return Err(TraversalError::Transport(e.to_string()));
        }

        let timeout = self.traversal_config.reflex_timeout;
        match tokio::time::timeout(timeout, rx).await {
            Ok(Ok(addr)) => Ok(addr),
            Ok(Err(_recv_err)) => {
                // oneshot cancelled — treat as timeout. Only
                // happens if a concurrent probe to the same peer
                // replaced our sender; the replacement owns the
                // map entry now and we must NOT touch it.
                Err(TraversalError::ReflexTimeout)
            }
            Err(_elapsed) => {
                self.pending_reflex_probes
                    .remove_if(&peer_node_id, |_, (g, _)| *g == gen);
                Err(TraversalError::ReflexTimeout)
            }
        }
    }

    /// The current NAT classification for this node. `Unknown`
    /// until the classification sweep has run; updated atomically
    /// by the sweep and by [`Self::reclassify_nat`]. Read-only for
    /// external callers — the sweep is the only writer.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub fn nat_class(&self) -> super::traversal::classify::NatClass {
        super::traversal::classify::NatClass::from_u8(
            self.nat_class.load(std::sync::atomic::Ordering::Acquire),
        )
    }

    /// This node's public-facing `SocketAddr` as observed by a
    /// remote peer during the classification sweep. `None` before
    /// the first sweep has produced an observation. Exposed
    /// primarily for tests + observability; the announce-
    /// capabilities path piggybacks this value onto every signed
    /// `CapabilityAnnouncement`.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub fn reflex_addr(&self) -> Option<std::net::SocketAddr> {
        self.reflex_addr.load_full().map(|arc| *arc)
    }

    /// Install a runtime reflex override. Forces `nat_class =
    /// Open` and `reflex_addr = Some(external)` immediately, and
    /// short-circuits any further classifier sweeps until
    /// [`Self::clear_reflex_override`] is called.
    ///
    /// # Publishing to peers
    ///
    /// This method updates only *local* state. To propagate the
    /// change to peers, call [`Self::announce_capabilities`]
    /// afterward. The setter resets the announce rate-limit
    /// floor so the next announce is guaranteed to broadcast
    /// rather than coalesce against the previous send — cubic
    /// P2 pinned this, after flagging that callers who set an
    /// override within `min_announce_interval` of a prior
    /// announce would find peers still seeing the old reflex.
    ///
    /// **Optimization, not correctness.** A node with no override
    /// still reaches every peer through the routed-handshake
    /// path; the override just pins the publicly-advertised
    /// address when it's already known (port-forwarded server, a
    /// successful stage-4 port-mapping install, etc).
    ///
    /// Safe to call concurrently with `announce_capabilities` —
    /// the triple-write runs under `traversal_publish_mu`
    /// (alongside the announce's multi-field read), so a
    /// concurrent announce either sees the pre-override state
    /// or the fully-installed override, never a torn mix.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub fn set_reflex_override(&self, external: SocketAddr) {
        use std::sync::atomic::Ordering;
        // Hold the publication mutex across the triple-write.
        // Without it, a concurrent `announce_capabilities_with`
        // could interleave its two reads between our three
        // writes and publish a torn state (e.g. the new reflex
        // paired with the pre-override NAT class). The mutex is
        // briefly contended only with other override writers or
        // the announce multi-field read; single-field readers
        // stay lock-free.
        let _g = self.traversal_publish_mu.lock();
        self.reflex_addr.store(Some(Arc::new(external)));
        self.nat_class.store(
            super::traversal::classify::NatClass::Open.as_u8(),
            Ordering::Release,
        );
        self.reflex_override_active.store(true, Ordering::Release);

        // Reset the rate-limit floor so the next
        // `announce_capabilities` call is guaranteed to
        // broadcast — cubic P2 flagged that the override
        // setter's doc implies immediate peer visibility, but
        // the rate limit could coalesce an announce that lands
        // inside `min_announce_interval`. Callers that want
        // peers to see the new reflex "right away" still need
        // to call announce themselves; this just makes that
        // call's broadcast step unconditional instead of
        // coalesced. Cancel any pending trailing-edge flush in
        // the same lock (RT-1 review follow-up): the caller's
        // documented next announce supersedes it, and letting it
        // fire too would put a second broadcast inside the fresh
        // window. The parked flush task no-ops when it finds the
        // slot cleared.
        {
            let mut gate = self.announce_gate.lock();
            gate.last_broadcast_at = None;
            gate.deferred_scheduled = false;
        }
    }

    /// Drop a previously-installed runtime reflex override. The
    /// classifier sweep resumes on its normal cadence; the next
    /// sweep repopulates `reflex_addr` and `nat_class` from real
    /// probe observations. `reflex_addr` is cleared to `None`
    /// immediately so a between-sweep read doesn't return a stale
    /// override value as "still current."
    ///
    /// # Publishing to peers
    ///
    /// Mirrors [`Self::set_reflex_override`]: only local state
    /// changes here. Call [`Self::announce_capabilities`] after
    /// this to tell peers. The rate-limit floor is reset so that
    /// call broadcasts unconditionally.
    ///
    /// No-op when no override is active — safe to call
    /// unconditionally during shutdown / port-mapping revoke
    /// paths.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub fn clear_reflex_override(&self) {
        use std::sync::atomic::Ordering;
        // Hold the publication mutex across the flag flip + the
        // field resets so a concurrent announce can't observe
        // the cleared flag alongside the not-yet-reset reflex /
        // NAT class (or vice versa). Same invariant as in
        // `set_reflex_override`.
        let _g = self.traversal_publish_mu.lock();
        if !self.reflex_override_active.swap(false, Ordering::AcqRel) {
            return;
        }
        // Reset reflex_addr + nat_class to their pre-classification
        // defaults so a caller reading immediately gets an honest
        // "no current observation" answer rather than the stale
        // override.
        self.reflex_addr.store(None);
        self.nat_class.store(
            super::traversal::classify::NatClass::Unknown.as_u8(),
            Ordering::Release,
        );
        // Same rate-limit reset as `set_reflex_override` — the
        // next `announce_capabilities` call broadcasts
        // unconditionally instead of coalescing against the
        // previous send, and a pending trailing-edge flush is
        // canceled for the same reason. See that method's
        // comment for details (cubic P2 + RT-1 follow-up).
        {
            let mut gate = self.announce_gate.lock();
            gate.last_broadcast_at = None;
            gate.deferred_scheduled = false;
        }
    }

    /// Reflex-diff re-classification trigger
    /// (`NAT_TRAVERSAL_V2_PLAN.md` decision 8, trigger 2). Called by
    /// the capability re-announce loop before each periodic announce:
    /// if the currently-observed reflex differs from the one in the
    /// last *published* announcement, run exactly one classification
    /// sweep first so the `nat:*` tag and the reflex field ship
    /// together — a reflex that drifted since the last sweep (probe /
    /// punch activity, gateway reboot) usually means the class is
    /// stale too.
    ///
    /// Returns `true` iff a sweep ran. Deliberately conservative —
    /// all of these skip (no sweep, `false`):
    /// - an active reflex override (it pins `(class, reflex)`; the
    ///   sweep would be short-circuited anyway),
    /// - no prior published announcement (the initial announce path
    ///   owns the first pair),
    /// - no current observation (`reflex_addr = None` — the classify
    ///   loop owns first population; announcing `None` is honest),
    /// - observed == published (the no-flap cadence guard: steady
    ///   state must not add sweeps to the re-announce tick).
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn reclassify_if_reflex_drifted(&self) -> bool {
        use std::sync::atomic::Ordering as AtOrd;
        if self.reflex_override_active.load(AtOrd::Acquire) {
            return false;
        }
        let Some(published) = self.local_announcement.load_full() else {
            return false;
        };
        let Some(observed) = self.reflex_addr() else {
            return false;
        };
        if published.reflex_addr == Some(observed) {
            return false;
        }
        self.reclassify_nat().await;
        true
    }

    /// Testing hook: overwrite the observed reflex WITHOUT the
    /// override pin (unlike [`Self::set_reflex_override`], which pins
    /// `(class, reflex)` and short-circuits the classifier). Lets
    /// tests simulate a between-announce reflex drift — something a
    /// real deployment gets from probe/punch observations after a
    /// gateway reboot, and loopback can never produce naturally —
    /// so the reflex-diff trigger has something to reconcile. Runs
    /// under `traversal_publish_mu` like every multi-field traversal
    /// write.
    #[cfg(feature = "nat-traversal")]
    #[doc(hidden)]
    pub fn set_reflex_for_test(&self, addr: SocketAddr) {
        let _g = self.traversal_publish_mu.lock();
        self.reflex_addr.store(Some(Arc::new(addr)));
    }

    /// Testing / debugging hook: force this node's advertised
    /// `NatClass` without running the probe sweep. On loopback
    /// every node classifies as `Open`, which means the pair-type
    /// matrix always picks `Direct` — useful for Open×Open cases
    /// but leaves the `SinglePunch` path unexercised. Regression
    /// tests that need to drive `connect_direct` through the
    /// punch branch set this to `Cone` (or `Symmetric`) before
    /// calling `announce_capabilities`, then the peer reads it
    /// back via `peer_nat_class` and the matrix resolves to
    /// `SinglePunch`.
    ///
    /// Not for production use: the classifier is the intended
    /// writer, and forcing a class short-circuits real NAT
    /// observation. Exposed as `pub` (not `pub(crate)`) only so
    /// `tests/connect_direct.rs` can reach it from a separate
    /// crate.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    #[doc(hidden)]
    pub fn force_nat_class_for_test(&self, class: super::traversal::classify::NatClass) {
        self.nat_class.store(class.as_u8(), Ordering::Release);
    }

    /// Test / debug accessor for the most-recent local
    /// capability announcement. Returns `None` until the first
    /// `announce_capabilities*` call. The stored value is the
    /// coherent snapshot published by
    /// [`Self::announce_capabilities_with`] under
    /// `traversal_publish_mu` — regression tests for the
    /// (class, reflex_addr) race read this instead of the
    /// separate atomic accessors, which are lock-free and can
    /// return torn pairs under concurrent mutation.
    #[doc(hidden)]
    pub fn local_announcement_for_test(&self) -> Option<Arc<CapabilityAnnouncement>> {
        self.local_announcement.load_full()
    }

    /// Send a `PunchRequest` to a coordinator peer `relay`, asking
    /// it to mediate a hole-punch to `target`. Returns the
    /// `PunchIntroduce` produced by the coordinator (the one
    /// arriving on this node's side of the introduction — carrying
    /// `target`'s reflex and the shared `fire_at`).
    ///
    /// This is a stage-3b primitive: it exercises the coordinator
    /// fan-out end-to-end but does not itself schedule the
    /// keep-alive train or finalize the punched session. The
    /// full `connect_direct` flow lands in stage 3c.
    ///
    /// Fails with:
    /// - [`super::traversal::TraversalError::PeerNotReachable`] if `relay` has no
    ///   active session.
    /// - [`super::traversal::TraversalError::Transport`] on a socket-level send
    ///   failure.
    /// - [`super::traversal::TraversalError::RendezvousRejected`] if the
    ///   coordinator refused with a typed `PunchReject` (rate-limited, no
    ///   cached target reflex, no session with the target, or the
    ///   anti-reflection check failed). This resolves *immediately* — no
    ///   `punch_deadline` wait — and carries the reason sub-kind.
    /// - [`super::traversal::TraversalError::PunchFailed`] if the coordinator
    ///   neither introduced nor rejected within
    ///   [`super::traversal::TraversalConfig::punch_deadline`].
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn request_punch(
        &self,
        relay: u64,
        target: u64,
        self_reflex: std::net::SocketAddr,
    ) -> Result<super::traversal::rendezvous::PunchIntroduce, super::traversal::TraversalError>
    {
        use super::traversal::rendezvous::{PunchRequest, RendezvousMsg};
        use super::traversal::TraversalError;

        let relay_addr = self
            .peer_addrs
            .get(&relay)
            .map(|e| *e.value())
            .ok_or(TraversalError::PeerNotReachable)?;

        // Install the waiter BEFORE sending. An improbably fast
        // coordinator response (R is local, A is local) could
        // otherwise arrive before the oneshot is registered.
        // Keyed by `target` because the introduce we'll receive
        // has `peer = target` in its body.
        //
        // Generation-stamped so our cleanup only evicts our own
        // entry — a concurrent `request_punch` to the same
        // target installs a new entry (and drops our sender),
        // and that replacement must survive our timeout/send-
        // failure remove.
        let (tx, rx) = oneshot::channel();
        let gen = self
            .next_waiter_gen
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        // Wire correlation token, echoed by any PunchReject this
        // request draws. Skip the reserved 0 sentinel on wrap.
        let punch_id = {
            let mut id = self
                .next_punch_id
                .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            if id == 0 {
                id = self
                    .next_punch_id
                    .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
            }
            id
        };
        // Bind to the relay we're sending PunchRequest to — only
        // that node is authorized to send the matching introduce
        // back. Without this, any session peer could forge a
        // PunchIntroduce for `target` and complete this oneshot
        // with attacker-chosen reflex data.
        self.pending_punch_introduces
            .insert(target, (gen, relay, punch_id, tx));

        let body = RendezvousMsg::PunchRequest(PunchRequest {
            target,
            punch_id,
            self_reflex,
        })
        .encode();
        if let Err(e) = self
            .send_subprotocol(relay_addr, super::traversal::SUBPROTOCOL_RENDEZVOUS, &body)
            .await
        {
            self.pending_punch_introduces
                .remove_if(&target, |_, (g, _, _, _)| *g == gen);
            return Err(TraversalError::Transport(e.to_string()));
        }

        let deadline = self.traversal_config.punch_deadline;
        match tokio::time::timeout(deadline, rx).await {
            Ok(Ok(PunchIntroduceOutcome::Introduce(intro))) => Ok(intro),
            Ok(Ok(PunchIntroduceOutcome::Rejected(reason))) => {
                // Coordinator refused with a typed reason — fast,
                // non-timeout failure (Finding 5). The waiter was
                // removed by the dispatch arm that delivered the
                // reject; nothing to clean up here.
                self.traversal_stats.record_punch_rejection();
                Err(TraversalError::RendezvousRejected(
                    reason.kind().to_string(),
                ))
            }
            Ok(Err(_recv_err)) => {
                // oneshot cancelled — another request_punch to the
                // same target replaced our sender. Don't touch the
                // map: the replacement owns the entry now. Not a
                // timeout — no reason counter (stage 5): the
                // superseding call does its own accounting.
                Err(TraversalError::PunchFailed)
            }
            Err(_elapsed) => {
                self.pending_punch_introduces
                    .remove_if(&target, |_, (g, _, _, _)| *g == gen);
                self.traversal_stats.record_punch_timeout();
                Err(TraversalError::PunchFailed)
            }
        }
    }

    /// Install a waiter for an incoming `PunchIntroduce` from
    /// `counterpart`, brokered by `coordinator`. The dispatch arm
    /// admits the introduce only when the session peer matches
    /// `coordinator`. The returned future resolves when the
    /// dispatcher decodes a matching introduce, or with
    /// [`super::traversal::TraversalError::PunchFailed`] after
    /// [`super::traversal::TraversalConfig::punch_deadline`].
    ///
    /// Stage-3b responder-side primitive: the peer being punched
    /// *into* uses this to observe the introduce without
    /// initiating the flow itself. The responder must know which
    /// coordinator will forward the introduce — supply that node's
    /// id as `coordinator`. Stage 3c wires the keep-alive train
    /// onto the returned introduce.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn await_punch_introduce(
        &self,
        counterpart: u64,
        coordinator: u64,
    ) -> Result<super::traversal::rendezvous::PunchIntroduce, super::traversal::TraversalError>
    {
        use super::traversal::TraversalError;
        let (tx, rx) = oneshot::channel();
        let gen = self
            .next_waiter_gen
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        self.pending_punch_introduces
            .insert(counterpart, (gen, coordinator, 0, tx));
        let deadline = self.traversal_config.punch_deadline;
        match tokio::time::timeout(deadline, rx).await {
            Ok(Ok(PunchIntroduceOutcome::Introduce(intro))) => Ok(intro),
            Ok(Ok(PunchIntroduceOutcome::Rejected(reason))) => {
                self.traversal_stats.record_punch_rejection();
                Err(TraversalError::RendezvousRejected(
                    reason.kind().to_string(),
                ))
            }
            Ok(Err(_)) => Err(TraversalError::PunchFailed),
            Err(_) => {
                self.pending_punch_introduces
                    .remove_if(&counterpart, |_, (g, _, _, _)| *g == gen);
                self.traversal_stats.record_punch_timeout();
                Err(TraversalError::PunchFailed)
            }
        }
    }

    /// Install a waiter for an incoming `PunchAck` whose
    /// `from_peer` matches `counterpart`. Stage-3d correlation
    /// surface — the `SinglePunch` path in `connect_direct`
    /// registers the waiter before firing `request_punch` and
    /// awaits it afterward. Times out with
    /// [`super::traversal::TraversalError::PunchFailed`] after
    /// [`super::traversal::TraversalConfig::punch_deadline`].
    ///
    /// Note: the caller inserts the oneshot sender into
    /// `pending_punch_acks` before issuing the request so the ack
    /// can't arrive and be dropped before the await call is
    /// entered.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn await_punch_ack(
        &self,
        counterpart: u64,
        coordinator: u64,
    ) -> Result<super::traversal::rendezvous::PunchAck, super::traversal::TraversalError> {
        use super::traversal::TraversalError;
        let (tx, rx) = oneshot::channel();
        let gen = self
            .next_waiter_gen
            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        self.pending_punch_acks
            .insert(counterpart, (gen, coordinator, tx));
        let deadline = self.traversal_config.punch_deadline;
        match tokio::time::timeout(deadline, rx).await {
            Ok(Ok(ack)) => Ok(ack),
            Ok(Err(_)) => Err(TraversalError::PunchFailed),
            Err(_) => {
                self.pending_punch_acks
                    .remove_if(&counterpart, |_, (g, _, _)| *g == gen);
                Err(TraversalError::PunchFailed)
            }
        }
    }

    /// Fire the classification sweep. Picks up to two currently-
    /// connected peers, runs [`Self::probe_reflex`] against each in
    /// parallel, feeds the observations to
    /// [`super::traversal::classify::ClassifyFsm`], and updates
    /// `nat_class` + `reflex_addr` with the result.
    ///
    /// Runs at most one *sweep* at a time — a second `reclassify_nat`
    /// call while a sweep is in flight is a no-op (the `SweepGuard`
    /// at the top of the body). The gate is sweep-level only: a
    /// standalone [`Self::probe_reflex`] — e.g. the
    /// `net_mesh_probe_reflex` FFI — is *not* gated and can still race
    /// a sweep's probe to the same peer (a benign collision; see the
    /// gate comment in the body). Exits early if fewer than 2
    /// peers are currently connected; callers should check
    /// [`Self::nat_class`] after the returned future completes to
    /// see whether classification produced a definite verdict or
    /// stayed at `Unknown`.
    ///
    /// Bounded by [`super::traversal::TraversalConfig::classify_deadline`] — even if
    /// probes hang, the sweep returns within that window with
    /// whatever observations arrived.
    ///
    /// Requires the `nat-traversal` cargo feature.
    #[cfg(feature = "nat-traversal")]
    pub async fn reclassify_nat(&self) {
        use super::traversal::classify::ClassifyFsm;

        // Single-flight gate (doc contract: "at most one sweep at a
        // time"). `reclassify_nat` is `pub` + FFI-exported, so an
        // operator call can race the background classify loop's tick
        // (or another operator call). Concurrent sweeps collide on
        // `pending_reflex_probes` — keyed by peer id, the later
        // probe insert drops the earlier sweep's oneshot and starves
        // it. A second concurrent entry is a no-op; the RAII guard
        // clears the flag on every exit path below.
        //
        // Scope: this gate serializes *sweeps* against each other, not
        // the `pending_reflex_probes` map itself. A standalone
        // `probe_reflex` (the `net_mesh_probe_reflex` FFI) doesn't take
        // the gate, so it can still race a sweep's probe to the same
        // peer and cancel one of them. That residual is benign: probe
        // waiters are generation-stamped (cleanup can't evict a
        // replacement), the loser just gets `ReflexTimeout`, and the
        // <2-observation guard (Finding B2) keeps a sweep that drops a
        // probe this way on its prior class instead of flapping to
        // Unknown.
        let Some(_sweep) = SweepGuard::try_enter(&self.nat_classifying) else {
            return;
        };

        // Reflex-override short-circuit: an operator-set (or
        // port-mapping installed) external address already tells
        // us everything the classifier would: NAT type is Open,
        // reflex is the override. Running the multi-peer probe
        // sweep would only replace the overridden values with
        // (possibly worse) observations — skip it.
        if self
            .reflex_override_active
            .load(std::sync::atomic::Ordering::Acquire)
        {
            return;
        }

        // Snapshot up to two peers. Two is enough to distinguish
        // Cone vs. Symmetric (plan §2); sampling more adds probe
        // traffic for no classification gain.
        //
        // Caveat (code review 2026-06-21, Finding B4): symmetric-NAT
        // detection assumes the two peers are distinct *destinations*
        // (different public IPs). Two node ids resolving to the same
        // host/IP look like one destination to the NAT, so a
        // symmetric NAT keyed on dest IP could hand out the same port
        // for both and be misread as Cone. Low-probability on a real
        // mesh, and it only affects the Cone-vs-Symmetric distinction
        // — a misread still falls back to the routed path on punch
        // failure.
        let peers: Vec<u64> = self.peers.iter().map(|e| *e.key()).take(2).collect();
        if peers.len() < 2 {
            return;
        }

        // Fire probes in parallel so the sweep finishes in one
        // reflex_timeout window rather than N*timeout. Each probe
        // already respects its own timeout via `probe_reflex`.
        let bind = self.local_addr();
        let futures = peers.iter().copied().map(|peer| async move {
            let res = self.probe_reflex(peer).await;
            (peer, res)
        });
        let deadline = self.traversal_config.classify_deadline;
        let results = match tokio::time::timeout(deadline, futures::future::join_all(futures)).await
        {
            Ok(results) => results,
            Err(_elapsed) => {
                // Classification-deadline blown. Leave current
                // classification untouched — a later sweep can
                // retry; treating deadline-expired as "Unknown"
                // would flap state on a temporarily slow link.
                tracing::debug!("nat-traversal: classify_deadline elapsed, keeping prior state");
                return;
            }
        };

        let mut fsm = ClassifyFsm::new();
        let mut latest_reflex: Option<std::net::SocketAddr> = None;
        for (peer, res) in results {
            if let Ok(addr) = res {
                fsm.observe(peer, addr);
                latest_reflex = Some(addr);
            }
        }

        let class = fsm.classify(bind);
        self.commit_reclassify_observations(class, latest_reflex, fsm.observation_count());
    }

    /// Commit the result of a classification sweep.
    ///
    /// Split out from [`Self::reclassify_nat`] so the
    /// override-race guard is unit-testable without standing up
    /// a full probe mesh. The guard fixes a cubic-flagged P1
    /// bug: the entry-time check in `reclassify_nat` races with
    /// any `set_reflex_override` call that lands *during* the
    /// probe sweep — the flag flips false→true while we're
    /// awaiting probe futures, and a blind commit would silently
    /// stomp the fresh override with whatever the classifier
    /// observed. A port-mapping install is a strong signal (we
    /// have a known-public `external` address) that outranks
    /// peer-probed reflex; clobbering it would demote the node
    /// from Open back to whatever NAT class the probes inferred
    /// and could re-advertise the wrong reflex to peers.
    #[cfg(feature = "nat-traversal")]
    fn commit_reclassify_observations(
        &self,
        class: super::traversal::classify::NatClass,
        latest_reflex: Option<std::net::SocketAddr>,
        observation_count: usize,
    ) {
        use std::sync::atomic::Ordering;
        // Hold the publication mutex across the re-check + the
        // (potentially) paired writes. This both makes the
        // override mid-sweep guard atomic with the commit
        // (no TOCTOU on the flag vs stores), and serializes
        // against concurrent `announce_capabilities_with` reads
        // so the classifier can't publish nat_class without
        // reflex_addr (or vice versa) being visible together.
        let _g = self.traversal_publish_mu.lock();
        if self.reflex_override_active.load(Ordering::Acquire) {
            tracing::debug!("nat-traversal: reflex override installed mid-sweep, skipping commit");
            return;
        }
        // Insufficient-observations guard (code review 2026-06-21,
        // Finding B2). `classify` returns `Unknown` below two
        // observations; publishing that would flap a previously-good
        // Cone/Open down to Unknown on nothing more than transient
        // packet loss (one of the two probes dropped). That's the same
        // flap the deadline-expired branch in `reclassify_nat`
        // deliberately avoids — so apply the same policy here: keep
        // the prior (class, reflex) pair and let a later two-response
        // sweep install a fresh one.
        if observation_count < 2 {
            tracing::debug!(
                observation_count,
                "nat-traversal: fewer than 2 probe observations this sweep, keeping prior pair"
            );
            return;
        }
        // No-reflex guard (defense-in-depth). For coherent inputs from
        // `reclassify_nat` the <2-observation guard above already
        // subsumes this case: an all-probes-failed sweep has
        // `observation_count == 0`, and any sweep with
        // `observation_count >= 2` necessarily threaded a
        // `latest_reflex` (it is set on every `fsm.observe`). This
        // guard remains for a *torn* input — a caller passing
        // `observation_count >= 2` with `latest_reflex == None` — so
        // the commit never publishes a `nat_class` without a paired
        // reflex (the `traversal_publish_mu` coherence invariant a
        // downstream `announce_capabilities_with` reader relies on).
        // Same policy as the deadline-expired branch in
        // `reclassify_nat`: leave the previously-published pair
        // untouched. Pinned by
        // `commit_keeps_prior_on_torn_class_without_reflex`.
        let Some(addr) = latest_reflex else {
            tracing::debug!(
                "nat-traversal: no probe observations this sweep, keeping prior (class, reflex) pair"
            );
            return;
        };
        self.nat_class.store(class.as_u8(), Ordering::Release);
        self.reflex_addr.store(Some(Arc::new(addr)));
        tracing::debug!(
            nat_class = ?class,
            reflex = ?addr,
            "nat-traversal: reclassified",
        );
    }
}

// ── Adapter trait impl ──────────────────────────────────────────────────

#[async_trait]
impl Adapter for MeshNode {
    async fn init(&mut self) -> Result<(), AdapterError> {
        // MeshNode is initialized via new() + connect(). This is a no-op.
        Ok(())
    }

    async fn on_batch(&self, batch: std::sync::Arc<Batch>) -> Result<(), AdapterError> {
        // Send to the first connected peer. For a real mesh, this should
        // use the routing table to pick the right peer based on the
        // event's destination. For now, round-robin or first-match.
        let peer_addr = self
            .peers
            .iter()
            .next()
            .map(|e| e.value().addr)
            .ok_or_else(|| AdapterError::Connection("no peers connected".into()))?;

        self.send_to_peer(peer_addr, &batch).await
    }

    async fn flush(&self) -> Result<(), AdapterError> {
        Ok(())
    }

    async fn shutdown(&self) -> Result<(), AdapterError> {
        self.shutdown.store(true, Ordering::Release);
        self.shutdown_notify.notify_waiters();
        self.router.stop();

        // Deactivate all sessions
        for entry in self.peers.iter() {
            entry.value().session.deactivate();
        }

        // Wait for background tasks
        let tasks = std::mem::take(&mut *self.tasks.lock().await);
        for handle in tasks {
            let _ = handle.await;
        }

        Ok(())
    }

    async fn poll_shard(
        &self,
        shard_id: u16,
        from_id: Option<&str>,
        limit: usize,
    ) -> Result<ShardPollResult, AdapterError> {
        let queue = match self.inbound.get(&shard_id) {
            Some(q) => q,
            None => return Ok(ShardPollResult::empty()),
        };

        let mut events = Vec::with_capacity(limit.min(1000));
        let mut last_id = None;
        // from_id is ignored — the SegQueue is consume-once, so every pop
        // removes the event permanently. Cursor-based skipping would destroy
        // events that have already been consumed. Callers should consume
        // from the head without a cursor.
        let _ = from_id;

        for _ in 0..limit {
            match queue.pop() {
                Some(event) => {
                    last_id = Some(event.id.clone());
                    events.push(event);
                }
                None => break,
            }
        }

        let has_more = !queue.is_empty();

        Ok(ShardPollResult {
            events,
            next_id: last_id,
            has_more,
        })
    }

    fn name(&self) -> &'static str {
        "mesh"
    }

    async fn is_healthy(&self) -> bool {
        self.started.load(Ordering::Acquire) && !self.peers.is_empty()
    }
}

impl Drop for MeshNode {
    fn drop(&mut self) {
        self.shutdown.store(true, Ordering::Release);
        self.shutdown_notify.notify_waiters();
        self.router.stop();
    }
}

#[cfg(all(test, feature = "nat-traversal"))]
mod punch_observer_tests {
    //! Tests for [`await_punch_observer_outcome`].
    //!
    //! Regression coverage for a cubic-flagged bug (P2): earlier
    //! revisions collapsed the `Ok(Err(_))` (sender dropped) and
    //! `Err(_)` (deadline) arms into a single `remove`-in-both
    //! branch, which evicted replacement observers. Each test
    //! below pins one of the three outcomes independently.
    use super::*;
    use crate::adapter::net::traversal::rendezvous::Keepalive;
    use tokio::sync::oneshot;

    fn sample_ka() -> Keepalive {
        Keepalive {
            sender_node_id: 0x1234,
            punch_id: 0,
        }
    }

    fn sample_peer() -> SocketAddr {
        "198.51.100.5:9001".parse().unwrap()
    }

    /// Expected counterpart node id stored alongside each observer.
    /// `await_punch_observer_outcome` itself doesn't validate it —
    /// the receive loop's `remove_if` does that before firing — so
    /// these cleanup-semantics tests just need a stable value.
    const EXPECTED_PEER: u64 = 0x1234;

    /// Keep-alive fires before the deadline — outcome is `true`
    /// (caller emits the ack). The map entry was consumed by the
    /// receive loop's sender-validated `remove_if` when it fired the
    /// oneshot, so the helper doesn't need to remove anything.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn fires_true_when_keepalive_arrives() {
        let observers: DashMap<SocketAddr, (u64, oneshot::Sender<Keepalive>)> = DashMap::new();
        let peer = sample_peer();
        let (tx, rx) = oneshot::channel();
        observers.insert(peer, (EXPECTED_PEER, tx));

        // Simulate the receive loop firing the oneshot after its
        // sender-id check passes: remove from the map + send the ka.
        let (_, (_id, fired_tx)) = observers.remove(&peer).unwrap();
        fired_tx.send(sample_ka()).expect("send");

        let result =
            await_punch_observer_outcome(rx, Duration::from_secs(1), &observers, peer).await;
        assert!(result, "keepalive arrival should return true");
    }

    /// Deadline expires while our sender is still the live value
    /// in the map — helper must evict the stale entry so a late
    /// keep-alive doesn't find it.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn timeout_evicts_own_stale_entry() {
        let observers: DashMap<SocketAddr, (u64, oneshot::Sender<Keepalive>)> = DashMap::new();
        let peer = sample_peer();
        let (tx, rx) = oneshot::channel();
        observers.insert(peer, (EXPECTED_PEER, tx));

        // Very short deadline; nobody fires.
        let result =
            await_punch_observer_outcome(rx, Duration::from_millis(50), &observers, peer).await;
        assert!(!result, "timeout should return false");
        assert!(
            !observers.contains_key(&peer),
            "timeout should evict our own stale entry",
        );
    }

    /// The cubic-flagged regression: a newer observer replaces
    /// ours (our sender is dropped). Our task's `Ok(Err(_))` arm
    /// must **not** remove the peer_reflex key — it would evict
    /// the replacement observer that's the current live value
    /// in the map.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn sender_dropped_leaves_replacement_observer_intact() {
        let observers: DashMap<SocketAddr, (u64, oneshot::Sender<Keepalive>)> = DashMap::new();
        let peer = sample_peer();

        // Install observer A.
        let (tx_a, rx_a) = oneshot::channel::<Keepalive>();
        observers.insert(peer, (EXPECTED_PEER, tx_a));

        // Install observer B via insert — this drops A's sender
        // (the old value returned from the insert is dropped
        // immediately). Now the map contains B's sender.
        let (tx_b, _rx_b) = oneshot::channel::<Keepalive>();
        observers.insert(peer, (EXPECTED_PEER, tx_b));
        assert!(observers.contains_key(&peer), "B's sender in map");

        // A's task runs the cleanup helper. A's rx_a sees
        // RecvError (tx_a dropped), outcome is `Ok(Err(_))`.
        let result =
            await_punch_observer_outcome(rx_a, Duration::from_secs(5), &observers, peer).await;
        assert!(!result, "sender-dropped path returns false");
        assert!(
            observers.contains_key(&peer),
            "B's sender must still be in the map — A's cleanup must not evict",
        );
    }

    /// Idempotent-by-peer check: after a timeout-eviction,
    /// removing again is a no-op. Prevents a hypothetical
    /// double-eviction regression where the helper called
    /// `remove` on every cleanup path.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn timeout_then_sender_drop_does_not_double_evict() {
        let observers: DashMap<SocketAddr, (u64, oneshot::Sender<Keepalive>)> = DashMap::new();
        let peer = sample_peer();

        // First task: install A, let it time out, evict.
        let (tx_a, rx_a) = oneshot::channel::<Keepalive>();
        observers.insert(peer, (EXPECTED_PEER, tx_a));
        let r1 =
            await_punch_observer_outcome(rx_a, Duration::from_millis(20), &observers, peer).await;
        assert!(!r1);
        assert!(!observers.contains_key(&peer));

        // Second task: install B, drop B's sender via a fresh
        // insert from C — simulates the "replacement" scenario
        // but now for a different observer lineage.
        let (tx_b, rx_b) = oneshot::channel::<Keepalive>();
        observers.insert(peer, (EXPECTED_PEER, tx_b));
        let (tx_c, _rx_c) = oneshot::channel::<Keepalive>();
        observers.insert(peer, (EXPECTED_PEER, tx_c));

        // B's task cleanup. Must NOT remove peer (C is live).
        let r2 = await_punch_observer_outcome(rx_b, Duration::from_secs(5), &observers, peer).await;
        assert!(!r2);
        assert!(
            observers.contains_key(&peer),
            "C's sender must remain after B's sender-dropped cleanup",
        );
    }
}

#[cfg(all(test, feature = "nat-traversal"))]
mod keepalive_offset_tests {
    //! Unit coverage for [`keepalive_send_offsets`] (code review
    //! 2026-06-21, Finding 3): the per-packet send schedule must
    //! clamp a coordinator-supplied `fire_at_ms` so a far-future
    //! value can't park the keep-alive sender task indefinitely or
    //! overflow `Instant`.
    use super::keepalive_send_offsets;
    use std::time::Duration;

    const DEADLINE: Duration = Duration::from_secs(5);

    #[test]
    fn normal_lead_is_preserved_with_documented_spacing() {
        // fire_at 500 ms in the future → 500 / 600 / 750 ms.
        let offsets = keepalive_send_offsets(1_000_500, 1_000_000, DEADLINE);
        assert_eq!(offsets[0], Duration::from_millis(500));
        assert_eq!(offsets[1], Duration::from_millis(600));
        assert_eq!(offsets[2], Duration::from_millis(750));
    }

    #[test]
    fn past_fire_at_collapses_to_immediate() {
        // fire_at already elapsed → base lead 0; spacing still applies.
        let offsets = keepalive_send_offsets(900_000, 1_000_000, DEADLINE);
        assert_eq!(offsets[0], Duration::ZERO);
        assert_eq!(offsets[1], Duration::from_millis(100));
        assert_eq!(offsets[2], Duration::from_millis(250));
    }

    #[test]
    fn far_future_fire_at_is_clamped_to_deadline() {
        // A malicious/buggy coordinator names a fire time ~1e9 s out.
        // The base lead must clamp to `deadline`, bounding the sender
        // task's lifetime rather than parking it for ~31 years.
        let offsets = keepalive_send_offsets(1_000_000 + 1_000_000_000_000, 1_000_000, DEADLINE);
        assert_eq!(offsets[0], DEADLINE, "base lead must clamp to deadline");
        // Spacing applies after the clamp; bounded just past it.
        assert_eq!(offsets[1], DEADLINE + Duration::from_millis(100));
        assert_eq!(offsets[2], DEADLINE + Duration::from_millis(250));
    }

    #[test]
    fn u64_max_fire_at_does_not_panic_and_clamps() {
        // Extreme input: must neither panic on the millis→Duration
        // conversion nor exceed the clamp.
        let offsets = keepalive_send_offsets(u64::MAX, 0, DEADLINE);
        assert_eq!(offsets[0], DEADLINE);
        assert!(offsets[2] <= DEADLINE + Duration::from_millis(250));
    }
}

#[cfg(all(test, feature = "nat-traversal"))]
mod sweep_guard_tests {
    //! Unit coverage for [`SweepGuard`] (code review 2026-06-21,
    //! port-scanning Finding B1): the single-flight gate that backs
    //! `reclassify_nat`'s "at most one sweep at a time" contract.
    use super::SweepGuard;
    use std::sync::atomic::AtomicBool;

    #[test]
    fn try_enter_is_single_flight_and_releases_on_drop() {
        let flag = AtomicBool::new(false);

        let g1 = SweepGuard::try_enter(&flag);
        assert!(g1.is_some(), "first entry must acquire the gate");
        assert!(
            SweepGuard::try_enter(&flag).is_none(),
            "a second concurrent entry must be refused while the first is held",
        );

        drop(g1);
        assert!(
            SweepGuard::try_enter(&flag).is_some(),
            "after the guard drops, the gate must be re-enterable",
        );
    }
}

#[cfg(all(test, feature = "nat-traversal"))]
mod reclassify_override_race_tests {
    //! Regression coverage for a cubic-flagged P1 bug:
    //! [`MeshNode::reclassify_nat`] checked
    //! `reflex_override_active` only at entry, then ran the
    //! multi-peer probe sweep, then committed the result. A
    //! `set_reflex_override` call landing *after* the entry
    //! check but *before* the commit was silently stomped:
    //! the commit unconditionally overwrote `nat_class` and
    //! `reflex_addr` with the probe-derived values, undoing
    //! the freshly-installed override.
    //!
    //! Fix: [`MeshNode::reclassify_nat`] now calls
    //! [`MeshNode::commit_reclassify_observations`], which
    //! re-loads the flag before any store and bails out if an
    //! override landed mid-sweep. Tests below pin that guard
    //! without needing to stand up a real probe mesh.
    use super::*;
    use crate::adapter::net::traversal::classify::NatClass;
    use std::net::SocketAddr;

    async fn build_node_for_test() -> Arc<MeshNode> {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x17u8; 32]);
        Arc::new(
            MeshNode::new(EntityKeypair::generate(), cfg)
                .await
                .expect("MeshNode::new"),
        )
    }

    /// Regression for the capability re-announce loop. A node's own
    /// capability self-entry TTL-expires and the fold sweeper reaps it,
    /// after which (a) its callee-side nRPC gate denies its own services
    /// and (b) peers can no longer discover it. The loop must re-announce
    /// on its cadence — keeping the self-entry alive past its TTL (checked
    /// here) while advancing `capability_version` (the actual broadcast).
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn capability_reannounce_keeps_self_entry_alive_past_ttl() {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x21u8; 32])
            .with_capability_reannounce_interval(Duration::from_millis(40));
        let node = Arc::new(
            MeshNode::new(EntityKeypair::generate(), cfg)
                .await
                .expect("MeshNode::new"),
        );
        // Self-entry with a deliberately short TTL — without the loop it
        // would expire and the fold sweeper (500 ms) would reap it.
        node.announce_capabilities_with(CapabilitySet::new(), Duration::from_millis(120), true)
            .await
            .expect("announce");
        node.start_arc();

        let v0 = node.capability_version.load(Ordering::Relaxed);
        // Past the 120 ms TTL and a fold sweep tick.
        tokio::time::sleep(Duration::from_millis(750)).await;
        let present = node
            .capability_fold
            .with_state(|s| s.by_node.contains_key(&node.node_id));
        let v1 = node.capability_version.load(Ordering::Relaxed);
        assert!(
            present,
            "self-entry must survive past its TTL while the re-announce loop runs"
        );
        assert!(
            v1 >= v0 + 3,
            "the loop must re-announce (broadcast) periodically: version {v0} -> {v1}"
        );
    }

    /// Control for the above: with the loop disabled (`Duration::MAX`),
    /// the self-entry expires and is swept — the pre-fix behavior, pinned
    /// so the loop's effect is unambiguous.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn capability_self_entry_expires_without_reannounce() {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x22u8; 32])
            .with_capability_reannounce_interval(Duration::MAX);
        let node = Arc::new(
            MeshNode::new(EntityKeypair::generate(), cfg)
                .await
                .expect("MeshNode::new"),
        );
        node.announce_capabilities_with(CapabilitySet::new(), Duration::from_millis(120), true)
            .await
            .expect("announce");
        node.start_arc();

        tokio::time::sleep(Duration::from_millis(750)).await;
        let present = node
            .capability_fold
            .with_state(|s| s.by_node.contains_key(&node.node_id));
        assert!(
            !present,
            "without the re-announce loop the self-entry must expire and be swept"
        );
    }

    /// Regression for the P2 throttle interaction: when the re-announce
    /// interval is configured *below* `min_announce_interval`, the loop ticks
    /// fast but `announce_capabilities_with` rate-limits the network broadcast
    /// to `min_announce_interval`. The stamped TTL must cover that *effective*
    /// (throttled) cadence — `2 × min_announce_interval` here — not the bare
    /// `2 × reannounce_interval`, which would expire on peers before the
    /// throttle releases the next broadcast.
    #[test]
    fn reannounce_ttl_covers_throttled_broadcast_cadence() {
        // reannounce 40 ms ≪ min_announce 10 s: the throttle dominates.
        let ttl = capability_reannounce_ttl(Duration::from_millis(40), Duration::from_secs(10));
        assert_eq!(
            ttl,
            Duration::from_secs(20),
            "TTL must be 2× the effective (throttled) cadence, not 2× the 40 ms tick"
        );
    }

    /// When the re-announce interval dominates `min_announce_interval`, the
    /// throttle is a no-op and the TTL is just `2 × reannounce_interval`.
    #[test]
    fn reannounce_ttl_uses_reannounce_when_it_dominates() {
        // Defaults: reannounce 150 s, min_announce 10 s.
        let ttl = capability_reannounce_ttl(Duration::from_secs(150), Duration::from_secs(10));
        assert_eq!(ttl, Duration::from_secs(300));
    }

    /// Both intervals sub-second → the TTL still floors at 1 s, since the
    /// announce TTL is truncated to whole seconds on the wire.
    #[test]
    fn reannounce_ttl_floors_at_one_second() {
        let ttl = capability_reannounce_ttl(Duration::from_millis(40), Duration::from_millis(50));
        assert_eq!(ttl, Duration::from_secs(1));
    }

    /// Pre-fix behavior: with override inactive, the commit
    /// path overwrites both `nat_class` and `reflex_addr`.
    /// This pins the positive case so the guard doesn't
    /// silently turn into a no-op.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn commit_applies_when_override_inactive() {
        let node = build_node_for_test().await;
        let probed: SocketAddr = "198.51.100.9:4242".parse().unwrap();

        // Override flag is false by default.
        node.commit_reclassify_observations(NatClass::Cone, Some(probed), 2);

        assert_eq!(node.nat_class(), NatClass::Cone);
        assert_eq!(node.reflex_addr(), Some(probed));
    }

    /// The race guard: flag flipped true mid-sweep →
    /// commit must be a no-op. Without the fix the `nat_class`
    /// store and the `reflex_addr` store would land regardless,
    /// demoting the override-provided Open/external-ip back to
    /// the classifier's observation.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn commit_skips_when_override_installed_mid_sweep() {
        let node = build_node_for_test().await;
        let override_addr: SocketAddr = "203.0.113.77:9999".parse().unwrap();
        let probed: SocketAddr = "198.51.100.9:4242".parse().unwrap();

        // Simulate the race: `reclassify_nat` passed its entry
        // check with the flag false, ran probes, and is about
        // to commit. In between, port-mapping install fires
        // `set_reflex_override` — the flag flips true and the
        // reflex/class are written.
        node.set_reflex_override(override_addr);
        assert_eq!(node.nat_class(), NatClass::Open);
        assert_eq!(node.reflex_addr(), Some(override_addr));

        // Now the classifier's (stale) commit tries to land.
        // With the guard in place, it must be skipped.
        node.commit_reclassify_observations(NatClass::Symmetric, Some(probed), 2);

        assert_eq!(
            node.nat_class(),
            NatClass::Open,
            "mid-sweep commit stomped the override's NAT class — \
             the node would be demoted from Open back to Symmetric",
        );
        assert_eq!(
            node.reflex_addr(),
            Some(override_addr),
            "mid-sweep commit stomped the override reflex — the \
             node would advertise the classifier's observation \
             instead of the known-public mapping",
        );
    }

    /// Same guard, but the `latest_reflex = None` path — when
    /// every probe failed, the buggy commit *still* wrote
    /// `nat_class` (only the `reflex_addr` store was gated by
    /// `Some`). The fix's guard covers both stores.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn commit_skips_nat_class_store_even_when_reflex_absent() {
        let node = build_node_for_test().await;
        let override_addr: SocketAddr = "203.0.113.77:9999".parse().unwrap();

        node.set_reflex_override(override_addr);

        // Classifier gave up (all probes failed); it would
        // still store `Unknown` without the guard.
        node.commit_reclassify_observations(NatClass::Unknown, None, 0);

        assert_eq!(
            node.nat_class(),
            NatClass::Open,
            "`nat_class` was overwritten with Unknown even though \
             `latest_reflex` was None — demonstrates the second \
             half of the bug that the bare `if let Some` would've \
             missed",
        );
        assert_eq!(node.reflex_addr(), Some(override_addr));
    }

    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #4: when every
    /// probe in a sweep failed (`latest_reflex == None`) and the
    /// override is INACTIVE, the commit must skip both stores
    /// rather than writing `nat_class` (typically `Unknown`) over
    /// the previously-published class while leaving the previous
    /// `reflex_addr` in place — that pair is torn from the
    /// `traversal_publish_mu` reader's perspective. Match the
    /// deadline-expired branch in `reclassify_nat`: treat
    /// "no observations this sweep" as transient and keep the
    /// previously-published pair coherent.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn commit_skips_both_stores_when_no_observation_and_no_override() {
        let node = build_node_for_test().await;
        let probed: SocketAddr = "198.51.100.9:4242".parse().unwrap();

        // Seed a coherent (Cone, Some(probed)) pair via the same
        // commit path; no override is installed so this must apply.
        node.commit_reclassify_observations(NatClass::Cone, Some(probed), 2);
        assert_eq!(node.nat_class(), NatClass::Cone);
        assert_eq!(node.reflex_addr(), Some(probed));

        // Simulate the next sweep where every probe failed.
        // Pre-fix this would have stored `Unknown` over `Cone`
        // while keeping `Some(probed)` as the reflex — torn pair.
        // Post-fix the function returns early and both fields
        // remain untouched.
        node.commit_reclassify_observations(NatClass::Unknown, None, 0);

        assert_eq!(
            node.nat_class(),
            NatClass::Cone,
            "no-observation sweep flapped nat_class from Cone to \
             Unknown; pre-fix the store landed unconditionally even \
             though the paired reflex store was gated by Some",
        );
        assert_eq!(
            node.reflex_addr(),
            Some(probed),
            "reflex_addr was not torn (good) but nat_class was \
             rewritten — the pair an `announce_capabilities_with` \
             reader sees under traversal_publish_mu becomes \
             (fresh class, stale reflex) which violates the mutex's \
             coherent-snapshot invariant",
        );
    }

    /// Finding B2 (code review 2026-06-21, port-scanning): a sweep
    /// that collected fewer than two observations must NOT publish.
    /// `classify` returns `Unknown` below 2 observations, and
    /// committing that would flap a previously-good class down to
    /// Unknown on nothing more than transient packet loss (one of the
    /// two probes dropped). The commit must keep the prior
    /// (class, reflex) pair.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn commit_keeps_prior_class_on_single_observation_sweep() {
        let node = build_node_for_test().await;
        let probed: SocketAddr = "198.51.100.9:4242".parse().unwrap();

        // Seed a coherent two-observation result.
        node.commit_reclassify_observations(NatClass::Cone, Some(probed), 2);
        assert_eq!(node.nat_class(), NatClass::Cone);
        assert_eq!(node.reflex_addr(), Some(probed));

        // Next sweep gets only ONE probe response → classify() yields
        // Unknown for <2 observations. Pre-fix this stored
        // (Unknown, single); post-fix the prior pair is kept.
        let single: SocketAddr = "198.51.100.10:4243".parse().unwrap();
        node.commit_reclassify_observations(NatClass::Unknown, Some(single), 1);

        assert_eq!(
            node.nat_class(),
            NatClass::Cone,
            "a single-observation sweep must not downgrade a good class to Unknown",
        );
        assert_eq!(
            node.reflex_addr(),
            Some(probed),
            "a single-observation sweep must not overwrite the published reflex",
        );
    }

    /// Finding B2 follow-up (code review 2026-06-21, port-scanning):
    /// the no-reflex guard in `commit_reclassify_observations` is
    /// subsumed by the <2-observation guard for every coherent
    /// `reclassify_nat` input (0 observations ⟹ caught by the count
    /// guard; ≥2 observations ⟹ a reflex was threaded). It is retained
    /// purely as defense-in-depth against a *torn* input — a commit
    /// claiming ≥2 observations yet carrying no reflex. Such an input
    /// must still keep the prior (class, reflex) pair rather than
    /// publish a class with no paired reflex.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn commit_keeps_prior_on_torn_class_without_reflex() {
        let node = build_node_for_test().await;
        let probed: SocketAddr = "198.51.100.9:4242".parse().unwrap();

        // Seed a coherent two-observation result.
        node.commit_reclassify_observations(NatClass::Cone, Some(probed), 2);
        assert_eq!(node.nat_class(), NatClass::Cone);
        assert_eq!(node.reflex_addr(), Some(probed));

        // Torn input: claims 2 observations (so the <2 guard does NOT
        // fire) but carries no reflex. The no-reflex guard must catch
        // it and keep the prior pair.
        node.commit_reclassify_observations(NatClass::Open, None, 2);

        assert_eq!(
            node.nat_class(),
            NatClass::Cone,
            "a torn (class, None) commit must not publish a class without a reflex",
        );
        assert_eq!(
            node.reflex_addr(),
            Some(probed),
            "a torn (class, None) commit must leave the published reflex intact",
        );
    }

    /// After `clear_reflex_override` is called, the classifier
    /// regains write access. Without this, the fix would
    /// permanently freeze classification once any override had
    /// ever been installed.
    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn commit_resumes_after_override_cleared() {
        let node = build_node_for_test().await;
        let override_addr: SocketAddr = "203.0.113.77:9999".parse().unwrap();
        let probed: SocketAddr = "198.51.100.9:4242".parse().unwrap();

        node.set_reflex_override(override_addr);
        node.clear_reflex_override();

        node.commit_reclassify_observations(NatClass::Cone, Some(probed), 2);

        assert_eq!(node.nat_class(), NatClass::Cone);
        assert_eq!(node.reflex_addr(), Some(probed));
    }
}

#[cfg(test)]
mod fold_publisher_helpers_tests {
    //! Per-fold publisher convenience helpers — confirm the
    //! per-`(kind, class)` generation counter advances
    //! monotonically and shards correctly. The actual sign +
    //! broadcast pipeline is exercised by the existing
    //! `behavior::fold::tests` end-to-end pin
    //! (`publisher_to_receiver_full_pipeline_in_process`); this
    //! module pins the publisher-side counter logic that the
    //! helpers compose with that pipeline.

    use super::*;
    use std::net::SocketAddr;

    async fn build_node_for_test() -> Arc<MeshNode> {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x42u8; 32]);
        Arc::new(
            MeshNode::new(EntityKeypair::generate(), cfg)
                .await
                .expect("MeshNode::new"),
        )
    }

    #[tokio::test]
    async fn next_fold_generation_first_call_returns_one() {
        // Wire format reserves gen=0 as the "uninitialized"
        // sentinel; the helper's pre-increment shape ensures
        // the first emitted announcement is always gen=1.
        let node = build_node_for_test().await;
        assert_eq!(node.next_fold_generation(0x0F00, 0xAA), 1);
    }

    #[tokio::test]
    async fn next_fold_generation_advances_monotonically_per_class() {
        let node = build_node_for_test().await;
        let class = 0xBEEF;
        let kind = 0x0F00;
        let mut last = 0;
        for _ in 0..8 {
            let g = node.next_fold_generation(kind, class);
            assert!(
                g > last,
                "generation must be strictly monotonic per (kind, class)"
            );
            last = g;
        }
        assert_eq!(last, 8, "8 calls → gens 1..=8");
    }

    #[tokio::test]
    async fn next_fold_generation_shards_per_kind_and_class() {
        // Independent (kind, class) slots have independent
        // counters — gen=1 for (kind_A, class_X) doesn't
        // affect (kind_A, class_Y) or (kind_B, class_X).
        let node = build_node_for_test().await;
        let g_a_x = node.next_fold_generation(0x0F00, 0xAA);
        let g_a_y = node.next_fold_generation(0x0F00, 0xBB);
        let g_b_x = node.next_fold_generation(0x0F01, 0xAA);
        assert_eq!(g_a_x, 1);
        assert_eq!(g_a_y, 1);
        assert_eq!(g_b_x, 1);

        // Second call on (kind_A, class_X) advances independently
        // of the other slots, which stay at their last value.
        let g_a_x_2 = node.next_fold_generation(0x0F00, 0xAA);
        assert_eq!(g_a_x_2, 2);
        // Other slots advance to 2 only when we ask them to.
        assert_eq!(node.next_fold_generation(0x0F00, 0xBB), 2);
        assert_eq!(node.next_fold_generation(0x0F01, 0xAA), 2);
    }

    #[tokio::test]
    async fn publish_capability_membership_signs_with_node_identity() {
        // The publisher helper must sign with the local node's
        // identity. Roundtrip-verify by hand: capture the
        // identity, replicate the sign step independently, and
        // confirm the helper's signature would verify against
        // it. We can't fully exercise broadcast here (no peers),
        // but we CAN confirm the helper composes correctly with
        // `next_fold_generation` and produces a well-formed
        // envelope on the broadcast path.
        let node = build_node_for_test().await;
        // No peers connected → broadcast returns 0 sent without
        // failure. The relevant pin: the helper doesn't panic
        // and produces a result.
        let result = node
            .publish_capability_membership(super::super::behavior::fold::CapabilityMembership {
                class_hash: 0x1000,
                tags: vec!["gpu".into()],
                hardware: None,
                state: super::super::behavior::fold::NodeState::Idle,
                region: Some("us-east".into()),
                price_quote: None,
                reflex_addr: None,
                allowed_nodes: Vec::new(),
                allowed_subnets: Vec::new(),
                allowed_groups: Vec::new(),
                metadata: std::collections::BTreeMap::new(),
            })
            .await;
        assert!(result.is_ok());
        assert_eq!(result.unwrap(), 0, "no peers → 0 sent");

        // The generation counter advanced for (CapabilityFold,
        // 0x1000) — pinning that the helper threaded through
        // next_fold_generation correctly.
        let next = node.next_fold_generation(
            <super::super::behavior::fold::CapabilityFold as super::super::behavior::fold::FoldKind>::KIND_ID,
            0x1000,
        );
        assert_eq!(
            next, 2,
            "first publish used gen=1, next_fold_generation returns gen=2"
        );
    }

    #[tokio::test]
    async fn fold_generation_gc_evicts_stale_slots_keeps_recent() {
        // GC behavior: an entry whose last_touched_us is older
        // than FOLD_GENERATION_GC_MAX_AGE is removed; recently-
        // touched slots survive. We drive the sweep inline by
        // calling the same retain closure the background task
        // uses, so the test stays fast and deterministic without
        // spinning the 5-minute interval.
        let node = build_node_for_test().await;
        let kind = 0x0F00u16;
        let stale_class = 0xAAAA_u64;
        let fresh_class = 0xBBBB_u64;

        // Stale entry: stamp last_touched far in the past.
        node.next_fold_generation(kind, stale_class);
        node.fold_generations
            .get(&(kind, stale_class))
            .expect("stale entry exists")
            .last_touched_us
            .store(0, Ordering::Relaxed);

        // Fresh entry: just stamped, last_touched ≈ now.
        node.next_fold_generation(kind, fresh_class);

        // Run the same retain the background loop would on tick.
        let cutoff_us = crate::adapter::net::current_timestamp_micros()
            .saturating_sub(FOLD_GENERATION_GC_MAX_AGE.as_micros() as u64);
        node.fold_generations
            .retain(|_, e| e.last_touched_us.load(Ordering::Relaxed) >= cutoff_us);

        assert!(
            !node.fold_generations.contains_key(&(kind, stale_class)),
            "stale slot evicted"
        );
        assert!(
            node.fold_generations.contains_key(&(kind, fresh_class)),
            "fresh slot survives"
        );
    }

    #[tokio::test]
    async fn origin_hash_index_first_write_wins_on_adversarial_collision() {
        // Post-`WIRE_ORIGIN_HASH_64BIT` policy: `origin_hash_to_node`
        // uses first-write-wins. Two distinct node_ids claiming the
        // same u64 origin_hash (~2^32 adversarial work to engineer)
        // resolve to whichever was inserted first; the second
        // claimant cannot displace the established slot.
        //
        // Pre-cutover the slot promoted to `Multiple` and lookups
        // returned `None` for the ambiguous case — that branch is
        // gone with the truncation it was designed to handle.
        let node = build_node_for_test().await;
        let hash = 0xCAFE_BABE_DEAD_BEEF_u64;
        let first = 0xAAAA_u64;
        let second = 0xBBBB_u64;

        // Empty slot.
        assert_eq!(node.get_node_by_origin_hash(hash), None);

        // First claimant lands.
        node.origin_hash_to_node.entry(hash).or_insert(first);
        assert_eq!(node.get_node_by_origin_hash(hash), Some(first));

        // Second adversarial claimant — `or_insert` is a no-op
        // because the entry already exists.
        node.origin_hash_to_node.entry(hash).or_insert(second);
        assert_eq!(
            node.get_node_by_origin_hash(hash),
            Some(first),
            "first-write-wins must not be displaced by an adversarial grind"
        );

        // Removal via `remove_if` only drops when the predicate
        // matches the current claimant — mirrors what the
        // failure-detector eviction does.
        node.origin_hash_to_node
            .remove_if(&hash, |_, claimant| *claimant == second);
        assert_eq!(
            node.get_node_by_origin_hash(hash),
            Some(first),
            "remove_if on non-claimant is a no-op"
        );
        node.origin_hash_to_node
            .remove_if(&hash, |_, claimant| *claimant == first);
        assert_eq!(
            node.get_node_by_origin_hash(hash),
            None,
            "remove_if on the current claimant clears the slot"
        );
    }

    #[tokio::test]
    async fn origin_hash_index_distinguishes_low32_collisions() {
        // Regression for the original cutover motivation: pre-
        // `WIRE_ORIGIN_HASH_64BIT` the slot keyed on the truncated
        // u32 form, so two `EntityId`s whose low 32 bits collided
        // but whose full u64 hashes differed would conflict on the
        // wire. Post-cutover the index keys on the full u64, so the
        // two publishers occupy distinct slots and both lookups
        // succeed.
        let node = build_node_for_test().await;
        let low_common: u32 = 0xDEAD_BEEF;
        let hash_a: u64 = low_common as u64;
        let hash_b: u64 = (0x4242_4242_u64 << 32) | (low_common as u64);
        assert_eq!(hash_a as u32, hash_b as u32);
        assert_ne!(hash_a, hash_b);

        node.origin_hash_to_node.insert(hash_a, 0xAAAA);
        node.origin_hash_to_node.insert(hash_b, 0xBBBB);

        assert_eq!(node.get_node_by_origin_hash(hash_a), Some(0xAAAA));
        assert_eq!(node.get_node_by_origin_hash(hash_b), Some(0xBBBB));
    }

    #[tokio::test]
    async fn local_subnet_defaults_to_global_without_config_override() {
        // `build_node_for_test` constructs `MeshNodeConfig::new(...)`
        // without `.with_subnet(...)`, so the local subnet must
        // come out as `SubnetId::GLOBAL`. Pins the
        // GLOBAL-as-default contract operator tooling relies on.
        let node = build_node_for_test().await;
        assert_eq!(node.local_subnet(), SubnetId::GLOBAL);
        assert!(node.local_subnet_policy().is_none());
    }

    #[tokio::test]
    async fn gateway_handle_is_none_until_channel_configs_installed() {
        // `set_channel_configs` builds the gateway lazily; nodes
        // without a registry have no gateway and `gateway()`
        // returns `None`. Operator tooling discriminates on this
        // to print "no gateway configured" vs. real stats.
        let node = build_node_for_test().await;
        assert!(node.gateway().is_none());
        // The node we get from `build_node_for_test` is wrapped
        // in an `Arc`, so installing configs requires mutable
        // access via Arc::try_unwrap or unsafe. Cover the
        // None-then-Some transition via a fresh node we own.
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x17u8; 32]);
        let mut owned = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");
        assert!(owned.gateway().is_none());
        owned.set_channel_configs(std::sync::Arc::new(
            crate::adapter::net::ChannelConfigRegistry::new(),
        ));
        let gw = owned.gateway().expect("gateway installed");
        assert_eq!(gw.local_subnet(), SubnetId::GLOBAL);
        assert_eq!(gw.forwarded_count(), 0);
        assert_eq!(gw.dropped_count(), 0);
    }

    #[tokio::test]
    async fn failed_peer_eviction_drops_retained_subscribe_chains() {
        // A peer that fails (heartbeat timeout) never sends an
        // unsubscribe, and the periodic sweep can't reach its retained
        // chain once `peer_entity_ids` is cleared — so the
        // failure-detector callback must drop it directly, scoped to the
        // failed node and nothing else.
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg =
            MeshNodeConfig::new(addr, [0x17u8; 32]).with_session_timeout(Duration::from_millis(1));
        let node = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");

        let dead: u64 = 0xDEAD;
        let live: u64 = 0xBEEF;
        let channel_hash: ChannelHash = 0x1234;

        let issuer = EntityKeypair::generate();
        let subject = EntityKeypair::generate();
        let chain = TokenChain::single(PermissionToken::issue(
            &issuer,
            subject.entity_id().clone(),
            TokenScope::SUBSCRIBE,
            channel_hash,
            3600,
            0,
        ));
        node.subscriber_chains
            .insert((dead, channel_hash), RetainedChain::new(chain.clone()));
        node.subscriber_chains
            .insert((live, channel_hash), RetainedChain::new(chain));
        assert_eq!(node.subscriber_chains.len(), 2);

        node.failure_detector.heartbeat(dead, addr);
        node.failure_detector.heartbeat(live, addr);

        // Age `dead`'s heartbeat well past `miss_threshold × timeout`,
        // then refresh `live` so only `dead` trips.
        tokio::time::sleep(Duration::from_millis(20)).await;
        node.failure_detector.heartbeat(live, addr);

        let failed = node.failure_detector.check_all();
        assert!(failed.contains(&dead), "dead peer must be detected failed");

        assert!(
            node.subscriber_chains.get(&(live, channel_hash)).is_some(),
            "live peer's retained chain must survive"
        );
        assert!(
            node.subscriber_chains.get(&(dead, channel_hash)).is_none(),
            "failed peer's retained chain must be evicted"
        );
    }

    #[tokio::test]
    async fn delegated_publish_chain_authorizes_publish() {
        use crate::adapter::net::{ChannelConfig, ChannelConfigRegistry, ChannelId, ChannelName};

        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x17u8; 32]);
        let mut node = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");

        // Channel rooted at `owner`; the publishing node is NOT a root.
        let owner = EntityKeypair::generate();
        let mid = EntityKeypair::generate();
        let channel = ChannelName::new("fleet/telemetry").unwrap();
        let registry = ChannelConfigRegistry::new();
        registry.insert(
            ChannelConfig::new(ChannelId::new(channel.clone()))
                .with_token_roots(vec![owner.entity_id().clone()]),
        );
        node.set_channel_configs(Arc::new(registry));

        // Delegated PUBLISH chain: owner -> mid -> this node. The node's
        // own leaf token is issued by `mid` (a delegator), not a channel
        // root, so a single-link chain from it can't anchor.
        let root = PermissionToken::issue(
            &owner,
            mid.entity_id().clone(),
            TokenScope::PUBLISH.union(TokenScope::DELEGATE),
            channel.hash(),
            3600,
            2,
        );
        let leaf = root
            .delegate(&mid, node.entity_id().clone(), TokenScope::PUBLISH)
            .expect("delegation should succeed");
        let chain = TokenChain {
            tokens: vec![root, leaf],
        };

        let publisher = node.channel_publisher(channel.clone(), PublishConfig::default());

        // Without the held chain the publish-side ACL can only build a
        // single-link chain from the cache, which can't anchor a
        // delegated grant -> publish denied.
        assert!(
            node.publish_many(&publisher, &[Bytes::from_static(b"x")])
                .await
                .is_err(),
            "delegated publisher must be denied until it presents its chain"
        );

        // Install the delegated chain -> publish admitted (no
        // subscribers, so it reports an empty fan-out).
        node.set_publish_chain(&channel, chain);
        let report = node
            .publish_many(&publisher, &[Bytes::from_static(b"x")])
            .await
            .expect("held delegated chain must authorize publish");
        assert_eq!(report.attempted, 0);
    }

    #[cfg(feature = "cortex")]
    #[tokio::test]
    async fn aggregator_registry_is_none_until_installed() {
        // Nodes that don't run aggregators leave the registry
        // empty — CLI verbs short-circuit on this.
        use crate::adapter::net::behavior::aggregator::AggregatorRegistry;
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x17u8; 32]);
        let mut owned = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");
        assert!(owned.aggregator_registry().is_none());
        let registry = std::sync::Arc::new(AggregatorRegistry::new());
        owned.set_aggregator_registry(registry.clone());
        let installed = owned.aggregator_registry().expect("registry installed");
        assert!(std::sync::Arc::ptr_eq(installed, &registry));
        assert!(installed.is_empty());
    }

    #[tokio::test]
    async fn known_subnets_sorted_by_node_id() {
        // Pin the deterministic-order contract `subnet ls` /
        // `subnet tree` operator tools depend on. Build a node,
        // populate `peer_subnets` directly with three out-of-order
        // entries, and assert `known_subnets()` returns them
        // sorted ascending by node_id.
        let node = build_node_for_test().await;
        assert!(node.known_subnets().is_empty());

        node.peer_subnets
            .insert(0xC0FFEE, SubnetId::new(&[3, 7, 2]));
        node.peer_subnets.insert(0xAAAA, SubnetId::new(&[3, 7, 1]));
        node.peer_subnets.insert(0xB0B0, SubnetId::new(&[3, 8]));

        let snapshot = node.known_subnets();
        let ids: Vec<u64> = snapshot.iter().map(|(id, _)| *id).collect();
        assert_eq!(ids, vec![0xAAAA, 0xB0B0, 0xC0FFEE]);
        assert_eq!(snapshot[0].1, SubnetId::new(&[3, 7, 1]));
        assert_eq!(snapshot[1].1, SubnetId::new(&[3, 8]));
        assert_eq!(snapshot[2].1, SubnetId::new(&[3, 7, 2]));
    }

    #[tokio::test]
    async fn capability_fold_is_wired_at_construction() {
        // Sub-step 3B-1 contract: every freshly-built MeshNode
        // owns a CapabilityFold registered with the node's
        // internal FoldRegistry, with the registry installed as
        // the fold channel router. Pins the wiring so callers
        // can rely on `mesh.capability_fold()` returning a
        // queryable handle and the inbound dispatch arm
        // routing SUBPROTOCOL_FOLD envelopes correctly.
        let node = build_node_for_test().await;
        // Fold handle is reachable, queries don't panic.
        assert_eq!(node.capability_fold().stats().entries, 0);
        // Channel router is installed by default.
        assert!(node.has_fold_router());
        // Router exposes the fold's stats — proves the
        // capability fold is registered in the registry that
        // backs the router.
        let stats = node.fold_stats();
        assert!(
            stats.iter().any(|s| {
                s.kind == <super::super::behavior::fold::CapabilityFold
                as super::super::behavior::fold::FoldKind>::KIND_ID
            }),
            "capability fold registered in default router"
        );
    }
}

#[cfg(test)]
mod route_withdrawal_promotion_tests {
    //! RT-5 review Findings 1 & 2: the withdrawal receive path must
    //! not promote an alternate that is (a) a peer the failure
    //! detector considers dead — `peers`/`addr_to_node`/`peer_addrs`
    //! retain Failed peers for transient-partition recovery, so a
    //! naive promotion resurrects an un-displaceable metric-1 route
    //! to a dead peer; (b) a relayed hop, whose recorded address is
    //! the relay's and does not map back to the hop; or (c) any hop
    //! whose address is the withdrawing sender's own, which would
    //! reinstall exactly the route the withdrawal just dropped.
    use super::*;
    use crate::adapter::net::failure::{FailureDetector, FailureDetectorConfig, NodeStatus};
    use std::net::SocketAddr;
    use std::time::Duration;

    fn addr(port: u16) -> SocketAddr {
        format!("127.0.0.1:{port}").parse().unwrap()
    }

    /// A detector whose nodes go Failed after a hair of real time so
    /// the test can drive a specific `NodeStatus` deterministically.
    fn detector() -> FailureDetector {
        FailureDetector::with_config(FailureDetectorConfig {
            timeout: Duration::from_millis(1),
            miss_threshold: 1,
            suspicion_threshold: 1,
            cleanup_interval: Duration::from_secs(60),
        })
    }

    #[test]
    fn healthy_direct_hop_is_promotable() {
        let hop = 0xA1;
        let hop_addr = addr(4001);
        let via_addr = addr(4099);
        let a2n = DashMap::new();
        a2n.insert(hop_addr, hop);
        let fd = detector();
        fd.heartbeat(hop, hop_addr); // Healthy
        assert!(MeshNode::promotable_direct_hop(
            &a2n, &fd, hop, hop_addr, via_addr
        ));
    }

    #[test]
    fn failed_hop_is_not_promotable() {
        // Finding 2: dead-but-retained peer must not be resurrected.
        let hop = 0xA2;
        let hop_addr = addr(4002);
        let via_addr = addr(4099);
        let a2n = DashMap::new();
        a2n.insert(hop_addr, hop);
        let fd = detector();
        fd.heartbeat(hop, hop_addr);
        std::thread::sleep(Duration::from_millis(5));
        assert_eq!(fd.check_all(), vec![hop], "precondition: hop is Failed");
        assert_eq!(fd.status(hop), NodeStatus::Failed);
        assert!(
            !MeshNode::promotable_direct_hop(&a2n, &fd, hop, hop_addr, via_addr),
            "a Failed hop must never be promoted (un-displaceable metric-1 black hole)"
        );
    }

    #[test]
    fn relayed_hop_is_not_promotable() {
        // Finding 1: a relayed hop's recorded addr is the relay's and
        // does not map back to the hop in addr_to_node.
        let hop = 0xA3;
        let relay_addr = addr(4003);
        let via_addr = addr(4099);
        let a2n = DashMap::new();
        // relay_addr maps to some OTHER node (the relay), not `hop`.
        a2n.insert(relay_addr, 0xBEEF);
        let fd = detector();
        fd.heartbeat(hop, relay_addr); // hop itself is Healthy
        assert!(
            !MeshNode::promotable_direct_hop(&a2n, &fd, hop, relay_addr, via_addr),
            "a relayed hop (addr maps to the relay, not the hop) must not be promoted"
        );
    }

    #[test]
    fn hop_at_the_withdrawing_addr_is_not_promotable() {
        // Finding 1: never reinstall through the withdrawing sender's
        // own address — that is the route we just dropped.
        let hop = 0xA4;
        let via_addr = addr(4004);
        let a2n = DashMap::new();
        a2n.insert(via_addr, hop);
        let fd = detector();
        fd.heartbeat(hop, via_addr);
        assert!(
            !MeshNode::promotable_direct_hop(&a2n, &fd, hop, via_addr, via_addr),
            "promoting the withdrawing sender's own address reinstalls the dropped route"
        );
    }
}

#[cfg(test)]
mod heartbeat_aead_tests {
    //! Regression for BUG_AUDIT_2026_04_30_CORE.md #85: the mesh
    //! dispatch loop's heartbeat fast-path used to skip AEAD
    //! verification, letting an off-path attacker who observed the
    //! cleartext `session_id` and source UDP address spoof
    //! heartbeats indefinitely. The fix routes through
    //! [`NetSession::verify_and_touch_heartbeat`] before calling
    //! `failure_detector.heartbeat`. The verify+touch are now fused
    //! into the session method so a future caller can't reorder
    //! them or forget to touch on success. These tests pin both
    //! the AEAD-verify outcome AND the touch-on-success/no-touch-
    //! on-failure invariant at the same coverage bar the legacy
    //! single-peer adapter has at
    //! `mod.rs::heartbeat_is_aead_authenticated`.
    use super::*;
    use crate::adapter::net::crypto::{NoiseHandshake, StaticKeypair};
    use crate::adapter::net::pool::PacketBuilder;
    use crate::adapter::net::protocol::{NetHeader, PacketFlags};

    /// Extract the TX counter (bytes 16..24, little-endian u64) from
    /// a serialized packet's header. Both data packets and
    /// heartbeats patch the counter into the same wire-format
    /// position; see `pool.rs::PacketBuilder::build` lines
    /// `header_bytes[16..24].copy_from_slice(&counter.to_le_bytes())`
    /// and the matching line in `build_heartbeat`.
    fn counter_of(packet: &[u8]) -> u64 {
        u64::from_le_bytes(
            packet[16..24]
                .try_into()
                .expect("packet header is at least 24 bytes"),
        )
    }

    fn make_session_keys() -> (
        crate::adapter::net::crypto::SessionKeys,
        crate::adapter::net::crypto::SessionKeys,
    ) {
        let psk = [0x42u8; 32];
        let responder_kp = StaticKeypair::generate();
        let mut initiator = NoiseHandshake::initiator(&psk, &responder_kp.public).unwrap();
        let mut responder = NoiseHandshake::responder(&psk, &responder_kp).unwrap();
        let msg1 = initiator.write_message(&[]).unwrap();
        responder.read_message(&msg1).unwrap();
        let msg2 = responder.write_message(&[]).unwrap();
        initiator.read_message(&msg2).unwrap();
        (
            initiator.into_session_keys().unwrap(),
            responder.into_session_keys().unwrap(),
        )
    }

    #[test]
    fn aead_authenticated_heartbeat_passes_verification_and_touches_session() {
        let (init_keys, resp_keys) = make_session_keys();
        let resp_session = NetSession::new(resp_keys, "127.0.0.1:5000".parse().unwrap(), 4, false);
        let mut builder = PacketBuilder::new(&init_keys.tx_key, init_keys.session_id);
        let bytes = builder.build_heartbeat();

        let parsed = ParsedPacket::parse(bytes, "127.0.0.1:5000".parse().unwrap())
            .expect("legitimate heartbeat must parse");
        assert!(parsed.header.flags.is_heartbeat());

        let last_before = resp_session.last_activity_ns();
        // Sleep so `current_timestamp()` ticks observably forward
        // before `verify_and_touch_heartbeat` reads it.
        std::thread::sleep(std::time::Duration::from_millis(2));

        assert!(
            resp_session.verify_and_touch_heartbeat(&parsed),
            "AEAD-authenticated heartbeat must verify against the matched session"
        );
        assert!(
            resp_session.last_activity_ns() > last_before,
            "successful verify must touch the session — verify+touch are fused"
        );
    }

    #[test]
    fn unauthenticated_heartbeat_fails_verification_and_does_not_touch() {
        let (_init_keys, resp_keys) = make_session_keys();
        let resp_session = NetSession::new(resp_keys, "127.0.0.1:5000".parse().unwrap(), 4, false);

        // Attacker forges a heartbeat header with the right
        // session_id but garbage 16-byte tail. Pre-fix this passed
        // through; post-fix it must fail.
        let mut forged = bytes::BytesMut::new();
        let mut header_bytes = NetHeader::heartbeat(resp_session.session_id()).to_bytes();
        // Stamp a plausible nonce so the receiver gets to decrypt
        // (otherwise it bails earlier on the counter check).
        header_bytes[12..16].copy_from_slice(&[0u8; 4]);
        header_bytes[16..24].copy_from_slice(&1u64.to_le_bytes());
        forged.extend_from_slice(&header_bytes);
        forged.extend_from_slice(&[0xAAu8; 16]); // garbage tag
        let parsed = ParsedPacket::parse(forged.freeze(), "127.0.0.1:5000".parse().unwrap())
            .expect("forged heartbeat must still parse — verification is downstream");
        assert!(parsed.header.flags.is_heartbeat());

        let last_before = resp_session.last_activity_ns();
        std::thread::sleep(std::time::Duration::from_millis(2));

        assert!(
            !resp_session.verify_and_touch_heartbeat(&parsed),
            "heartbeat with garbage AEAD tag must NOT verify — pre-fix the \
             mesh dispatcher would have called session.touch() / \
             failure_detector.heartbeat() unconditionally"
        );
        assert_eq!(
            resp_session.last_activity_ns(),
            last_before,
            "failed verify must NOT touch the session — verify+touch are fused"
        );
    }

    /// Regression for BUG_AUDIT_2026_04_30_CORE.md #87: dropping
    /// a `PeerRegistrationGuard` whose `completed` flag is still
    /// `false` (cancellation, panic, or non-success path) must
    /// run the same rollback the legacy inline error arm did —
    /// remove the peer entry, peer-addr mapping, and routing
    /// table entry, but only if those entries still match the
    /// values this handshake wrote (a concurrent retry may have
    /// replaced them).
    #[tokio::test]
    async fn peer_registration_guard_rolls_back_on_drop_when_not_completed() {
        let peer_id = 0xDEAD_BEEFu64;
        let next_hop: SocketAddr = "10.0.0.1:9000".parse().unwrap();

        let peers: Arc<DashMap<u64, PeerInfo>> = Arc::new(DashMap::new());
        let peer_addrs: Arc<DashMap<u64, SocketAddr>> = Arc::new(DashMap::new());
        let router = Arc::new(
            NetRouter::new(crate::adapter::net::router::RouterConfig::new(
                0xCAFE_BABE,
                "127.0.0.1:0".parse().unwrap(),
            ))
            .await
            .unwrap(),
        );

        // Simulate the post-handshake registration: insert peer,
        // peer-addr, and a route. We can't construct a fully-
        // populated `PeerInfo` without the matched session keys,
        // but the rollback only inspects `pi.addr`, so we build
        // a minimal session and check post-Drop that the entry
        // is gone.
        let (init_keys, _resp_keys) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, next_hop, 4, false));
        let registered_session_id = session.session_id();
        let session_id_to_node: Arc<DashMap<u64, u64>> = Arc::new(DashMap::new());
        session_id_to_node.insert(registered_session_id, peer_id);
        peers.insert(
            peer_id,
            PeerInfo {
                node_id: peer_id,
                addr: next_hop,
                session,
                remote_static_pub: [0u8; 32],
                last_initiator_ephemeral: None,
            },
        );
        peer_addrs.insert(peer_id, next_hop);
        router.add_route(peer_id, next_hop);

        // Drop guard without committing.
        {
            let _guard = PeerRegistrationGuard {
                peer_node_id: peer_id,
                registered_session_id,
                registered_next_hop: next_hop,
                peers: peers.clone(),
                peer_addrs: peer_addrs.clone(),
                session_id_to_node: session_id_to_node.clone(),
                router: router.clone(),
            };
        } // Drop runs here.

        assert!(
            !peers.contains_key(&peer_id),
            "peers entry must be removed by Drop rollback"
        );
        assert!(
            !peer_addrs.contains_key(&peer_id),
            "peer_addrs entry must be removed by Drop rollback"
        );
        assert!(
            !session_id_to_node.contains_key(&registered_session_id),
            "session_id_to_node entry must be removed by Drop rollback (PERF_AUDIT §2.4)"
        );
        assert!(
            router.routing_table().lookup(peer_id).is_none(),
            "route must be removed by Drop rollback"
        );
    }

    #[tokio::test]
    async fn peer_registration_guard_is_no_op_on_drop_when_completed() {
        let peer_id = 0xCAFE_F00Du64;
        let next_hop: SocketAddr = "10.0.0.2:9000".parse().unwrap();

        let peers: Arc<DashMap<u64, PeerInfo>> = Arc::new(DashMap::new());
        let peer_addrs: Arc<DashMap<u64, SocketAddr>> = Arc::new(DashMap::new());
        let router = Arc::new(
            NetRouter::new(crate::adapter::net::router::RouterConfig::new(
                0xCAFE_BABE,
                "127.0.0.1:0".parse().unwrap(),
            ))
            .await
            .unwrap(),
        );

        let (init_keys, _resp_keys) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, next_hop, 4, false));
        let registered_session_id = session.session_id();
        let session_id_to_node: Arc<DashMap<u64, u64>> = Arc::new(DashMap::new());
        session_id_to_node.insert(registered_session_id, peer_id);
        peers.insert(
            peer_id,
            PeerInfo {
                node_id: peer_id,
                addr: next_hop,
                session,
                remote_static_pub: [0u8; 32],
                last_initiator_ephemeral: None,
            },
        );
        peer_addrs.insert(peer_id, next_hop);
        router.add_route(peer_id, next_hop);

        {
            let guard = PeerRegistrationGuard {
                peer_node_id: peer_id,
                registered_session_id,
                registered_next_hop: next_hop,
                peers: peers.clone(),
                peer_addrs: peer_addrs.clone(),
                session_id_to_node: session_id_to_node.clone(),
                router: router.clone(),
            };
            // Successful-send path consumes the guard without
            // running Drop's rollback.
            guard.commit();
        }

        assert!(peers.contains_key(&peer_id));
        assert!(peer_addrs.contains_key(&peer_id));
        assert!(
            session_id_to_node.contains_key(&registered_session_id),
            "commit() must preserve session_id_to_node alongside the other maps"
        );
        assert!(router.routing_table().lookup(peer_id).is_some());
    }

    /// Regression: if a concurrent retry has overwritten the
    /// peer-addr / route to a different next-hop, the guard's
    /// rollback must NOT clobber the newer (valid) registration.
    /// Mirrors the `remove_if`/`remove_route_if_next_hop_is`
    /// guarantees from the original inline rollback.
    #[tokio::test]
    async fn peer_registration_guard_preserves_concurrent_overwrite() {
        let peer_id = 0xFACE_F00Du64;
        let stale: SocketAddr = "10.0.0.3:9000".parse().unwrap();
        let fresh: SocketAddr = "10.0.0.4:9000".parse().unwrap();

        let peers: Arc<DashMap<u64, PeerInfo>> = Arc::new(DashMap::new());
        let peer_addrs: Arc<DashMap<u64, SocketAddr>> = Arc::new(DashMap::new());
        let router = Arc::new(
            NetRouter::new(crate::adapter::net::router::RouterConfig::new(
                0xCAFE_BABE,
                "127.0.0.1:0".parse().unwrap(),
            ))
            .await
            .unwrap(),
        );

        let (init_keys, _resp_keys) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, fresh, 4, false));
        let fresh_session_id = session.session_id();
        // The stale guard carries a DIFFERENT session_id — the
        // simulated concurrent retry installed a fresh session under
        // the same peer_node_id with a new session_id. The rollback
        // must not touch the fresh entry under the reverse index.
        let stale_session_id = fresh_session_id.wrapping_add(0xDEAD_BEEF);
        let session_id_to_node: Arc<DashMap<u64, u64>> = Arc::new(DashMap::new());
        session_id_to_node.insert(fresh_session_id, peer_id);
        // Concurrent retry has overwritten with `fresh` — the
        // stale guard about to drop should NOT remove this.
        peers.insert(
            peer_id,
            PeerInfo {
                node_id: peer_id,
                addr: fresh,
                session,
                remote_static_pub: [0u8; 32],
                last_initiator_ephemeral: None,
            },
        );
        peer_addrs.insert(peer_id, fresh);
        router.add_route(peer_id, fresh);

        {
            let _guard = PeerRegistrationGuard {
                peer_node_id: peer_id,
                registered_session_id: stale_session_id, // NOT the live session_id
                registered_next_hop: stale,              // NOT what's currently in the maps
                peers: peers.clone(),
                peer_addrs: peer_addrs.clone(),
                session_id_to_node: session_id_to_node.clone(),
                router: router.clone(),
            };
        }

        assert!(
            peers.contains_key(&peer_id),
            "peers must keep the fresh (concurrent-retry) entry"
        );
        assert_eq!(*peer_addrs.get(&peer_id).unwrap(), fresh);
        assert!(
            session_id_to_node.contains_key(&fresh_session_id),
            "session_id_to_node must keep the fresh entry — the stale guard's session_id \
             differs, so remove_if leaves the live entry alone"
        );
        assert_eq!(router.routing_table().lookup(peer_id), Some(fresh));
    }

    /// PERF_AUDIT §2.4 regression: the routed-local dispatch
    /// lookup must resolve via the `session_id → node_id` reverse
    /// index AND defensively re-check that the resolved peer's
    /// session_id still matches. A stale reverse-index entry (peer
    /// re-handshaken under the same node_id with a new session_id,
    /// reverse-index update racing with the inbound packet) would
    /// otherwise route the old packet to the wrong session.
    ///
    /// This pins the helper closure logic that lives in
    /// `dispatch_packet`'s routed branch:
    ///
    /// ```ignore
    /// session_id_to_node.get(session_id)
    ///     .and_then(|nid| peers.get(nid).map(|e| (nid, e.session.clone())))
    ///     .filter(|(_, sess)| sess.session_id() == session_id)
    /// ```
    ///
    /// Without the `.filter`, the second test case below would
    /// resolve to the FRESH session despite the inbound packet
    /// carrying the OLD session_id, and the receiver would AEAD-
    /// verify against the wrong key.
    #[tokio::test]
    async fn routed_dispatch_lookup_filters_session_id_mismatch() {
        let peer_id = 0xBEEF_CAFEu64;
        let peer_addr: SocketAddr = "10.1.1.1:9000".parse().unwrap();

        let peers: Arc<DashMap<u64, PeerInfo>> = Arc::new(DashMap::new());
        let session_id_to_node: Arc<DashMap<u64, u64>> = Arc::new(DashMap::new());

        let (init_keys, _resp_keys) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, peer_addr, 4, false));
        let live_session_id = session.session_id();
        peers.insert(
            peer_id,
            PeerInfo {
                node_id: peer_id,
                addr: peer_addr,
                session,
                remote_static_pub: [0u8; 32],
                last_initiator_ephemeral: None,
            },
        );
        session_id_to_node.insert(live_session_id, peer_id);

        // Case 1 — the happy path: an inbound packet carrying the
        // live session_id resolves to (peer_id, session) directly.
        let resolved = session_id_to_node
            .get(&live_session_id)
            .map(|e| *e.value())
            .and_then(|nid| peers.get(&nid).map(|e| (nid, e.value().session.clone())))
            .filter(|(_, s)| s.session_id() == live_session_id);
        assert!(
            resolved.is_some(),
            "fresh inbound for the live session_id must resolve via the reverse index"
        );
        let (resolved_node, resolved_session) = resolved.unwrap();
        assert_eq!(resolved_node, peer_id);
        assert_eq!(resolved_session.session_id(), live_session_id);

        // Case 2 — stale reverse-index entry: the peer was
        // re-handshaken under the same node_id and the live
        // session_id changed. An inbound packet carrying the OLD
        // session_id must NOT be routed to the live session (the
        // AEAD key would be wrong). The `.filter` clause is what
        // catches this — without it, the lookup would happily
        // resolve to the new session by node_id.
        let old_session_id = live_session_id.wrapping_add(1);
        session_id_to_node.insert(old_session_id, peer_id);
        let stale = session_id_to_node
            .get(&old_session_id)
            .map(|e| *e.value())
            .and_then(|nid| peers.get(&nid).map(|e| (nid, e.value().session.clone())))
            .filter(|(_, s)| s.session_id() == old_session_id);
        assert!(
            stale.is_none(),
            "stale reverse-index entry must NOT resolve to the live session — \
             the .filter() guard preserves the pre-fix `peers.iter().find(matching session_id)` \
             semantic that returned None in the same scenario"
        );
    }

    /// PERF_AUDIT §2.4 regression: a peer re-handshake replaces
    /// the `PeerInfo` under the same node_id with a fresh session
    /// (new session_id). The reverse index must evict the
    /// displaced session_id's entry alongside installing the new
    /// one — otherwise every re-handshake leaks one stale entry
    /// forever (the `.filter` guard in dispatch makes stale
    /// entries harmless for routing, but the map grows without
    /// bound across rotations).
    #[tokio::test]
    async fn install_peer_replacement_evicts_displaced_reverse_index_entry() {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x2Au8; 32]);
        let node = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");

        let peer_id = 0xFEED_F00Du64;
        let peer_addr: SocketAddr = "10.2.2.2:9100".parse().unwrap();

        let (first_keys, _) = make_session_keys();
        let first_session_id = first_keys.session_id;
        node.install_peer(
            peer_id,
            peer_addr,
            first_keys,
            AddrInstallMode::DirectOverwrite,
        );
        assert_eq!(
            node.session_id_to_node.get(&first_session_id).map(|e| *e),
            Some(peer_id),
            "first install must populate the reverse index"
        );

        // Re-handshake: fresh keys → fresh session_id under the
        // SAME node_id.
        let (second_keys, _) = make_session_keys();
        let second_session_id = second_keys.session_id;
        assert_ne!(
            first_session_id, second_session_id,
            "fresh handshake must derive a distinct session_id"
        );
        node.install_peer(
            peer_id,
            peer_addr,
            second_keys,
            AddrInstallMode::DirectOverwrite,
        );

        assert_eq!(
            node.session_id_to_node.get(&second_session_id).map(|e| *e),
            Some(peer_id),
            "replacement install must index the fresh session_id"
        );
        assert!(
            !node.session_id_to_node.contains_key(&first_session_id),
            "displaced session_id must be evicted from the reverse index — \
             leaving it would leak one entry per re-handshake"
        );
        assert_eq!(
            node.session_id_to_node.len(),
            1,
            "exactly one reverse-index entry per live peer session"
        );
    }

    /// Direct-path upgrade C2: `install_peer_cas` refuses to overwrite
    /// when the peer's current session_id no longer matches the one
    /// the upgrade observed — a racing handshake won, and clobbering it
    /// is exactly the F5 nondeterminism the CAS removes. The working
    /// session is left intact.
    #[tokio::test]
    async fn install_peer_cas_refuses_on_session_id_mismatch() {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x2Cu8; 32]);
        let node = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");

        let peer_id = 0xAB_CD_EF_01u64;
        let relay_addr: SocketAddr = "10.9.9.9:9100".parse().unwrap();
        let (relay_keys, _) = make_session_keys();
        let relay_session_id = relay_keys.session_id;
        node.install_peer(
            peer_id,
            relay_addr,
            relay_keys,
            AddrInstallMode::RoutedPreserve,
        );

        // A racing rotation installs a DIFFERENT session for the peer
        // (simulated by a plain install). The upgrade below still holds
        // the OLD session_id as its expectation.
        let (raced_keys, _) = make_session_keys();
        let raced_session_id = raced_keys.session_id;
        node.install_peer(
            peer_id,
            relay_addr,
            raced_keys,
            AddrInstallMode::RoutedPreserve,
        );

        // Upgrade tries to install a punched session but expects the
        // pre-race session_id → CAS must refuse.
        let punched_addr: SocketAddr = "10.1.1.1:7000".parse().unwrap();
        let (punch_keys, _) = make_session_keys();
        let installed = node.install_peer_cas(
            peer_id,
            punched_addr,
            punch_keys,
            AddrInstallMode::DirectOverwrite,
            Some(relay_session_id),
        );
        assert!(!installed, "CAS must refuse when the session_id changed");
        // The raced session survives untouched.
        assert_eq!(
            node.peers
                .get(&peer_id)
                .map(|p| p.value().session.session_id()),
            Some(raced_session_id),
            "the racing session must be left intact after a refused CAS",
        );
        assert!(
            !node.addr_to_node.contains_key(&punched_addr),
            "a refused CAS must not touch addr_to_node",
        );
    }

    /// C2 happy path: when the observed session_id still matches,
    /// `install_peer_cas` installs the new (punched) session and the
    /// C4 hygiene removes the displaced relay addr's stale reverse
    /// mapping.
    #[tokio::test]
    async fn install_peer_cas_installs_and_cleans_stale_addr_on_match() {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x2Du8; 32]);
        let node = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");

        let peer_id = 0x11_22_33_44u64;
        // Direct install so addr_to_node[old_addr] = peer_id (a
        // stale mapping the swap should clean up).
        let old_addr: SocketAddr = "10.5.5.5:9100".parse().unwrap();
        let (first_keys, _) = make_session_keys();
        let first_session_id = first_keys.session_id;
        node.install_peer(
            peer_id,
            old_addr,
            first_keys,
            AddrInstallMode::DirectOverwrite,
        );
        assert_eq!(
            node.addr_to_node.get(&old_addr).map(|e| *e),
            Some(peer_id),
            "precondition: old addr maps to the peer",
        );

        let new_addr: SocketAddr = "10.1.1.1:7000".parse().unwrap();
        let (punch_keys, _) = make_session_keys();
        let punch_session_id = punch_keys.session_id;
        let installed = node.install_peer_cas(
            peer_id,
            new_addr,
            punch_keys,
            AddrInstallMode::DirectOverwrite,
            Some(first_session_id),
        );
        assert!(installed, "CAS must install when the session_id matches");
        assert_eq!(
            node.peers
                .get(&peer_id)
                .map(|p| p.value().session.session_id()),
            Some(punch_session_id),
            "the punched session must replace the old one",
        );
        assert_eq!(
            node.addr_to_node.get(&new_addr).map(|e| *e),
            Some(peer_id),
            "the new addr must map to the peer",
        );
        assert!(
            !node.addr_to_node.contains_key(&old_addr),
            "C4: the displaced addr's stale reverse mapping must be removed",
        );
    }

    /// PERF_AUDIT §2.8 regression — the grant-path fast path must
    /// be SELF-PRIMING: a fallback resolution publishes the node id
    /// onto the session so the next packet takes the tier-1 atomic
    /// load. b45bc44b8 originally shipped without the publish, so
    /// the cache stayed empty for any session whose traffic never
    /// traversed the cortex RPC dispatch hook (plain reliable
    /// streams) and the fast path was dead. Also pins the stale-
    /// cache safety: a replaced session's resolution must fail the
    /// session-id cross-check rather than misroute to the
    /// replacement peer entry.
    #[tokio::test]
    async fn grant_peer_resolution_self_primes_node_id_cache() {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x2Bu8; 32]);
        let node = MeshNode::new(EntityKeypair::generate(), cfg)
            .await
            .expect("MeshNode::new");

        let peer_id = 0xCAFE_D00Du64;
        let peer_addr: SocketAddr = "10.3.3.3:9100".parse().unwrap();
        let (keys, _) = make_session_keys();
        node.install_peer(peer_id, peer_addr, keys, AddrInstallMode::DirectOverwrite);
        let session = node
            .peers
            .get(&peer_id)
            .map(|p| p.value().session.clone())
            .expect("peer installed");
        assert_eq!(
            session.cached_node_id(),
            None,
            "install_peer must not pre-prime the cache (lazy by design)"
        );

        // First resolution: tier 1 misses, the fallback resolves via
        // addr_to_node AND publishes the node id.
        let (resolved_addr, resolved_session) =
            MeshNode::resolve_grant_peer(&node.peers, &node.addr_to_node, &session)
                .expect("fallback chain resolves the installed peer");
        assert_eq!(resolved_addr, peer_addr);
        assert_eq!(resolved_session.session_id(), session.session_id());
        assert_eq!(
            session.cached_node_id(),
            Some(peer_id),
            "fallback resolution must publish the cache (self-priming)"
        );

        // Second resolution: tier 1 must carry it alone — drop the
        // addr_to_node entry to prove the fallback chain is no
        // longer needed for this session.
        node.addr_to_node.remove(&peer_addr);
        let (addr2, _) = MeshNode::resolve_grant_peer(&node.peers, &node.addr_to_node, &session)
            .expect("tier-1 cached resolution");
        assert_eq!(addr2, peer_addr);

        // Stale-cache safety: a re-handshake replaces the session
        // under the same node id. The OLD session's cached id now
        // points at a peer entry whose session_id no longer matches
        // — tier 1 must reject it, and with no addr or scan match
        // for the dead session the resolution returns None instead
        // of misrouting a grant to the replacement session.
        let (new_keys, _) = make_session_keys();
        node.install_peer(
            peer_id,
            peer_addr,
            new_keys,
            AddrInstallMode::DirectOverwrite,
        );
        assert!(
            MeshNode::resolve_grant_peer(&node.peers, &node.addr_to_node, &session).is_none(),
            "stale session must not resolve to the replacement peer entry"
        );
    }

    /// Regression for BUG_AUDIT_2026_04_30_CORE.md #97: the
    /// production heartbeat path must (a) build with the
    /// session's actual TX key — not `&[0u8; 32]` — and (b) use a
    /// **shared** `tx_counter` across builders so successive
    /// heartbeats don't all encrypt under counter=0 and trigger
    /// the receiver's replay window. Both bugs were latent before
    /// #85 wired up AEAD verification on the mesh receiver; this
    /// test pins the post-fix invariant by acquiring two builders
    /// from the SAME session pool (mirroring what the heartbeat
    /// timer at `mesh.rs:3220` does on each tick) and verifying
    /// that BOTH heartbeats verify against the peer session in
    /// order. Pre-fix behavior with the all-zero key would fail
    /// the first verify; pre-fix behavior with per-builder
    /// counters would fail the second.
    #[test]
    fn pooled_heartbeat_builds_succeed_in_sequence_and_verify() {
        let (init_keys, resp_keys) = make_session_keys();
        let init_session = NetSession::new(
            init_keys.clone(),
            "127.0.0.1:5001".parse().unwrap(),
            4,
            false,
        );
        let resp_session = NetSession::new(resp_keys, "127.0.0.1:5000".parse().unwrap(), 4, false);

        // Mirror the production sender — go through
        // `Session::build_heartbeat`, not a fresh
        // `PacketBuilder::new`.
        let h1_bytes = init_session.build_heartbeat();
        let h2_bytes = init_session.build_heartbeat();

        let p1 = ParsedPacket::parse(h1_bytes, "127.0.0.1:5001".parse().unwrap())
            .expect("first heartbeat must parse");
        let p2 = ParsedPacket::parse(h2_bytes, "127.0.0.1:5001".parse().unwrap())
            .expect("second heartbeat must parse");

        assert!(
            resp_session.verify_and_touch_heartbeat(&p1),
            "first pooled heartbeat must verify — pre-fix the \
             all-zero key would have produced an AEAD tag the \
             receiver couldn't decrypt"
        );
        assert!(
            resp_session.verify_and_touch_heartbeat(&p2),
            "second pooled heartbeat must also verify — pre-fix, \
             a per-builder fresh counter would reuse counter=0 \
             and the receiver's replay window would reject this \
             as a duplicate"
        );
    }

    #[test]
    fn replay_of_authenticated_heartbeat_fails_verification_on_second_try() {
        let (init_keys, resp_keys) = make_session_keys();
        let resp_session = NetSession::new(resp_keys, "127.0.0.1:5000".parse().unwrap(), 4, false);
        let mut builder = PacketBuilder::new(&init_keys.tx_key, init_keys.session_id);
        let bytes = builder.build_heartbeat();
        let parsed = ParsedPacket::parse(bytes, "127.0.0.1:5000".parse().unwrap()).unwrap();

        assert!(resp_session.verify_and_touch_heartbeat(&parsed));
        // Replay: counter is now committed, so the second attempt
        // must fail at the replay-window check.
        assert!(
            !resp_session.verify_and_touch_heartbeat(&parsed),
            "replay of an already-accepted heartbeat must fail"
        );
    }

    /// Invariant: heartbeats and data-path packets share a
    /// single TX counter via `thread_local_pool`. Pre-#106-fix,
    /// `NetSession` exposed two pools (`packet_pool` and
    /// `thread_local_pool`) with the same key but independent
    /// counters; a caller that mixed `session.packet_pool().get()`
    /// for some packets and `session.thread_local_pool().get()` for
    /// others would produce ChaCha20-Poly1305 nonce reuse against
    /// the same key, leaking plaintext via XOR.
    ///
    /// The fix removed `packet_pool` and routes all TX through
    /// `thread_local_pool`. Today `Session::build_heartbeat` calls
    /// `self.thread_local_pool.get().build_heartbeat()` and the
    /// data path builds via `self.thread_local_pool.get().build(...)`.
    /// This test pins the resulting wire-level invariant: the
    /// counters on heartbeat and data packets interleave strictly
    /// monotonically (no two packets ever share a counter, no
    /// matter the order they're built in). A future contributor who
    /// re-introduced a separate pool/counter for heartbeats would
    /// see this test fail because both sequences would restart at
    /// 0.
    #[test]
    fn heartbeat_and_data_share_tx_counter_strictly_monotonic() {
        let (init_keys, _resp_keys) = make_session_keys();
        let init_session = NetSession::new(
            init_keys.clone(),
            "127.0.0.1:5001".parse().unwrap(),
            4,
            false,
        );

        // Build sequence: heartbeat, data, heartbeat, data,
        // heartbeat. All five must have strictly-increasing
        // counters.
        let h1 = init_session.build_heartbeat();
        let d1 = {
            let mut pooled = init_session.thread_local_pool().get();
            pooled.build(
                0xCAFE_F00D,
                0,
                &[bytes::Bytes::from_static(b"event-a")],
                PacketFlags::NONE,
            )
        };
        let h2 = init_session.build_heartbeat();
        let d2 = {
            let mut pooled = init_session.thread_local_pool().get();
            pooled.build(
                0xCAFE_F00D,
                1,
                &[bytes::Bytes::from_static(b"event-b")],
                PacketFlags::NONE,
            )
        };
        let h3 = init_session.build_heartbeat();

        let counters = [
            counter_of(&h1),
            counter_of(&d1),
            counter_of(&h2),
            counter_of(&d2),
            counter_of(&h3),
        ];

        // Strict monotonicity: each counter > the previous one.
        for window in counters.windows(2) {
            assert!(
                window[0] < window[1],
                "tx counters must be strictly increasing across heartbeat/data \
                 interleave; got {:?} (regression: heartbeats and data \
                 are drawing from independent counters)",
                counters
            );
        }
    }

    /// CR-8: source-level tripwire pinning that no dispatch
    /// branch uses `events.into_iter().next()` to drop multi-event
    /// frames. The original fix only patched
    /// `SUBPROTOCOL_STREAM_WINDOW`; CR-8 extended the same fix to
    /// the migration / channel-membership / capability-ann / reflex
    /// / rendezvous branches. This test scans the file source for
    /// any new occurrence outside fix-doc comments and fails loudly
    /// if a future maintainer reintroduces the pattern.
    ///
    /// We assemble the forbidden token at runtime so the test's
    /// own source doesn't trigger itself.
    #[test]
    fn cr8_dispatch_must_not_use_single_event_pattern() {
        // Build the forbidden token from fragments so this test's
        // source doesn't contain the literal substring.
        let needle = format!("events.into_iter().{}()", "next");

        let src = include_str!("mesh.rs");
        for (lineno, line) in src.lines().enumerate() {
            let trimmed = line.trim_start();
            // Skip line comments and doc comments — these are
            // ALLOWED to mention the pre-fix shape (the fix-doc
            // narratives are load-bearing context for future
            // maintainers).
            if trimmed.starts_with("//") {
                continue;
            }
            // Skip lines inside doc-string-style comments inside
            // string literals: we don't try to be too clever here,
            // since a code line containing `events.into_iter().next()`
            // outside a comment is the regression we want to catch.
            assert!(
                !trimmed.contains(&needle),
                "CR-8 regression: single-event dispatch pattern reintroduced \
                 at mesh.rs:{} — multi-event frames will silently drop \
                 every payload past the first.\n  line: {}",
                lineno + 1,
                line
            );
        }
    }

    /// Source-level pin: every `hop_count += 1` / `hop_count = X + 1`
    /// pattern in this file MUST go through `saturating_add`.
    /// `hop_count: u8` saturates at 255; an attacker-controlled
    /// inbound packet whose `hop_count` is already u8::MAX would
    /// debug-panic (`overflow`) or release-wraparound to 0 on a
    /// bare `+= 1`. Today the upstream `< MAX_CAPABILITY_HOPS - 1`
    /// guard bounds the value at 14 before the bump, so the
    /// saturating call is dormant — but a future change that
    /// raises the cap or relaxes the guard would otherwise turn
    /// an attacker byte into UB / wrap. This pin ensures the
    /// hardening stays in place even if the upstream gate moves.
    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #3 (replay
    /// guard arm): a routed msg1 whose `remote_static_pub` matches
    /// the live session's static must be dropped so the live
    /// session's keys aren't overwritten by NKpsk0's fresh-ephemeral
    /// reply.
    #[test]
    fn routed_rotation_outcome_drops_replay_for_matching_static_and_ephemeral() {
        let addr: SocketAddr = "10.0.0.1:9000".parse().unwrap();
        let (init_keys, _) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, addr, 4, false));
        let static_a = [0xAAu8; 32];
        let ephemeral_a = [0xCCu8; 32];
        let info = PeerInfo {
            node_id: 0xBEEF_BEEFu64,
            addr,
            session,
            remote_static_pub: static_a,
            last_initiator_ephemeral: Some(ephemeral_a),
        };
        assert_eq!(
            routed_rotation_outcome(&info, &static_a, &ephemeral_a, Duration::from_secs(30)),
            RoutedRotationOutcome::DropReplay,
        );
    }

    /// Regression for the pass-2 follow-up: a routed msg1 with the
    /// SAME static but a DIFFERENT ephemeral is a legitimate
    /// re-handshake from the same peer (only the static + PSK
    /// holder can produce a fresh ephemeral). Pre-fix the gate
    /// flagged this as a replay and refused — breaking the
    /// `connect_direct` retarget path. AcceptRotation now.
    #[test]
    fn routed_rotation_outcome_accepts_reinit_with_fresh_ephemeral() {
        let addr: SocketAddr = "10.0.0.1:9000".parse().unwrap();
        let (init_keys, _) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, addr, 4, false));
        let static_a = [0xAAu8; 32];
        let ephemeral_old = [0xCCu8; 32];
        let ephemeral_new = [0xDDu8; 32];
        let info = PeerInfo {
            node_id: 0xBEEF_BEEFu64,
            addr,
            session,
            remote_static_pub: static_a,
            last_initiator_ephemeral: Some(ephemeral_old),
        };
        assert_eq!(
            routed_rotation_outcome(&info, &static_a, &ephemeral_new, Duration::from_secs(30)),
            RoutedRotationOutcome::AcceptRotation,
        );
    }

    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #3 (rotation
    /// gate, fresh-session arm): a routed msg1 with a *different*
    /// `remote_static_pub` for an existing peer must NOT overwrite
    /// the live session while the existing session is still within
    /// `session_timeout`. Pre-fix this branch unconditionally
    /// inserted the new keys, opening a trivial DoS where any party
    /// with the PSK and a valid Noise static could break AEAD
    /// verification on every legitimate packet to the affected peer.
    #[test]
    fn routed_rotation_outcome_refuses_rotation_while_session_is_fresh() {
        let addr: SocketAddr = "10.0.0.1:9000".parse().unwrap();
        let (init_keys, _) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, addr, 4, false));
        let info = PeerInfo {
            node_id: 0xBEEF_BEEFu64,
            addr,
            session,
            remote_static_pub: [0xAAu8; 32],
            last_initiator_ephemeral: Some([0xCCu8; 32]),
        };
        let new_static = [0xBBu8; 32];
        let new_ephemeral = [0xDDu8; 32];
        assert_eq!(
            routed_rotation_outcome(&info, &new_static, &new_ephemeral, Duration::from_secs(30),),
            RoutedRotationOutcome::RefuseFresh,
        );
    }

    /// Companion to the fresh-session refusal: once the live session
    /// has gone silent for at least `session_timeout`, a rotation
    /// from a different `remote_static_pub` IS accepted. This pins
    /// that the gate eventually unblocks — a permanent refusal would
    /// be a different kind of bug (legitimate peers rotating keys
    /// could never reconnect).
    #[test]
    fn routed_rotation_outcome_accepts_rotation_after_session_timeout() {
        let addr: SocketAddr = "10.0.0.1:9000".parse().unwrap();
        let (init_keys, _) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, addr, 4, false));
        let info = PeerInfo {
            node_id: 0xBEEF_BEEFu64,
            addr,
            session,
            remote_static_pub: [0xAAu8; 32],
            last_initiator_ephemeral: Some([0xCCu8; 32]),
        };
        // Wait past a 1 ms session_timeout. `current_timestamp()`
        // uses wall-clock `SystemTime::now()` so a real sleep
        // advances it.
        std::thread::sleep(Duration::from_millis(5));
        let new_static = [0xBBu8; 32];
        let new_ephemeral = [0xDDu8; 32];
        assert_eq!(
            routed_rotation_outcome(&info, &new_static, &new_ephemeral, Duration::from_millis(1),),
            RoutedRotationOutcome::AcceptRotation,
        );
    }

    /// Direct-path upgrade C3 (responder half): a same-static
    /// re-handshake that would normally rotate is DEFERRED when the
    /// existing session is live and busy (an open application stream),
    /// so an in-flight transfer isn't dropped by the swap.
    #[test]
    fn routed_rotation_outcome_defers_while_session_busy() {
        let addr: SocketAddr = "10.0.0.1:9000".parse().unwrap();
        let (init_keys, _) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, addr, 4, false));
        // Open an application stream → the session is now "busy".
        session.get_or_create_stream(1);
        assert!(session.has_open_streams(), "precondition: session is busy");
        let static_a = [0xAAu8; 32];
        let info = PeerInfo {
            node_id: 0xBEEF_BEEFu64,
            addr,
            session,
            remote_static_pub: static_a,
            last_initiator_ephemeral: Some([0xCCu8; 32]),
        };
        // Same static, fresh ephemeral, live (30 s timeout) + busy.
        assert_eq!(
            routed_rotation_outcome(&info, &static_a, &[0xDDu8; 32], Duration::from_secs(30)),
            RoutedRotationOutcome::DeferBusy,
        );
    }

    /// The DeferBusy liveness bound: a busy session that has gone idle
    /// past `session_timeout` rotates anyway (AcceptRotation), so a
    /// genuinely dead path — e.g. the peer recovering after a NAT
    /// rebind — is never blocked by stale "busy" state.
    #[test]
    fn routed_rotation_outcome_accepts_busy_session_past_timeout() {
        let addr: SocketAddr = "10.0.0.1:9000".parse().unwrap();
        let (init_keys, _) = make_session_keys();
        let session = Arc::new(NetSession::new(init_keys, addr, 4, false));
        session.get_or_create_stream(1);
        assert!(session.has_open_streams(), "precondition: session is busy");
        let static_a = [0xAAu8; 32];
        let info = PeerInfo {
            node_id: 0xBEEF_BEEFu64,
            addr,
            session,
            remote_static_pub: static_a,
            last_initiator_ephemeral: Some([0xCCu8; 32]),
        };
        // Let the session go idle past a 1 ms timeout — not live.
        std::thread::sleep(Duration::from_millis(5));
        assert_eq!(
            routed_rotation_outcome(&info, &static_a, &[0xDDu8; 32], Duration::from_millis(1)),
            RoutedRotationOutcome::AcceptRotation,
        );
    }

    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #9:
    /// `connect_on_direct_path` must refresh
    /// `addr_to_node[target_addr] = peer_node_id` on success.
    /// Pre-fix the closure called `connect_via` which deliberately
    /// does NOT touch `addr_to_node` (correct for relayed sessions
    /// where the relay's address must keep mapping to the relay's
    /// own node_id), so a successful direct upgrade left the
    /// dispatch fast path
    /// (`addr_to_node.get(&source) → peers.get(nid)`) missing on
    /// the upgraded session's reflex addr — every inbound packet
    /// then fell back to a linear `peers.iter().find(|e|
    /// session_id == ...)` for exactly the sessions that benefit
    /// most from the index. Source-level pin so the closure body
    /// keeps the `addr_to_node.insert` after the upgrade lands.
    #[test]
    fn connect_direct_upgrade_refreshes_addr_to_node() {
        let src = include_str!("mesh.rs");
        let start = src
            .find("let connect_on_direct_path =")
            .expect("connect_on_direct_path closure must exist");
        let scan_end = (start + 4000).min(src.len());
        let body = &src[start..scan_end];

        assert!(
            body.contains("self.addr_to_node.insert(target_addr, peer_node_id)"),
            "regression: connect_on_direct_path must refresh addr_to_node \
             on success — pre-fix the dispatch fast path missed on the \
             upgraded session's reflex addr and fell back to a linear \
             peers.iter().find per packet for exactly the sessions that \
             benefit most from the index."
        );
    }

    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #8: the
    /// migration-handler loopback drain in `process_local_packet`
    /// must cap the synchronous self-bounce depth. Pre-fix the
    /// in-place `pending: VecDeque` loop drained as long as the
    /// handler emitted self-bound follow-ups, so a buggy or
    /// attacker-influenced handler that always emitted a self-bound
    /// message would spin the dispatch task forever, starving every
    /// other peer's packets. Source-level pin: the constant
    /// `MAX_MIGRATION_LOOPBACK_DEPTH` and a `> MAX_..._DEPTH` guard
    /// must be present in the file. A future change that drops the
    /// guard fails this pin loudly rather than silently
    /// reintroducing the starvation.
    #[test]
    fn migration_loopback_drain_caps_self_bounce_depth() {
        let src = include_str!("mesh.rs");
        assert!(
            src.contains("const MAX_MIGRATION_LOOPBACK_DEPTH: usize"),
            "regression: process_local_packet's migration loopback drain \
             must declare a `MAX_MIGRATION_LOOPBACK_DEPTH` cap. Pre-fix \
             the loop ran unbounded so a handler stuck in a self-bounce \
             state would starve the dispatch task."
        );
        assert!(
            src.contains("loopback_count > MAX_MIGRATION_LOOPBACK_DEPTH"),
            "regression: the migration loopback drain must short-circuit \
             past the depth cap with a warn — the bare `loopback_count += 1; \
             match handler.handle_message(...)` shape without the threshold \
             check leaves the unbounded-spin hazard in place."
        );
    }

    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #7:
    /// `publish_to_peer` was the only sender call site that
    /// hard-coded `PacketFlags::NONE` instead of computing
    /// `if reliable { PacketFlags::RELIABLE } else { PacketFlags::NONE }`.
    /// Today the dispatch path doesn't consult `is_reliable()` (per-
    /// stream reliability is set at open), so the inconsistency is
    /// latent — but receiver-side code already consults the packet
    /// flag for `is_priority` / `is_control`, and `is_reliable` is
    /// the obvious next addition. This source-level pin ensures the
    /// fix doesn't get reverted before the dispatch path catches up.
    #[test]
    fn publish_to_peer_propagates_reliable_to_packet_flags() {
        let src = include_str!("mesh.rs");
        let start = src
            .find("async fn publish_to_peer(")
            .expect("publish_to_peer must exist");
        // Round down to a char boundary — the source has multibyte
        // box-drawing characters in doc comments, and a fixed-byte
        // window can land mid-UTF-8 sequence after edits to the
        // surrounding code shift offsets.
        let mut scan_end = (start + 6000).min(src.len());
        while scan_end < src.len() && !src.is_char_boundary(scan_end) {
            scan_end += 1;
        }
        let body = &src[start..scan_end];

        assert!(
            body.contains("if reliable") && body.contains("PacketFlags::RELIABLE"),
            "regression: publish_to_peer must thread `reliable` into the packet \
             header — pre-fix it hard-coded PacketFlags::NONE while only \
             feeding `reliable` into open_stream_with, leaving every other \
             sender call site (send_to_peer, send_routed, send_on_stream) \
             inconsistent."
        );
    }

    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #6: the
    /// routed-handshake replay/rotation decision and the subsequent
    /// `peers.insert` must happen under a single `peers.entry`
    /// write guard so two concurrent routed handshakes for the same
    /// `peer_node_id` cannot both pass the existing-static check
    /// and race the insert. The shape pin guards against a future
    /// refactor that reintroduces the get→insert split.
    #[test]
    fn routed_handshake_uses_entry_api_for_atomic_insert() {
        let src = include_str!("mesh.rs");
        // Find `fn handle_routed_handshake` and scan to the next
        // function definition (or 16 KB, whichever comes first).
        let start = src
            .find("fn handle_routed_handshake")
            .expect("handle_routed_handshake must exist");
        let scan_end = (start + 16_000).min(src.len());
        let body = &src[start..scan_end];
        assert!(
            body.contains("ctx.peers.entry(peer_node_id)"),
            "regression: handle_routed_handshake must use peers.entry() so the \
             replay/rotation decision and the insert are atomic. Pre-fix the \
             function used `peers.get` followed by `peers.insert`, which let \
             two concurrent handshakes race the insert and wedge the loser's \
             pending_handshakes state until handshake_timeout."
        );
        // Negative pin: the bare insert pattern outside the entry
        // block would signal a regression to the get→insert split.
        assert!(
            !body.contains("ctx.peers.insert(\n            peer_node_id,"),
            "regression: bare ctx.peers.insert(peer_node_id, ...) reintroduced \
             outside the peers.entry() block — the insert must be gated by the \
             same entry guard as the existing-static check."
        );
    }

    /// Regression for `BUG_AUDIT_2026_05_03_MESH.md` #5 (narrow form):
    /// the idempotent re-subscribe handling in `authorize_subscribe`
    /// must SUPPRESS THE CAP REJECTION ONLY — not short-circuit the
    /// whole auth chain. The original fix (returning `(true, None)`
    /// directly when `is_subscribed` was true) bypassed visibility,
    /// registry, and token validation for any peer already in the
    /// roster, silently outliving auth-state changes (e.g., a
    /// re-emitted Subscribe with a now-revoked token would have been
    /// admitted at the wire level even though the periodic sweep
    /// would later evict the entry). Pin the narrower combined check
    /// so a future "simplification" back to the broad form fails
    /// loudly here rather than re-introducing the bypass.
    #[test]
    fn authorize_subscribe_only_suppresses_cap_for_already_subscribed() {
        let src = include_str!("mesh.rs");
        let start = src
            .find("fn authorize_subscribe(")
            .expect("authorize_subscribe must exist");
        let scan_end = (start + 4_000).min(src.len());
        let body = &src[start..scan_end];

        // Positive: the combined predicate must be present.
        assert!(
            body.contains("let already_subscribed = ctx.roster.is_subscribed("),
            "regression: authorize_subscribe must capture an \
             `already_subscribed` boolean and use it to gate ONLY the \
             cap rejection."
        );
        assert!(
            body.contains("!already_subscribed") && body.contains(">= ctx.max_channels_per_peer"),
            "regression: the cap rejection must be guarded by \
             `!already_subscribed && ... >= max_channels_per_peer` so \
             an under-cap or already-subscribed peer falls through to \
             the visibility / registry / token gates rather than being \
             admitted with `(true, None)` ahead of them."
        );

        // Negative: the broad short-circuit `if is_subscribed { return (true, None) }`
        // must NOT reappear — that was the original over-broad form
        // that bypassed the rest of the auth chain.
        assert!(
            !body.contains("if ctx.roster.is_subscribed(from_node, &channel_id) {\n            return (true, None);"),
            "regression: the broad `if is_subscribed -> return (true, None)` \
             short-circuit reintroduced — this bypasses visibility, \
             registry, and token validation for any peer already in the \
             roster. Use the narrower `!already_subscribed && >= cap` \
             form so the cap rejection is the ONLY thing suppressed."
        );
    }

    #[test]
    fn hop_count_increments_must_be_saturating() {
        // Build the forbidden token at runtime so this test's source
        // doesn't trigger itself.
        let bare_bump = format!("hop_count {} 1", "+=");

        let src = include_str!("mesh.rs");
        for (lineno, line) in src.lines().enumerate() {
            let trimmed = line.trim_start();
            // Comments are allowed to mention the pre-fix shape.
            if trimmed.starts_with("//") {
                continue;
            }
            assert!(
                !trimmed.contains(&bare_bump),
                "hop_count regression: bare `+= 1` reintroduced at \
                 mesh.rs:{} — use `saturating_add(1)` so an attacker-\
                 controlled `hop_count == u8::MAX` cannot wrap.\n  line: {}",
                lineno + 1,
                line,
            );
        }
    }
}

#[cfg(test)]
#[cfg(feature = "redex")]
mod replication_dispatch_tests {
    //! Pure-logic tests for `dispatch_replication_payload`. Covers
    //! the wire-format dispatch routing (header → variant) without
    //! spinning a real `MeshNode`.
    use super::*;
    use crate::adapter::net::redex::{ChannelId, ReplicaRole};
    use crate::adapter::net::redex::{
        Inbound, ReplicationInboundRouter, SyncHeartbeat, SyncNack, SyncNackError, SyncRequest,
        SyncResponse, DISPATCH_SYNC_NACK,
    };
    use parking_lot::Mutex as ParkingMutex;

    #[derive(Default)]
    struct RecorderRouter {
        events: ParkingMutex<Vec<(ChannelId, Inbound)>>,
        /// When set, `try_route` returns the event back unrouted.
        always_reject: ParkingMutex<bool>,
    }

    impl ReplicationInboundRouter for RecorderRouter {
        fn try_route(&self, channel_id: ChannelId, inbound: Inbound) -> Result<(), Inbound> {
            if *self.always_reject.lock() {
                return Err(inbound);
            }
            self.events.lock().push((channel_id, inbound));
            Ok(())
        }
    }

    fn cid_for(name: &str) -> ChannelId {
        let cn = ChannelName::new(name).unwrap();
        ChannelId::from_name(&cn)
    }

    #[test]
    fn heartbeat_dispatches_to_router() {
        let cid = cid_for("test/heartbeat");
        let hb = SyncHeartbeat {
            channel_id: cid,
            tail_seq: 42,
            role: ReplicaRole::Leader,
            wall_clock_ms: 0,
        };
        let payload = hb.to_bytes();
        let router = RecorderRouter::default();
        MeshNode::dispatch_replication_payload(&payload, 0xDEAD_BEEF, &router);
        let events = router.events.lock();
        assert_eq!(events.len(), 1);
        let (got_cid, ref got_inbound) = events[0];
        assert_eq!(got_cid, cid);
        assert!(matches!(
            got_inbound,
            Inbound::Heartbeat {
                from: 0xDEAD_BEEF,
                ..
            }
        ));
    }

    #[test]
    fn sync_request_dispatches_to_router() {
        let cid = cid_for("test/sync_request");
        let req = SyncRequest {
            channel_id: cid,
            since_seq: 100,
            chunk_max: 4096,
            request_id: 0,
            class: Default::default(),
        };
        let payload = req.to_bytes();
        let router = RecorderRouter::default();
        MeshNode::dispatch_replication_payload(&payload, 0x12, &router);
        let events = router.events.lock();
        assert!(matches!(
            events[0].1,
            Inbound::SyncRequest { from: 0x12, .. }
        ));
    }

    #[test]
    fn sync_response_dispatches_to_router() {
        let cid = cid_for("test/sync_response");
        let resp = SyncResponse {
            channel_id: cid,
            first_seq: 0,
            leader_first_retained_seq: 0,
            events: vec![],
            request_id: 0,
        };
        let payload = resp.to_bytes();
        let router = RecorderRouter::default();
        MeshNode::dispatch_replication_payload(&payload, 0x34, &router);
        let events = router.events.lock();
        assert!(matches!(
            events[0].1,
            Inbound::SyncResponse { from: 0x34, .. }
        ));
    }

    #[test]
    fn sync_nack_dispatches_to_router() {
        let cid = cid_for("test/sync_nack");
        let nack = SyncNack {
            channel_id: cid,
            since_seq: 50,
            error_code: SyncNackError::NotLeader,
            leader_first_retained_seq: 0,
            detail: "re-resolve leader".to_string(),
            request_id: 0,
        };
        let payload = nack.to_bytes();
        let router = RecorderRouter::default();
        MeshNode::dispatch_replication_payload(&payload, 0x56, &router);
        let events = router.events.lock();
        assert!(matches!(events[0].1, Inbound::SyncNack { from: 0x56, .. }));
    }

    #[test]
    fn truncated_payload_dropped_silently() {
        let router = RecorderRouter::default();
        // Just the 3-byte header but body is missing.
        let payload: Vec<u8> = vec![0x00, 0x0E, DISPATCH_SYNC_NACK];
        MeshNode::dispatch_replication_payload(&payload, 0, &router);
        assert!(router.events.lock().is_empty());
    }

    #[test]
    fn payload_shorter_than_header_dropped() {
        let router = RecorderRouter::default();
        let payload: Vec<u8> = vec![0x00, 0x0E]; // missing dispatch byte
        MeshNode::dispatch_replication_payload(&payload, 0, &router);
        assert!(router.events.lock().is_empty());
    }

    #[test]
    fn unknown_dispatch_code_dropped() {
        let router = RecorderRouter::default();
        // Valid subprotocol id, but dispatch code outside
        // 0x20..=0x23 (the implemented range). 0x2F is in the
        // reserved-future range.
        let payload: Vec<u8> = vec![0x00, 0x0E, 0x2F, 0xAA, 0xBB];
        MeshNode::dispatch_replication_payload(&payload, 0, &router);
        assert!(router.events.lock().is_empty());
    }

    #[test]
    fn wrong_subprotocol_id_in_payload_dropped() {
        // Payload's leading 2 bytes claim a different
        // subprotocol id — the per-message decoder rejects it.
        let cid = cid_for("test/wrong_subprotocol");
        let hb = SyncHeartbeat {
            channel_id: cid,
            tail_seq: 0,
            role: ReplicaRole::Leader,
            wall_clock_ms: 0,
        };
        let mut payload = hb.to_bytes();
        payload[0] = 0x00;
        payload[1] = 0x05; // SUBPROTOCOL_MIGRATION
        let router = RecorderRouter::default();
        MeshNode::dispatch_replication_payload(&payload, 0, &router);
        assert!(router.events.lock().is_empty());
    }

    #[test]
    fn router_rejection_swallowed_silently() {
        // Router returns the event back (full buffer / unknown
        // channel). Dispatch hot-path must not panic; the event
        // is simply dropped.
        let cid = cid_for("test/rejection");
        let hb = SyncHeartbeat {
            channel_id: cid,
            tail_seq: 0,
            role: ReplicaRole::Leader,
            wall_clock_ms: 0,
        };
        let payload = hb.to_bytes();
        let router = RecorderRouter::default();
        *router.always_reject.lock() = true;
        // Should not panic.
        MeshNode::dispatch_replication_payload(&payload, 0, &router);
        assert!(router.events.lock().is_empty());
    }
}

#[cfg(test)]
mod chain_helper_tests {
    //! Pure-logic tests for `Mesh::chain_hex` / `is_causal_for` /
    //! `replace_causal_tags`. The integration-flavored variants
    //! that spin a real `MeshNode` live in
    //! `net/crates/net/tests/chain_discovery.rs`.
    use super::*;
    use crate::adapter::net::behavior::capability::CapabilitySet;
    use crate::adapter::net::behavior::tag::Tag;

    #[test]
    fn chain_hex_is_lowercase_16_chars() {
        assert_eq!(MeshNode::chain_hex(0), "0000000000000000");
        assert_eq!(
            MeshNode::chain_hex(0xDEAD_BEEF_CAFE_BABE),
            "deadbeefcafebabe"
        );
        assert_eq!(MeshNode::chain_hex(u64::MAX), "ffffffffffffffff");
        // Pin the 16-char width — wire-format drift would surface
        // here.
        for h in [0u64, 1, 0x42, u64::MAX] {
            assert_eq!(MeshNode::chain_hex(h).len(), 16);
        }
    }

    // The `MeshNode::blob_hex` / `is_blob_heat_for` /
    // `replace_blob_heat_tags` helpers live behind the `dataforts`
    // feature flag (they back the PR-5j-c blob-heat tag emission
    // path on the production wire). Gate the tests so a build
    // without the feature doesn't try to call non-existent
    // methods.
    #[cfg(feature = "dataforts")]
    #[test]
    fn blob_hex_is_lowercase_64_chars() {
        let zero = [0u8; 32];
        assert_eq!(MeshNode::blob_hex(&zero).len(), 64);
        assert!(MeshNode::blob_hex(&zero).chars().all(|c| c == '0'));
        let mut h = [0u8; 32];
        h[0] = 0xDE;
        h[1] = 0xAD;
        h[31] = 0xFF;
        let hex = MeshNode::blob_hex(&h);
        assert!(hex.starts_with("dead"));
        assert!(hex.ends_with("ff"));
        assert_eq!(hex.len(), 64);
    }

    #[cfg(feature = "dataforts")]
    #[test]
    fn is_blob_heat_for_matches_blob_body_only() {
        let mut h = [0u8; 32];
        h[0] = 0x42;
        let hex = MeshNode::blob_hex(&h);
        let blob_tag = Tag::Reserved {
            prefix: "heat:".to_string(),
            body: format!("blob:{}=0.5", hex),
        };
        assert!(MeshNode::is_blob_heat_for(&blob_tag, &hex));
        // Chain-heat shape (no "blob:" sub-prefix) must NOT match.
        let chain_tag = Tag::Reserved {
            prefix: "heat:".to_string(),
            body: format!("{}=0.5", MeshNode::chain_hex(0x42)),
        };
        assert!(!MeshNode::is_blob_heat_for(&chain_tag, &hex));
    }

    #[cfg(feature = "dataforts")]
    #[test]
    fn replace_blob_heat_tags_round_trip() {
        let mut h = [0u8; 32];
        h[0] = 0x77;
        let hex = MeshNode::blob_hex(&h);
        let mut caps = CapabilitySet::default();
        let initial = Tag::Reserved {
            prefix: "heat:".to_string(),
            body: format!("blob:{}=0.10", hex),
        };
        caps.tags.insert(initial.clone());
        // Replace with a fresh rate.
        let replacement = Tag::Reserved {
            prefix: "heat:".to_string(),
            body: format!("blob:{}=0.80", hex),
        };
        MeshNode::replace_blob_heat_tags(&mut caps, &h, Some(replacement.clone()));
        assert!(caps.tags.contains(&replacement));
        assert!(!caps.tags.contains(&initial));
        // Withdraw — every heat:blob:<hex>=* drops.
        MeshNode::replace_blob_heat_tags(&mut caps, &h, None);
        assert!(!caps
            .tags
            .iter()
            .any(|t| MeshNode::is_blob_heat_for(t, &hex)));
    }

    fn causal_tag(body: impl Into<String>) -> Tag {
        Tag::Reserved {
            prefix: "causal:".to_string(),
            body: body.into(),
        }
    }

    #[test]
    fn is_causal_for_presence_form() {
        let hex = MeshNode::chain_hex(0x42);
        assert!(MeshNode::is_causal_for(&causal_tag(&hex), &hex));
    }

    #[test]
    fn is_causal_for_tip_form() {
        let hex = MeshNode::chain_hex(0x42);
        assert!(MeshNode::is_causal_for(
            &causal_tag(format!("{hex}:100")),
            &hex
        ));
    }

    #[test]
    fn is_causal_for_range_form() {
        let hex = MeshNode::chain_hex(0x42);
        assert!(MeshNode::is_causal_for(
            &causal_tag(format!("{hex}[50..100]")),
            &hex
        ));
    }

    #[test]
    fn is_causal_for_rejects_different_hash() {
        let our = MeshNode::chain_hex(0x42);
        let theirs = MeshNode::chain_hex(0x43);
        assert!(!MeshNode::is_causal_for(&causal_tag(&theirs), &our));
        assert!(!MeshNode::is_causal_for(
            &causal_tag(format!("{theirs}:100")),
            &our,
        ));
    }

    #[test]
    fn is_causal_for_rejects_non_causal_reserved() {
        // `fork-of:<hash>` is a Reserved tag too, but with a
        // different prefix. Must not false-match.
        let hex = MeshNode::chain_hex(0x42);
        let t = Tag::Reserved {
            prefix: "fork-of:".to_string(),
            body: hex.clone(),
        };
        assert!(!MeshNode::is_causal_for(&t, &hex));
    }

    #[test]
    fn is_causal_for_rejects_axis_value_tag() {
        let hex = MeshNode::chain_hex(0x42);
        let t = Tag::parse("hardware.gpu=nvidia").unwrap();
        assert!(!MeshNode::is_causal_for(&t, &hex));
    }

    #[test]
    fn is_causal_for_no_false_match_on_hex_prefix() {
        // The shorter hex `00...0100` is a substring prefix of the
        // longer `00...1000` ONLY at the first character (`0`). The
        // matcher must inspect the byte AFTER the hex to ensure we
        // see `:`, `[`, or end-of-body.
        //
        // More direct test: a `causal:<our_hex>x...` body where `x`
        // is some character other than `:` or `[` — must not match.
        let our = MeshNode::chain_hex(0x42);
        let mut bogus = our.clone();
        bogus.push('x'); // not a valid delimiter
        bogus.push_str(":99");
        let t = causal_tag(bogus);
        assert!(!MeshNode::is_causal_for(&t, &our));
    }

    #[test]
    fn replace_causal_tags_strips_every_variant() {
        let mut caps = CapabilitySet::default();
        // Insert four causal: tags — three for our chain, one for
        // a different chain — plus an unrelated axis tag.
        let our = 0x42u64;
        let our_hex = MeshNode::chain_hex(our);
        let other_hex = MeshNode::chain_hex(0x43);
        caps.tags.insert(causal_tag(&our_hex));
        caps.tags.insert(causal_tag(format!("{our_hex}:50")));
        caps.tags.insert(causal_tag(format!("{our_hex}[10..20]")));
        caps.tags.insert(causal_tag(&other_hex));
        caps.tags.insert(Tag::parse("hardware.gpu").unwrap());

        MeshNode::replace_causal_tags(&mut caps, our, None);

        // Every causal: tag for our hash gone; other chain's tag
        // intact; axis tag untouched.
        let our_count = caps
            .tags
            .iter()
            .filter(|t| MeshNode::is_causal_for(t, &our_hex))
            .count();
        let other_count = caps
            .tags
            .iter()
            .filter(|t| MeshNode::is_causal_for(t, &other_hex))
            .count();
        assert_eq!(our_count, 0, "every variant for our hash must be stripped");
        assert_eq!(other_count, 1, "other chain's tag must survive");
        assert!(
            caps.tags.iter().any(|t| matches!(t,
                Tag::AxisPresent { axis, key }
                    if axis == &crate::adapter::net::behavior::tag::TaxonomyAxis::Hardware
                        && key == "gpu"
            )),
            "non-causal tag must survive"
        );
    }

    #[test]
    fn replace_causal_tags_inserts_replacement() {
        let mut caps = CapabilitySet::default();
        let our = 0x42u64;
        let our_hex = MeshNode::chain_hex(our);
        caps.tags.insert(causal_tag(format!("{our_hex}:50")));

        // Replace tip 50 with tip 100.
        let replacement = causal_tag(format!("{our_hex}:100"));
        MeshNode::replace_causal_tags(&mut caps, our, Some(replacement.clone()));

        let variants: Vec<_> = caps
            .tags
            .iter()
            .filter(|t| MeshNode::is_causal_for(t, &our_hex))
            .collect();
        assert_eq!(variants.len(), 1, "exactly one causal: tag for our hash");
        assert_eq!(variants[0], &replacement);
    }

    #[test]
    fn filter_unauthorized_heat_tags_strips_unclaimed_origins() {
        // A peer can only annotate heat for chains it also
        // advertises holding. Heat tags whose hex doesn't appear
        // in any causal: tag in the same set get filtered out.
        let mut caps = CapabilitySet::default();
        let owned_hex = MeshNode::chain_hex(0xCAFE);
        let forged_hex = MeshNode::chain_hex(0xDEAD);
        caps.tags.insert(causal_tag(&owned_hex));
        caps.tags.insert(Tag::Reserved {
            prefix: "heat:".to_string(),
            body: format!("{owned_hex}=0.50"),
        });
        caps.tags.insert(Tag::Reserved {
            prefix: "heat:".to_string(),
            body: format!("{forged_hex}=0.99"),
        });
        // Throw in a non-heat reserved tag — must survive.
        caps.tags.insert(Tag::Reserved {
            prefix: "scope:".to_string(),
            body: "industrial".to_string(),
        });

        MeshNode::filter_unauthorized_heat_tags(&mut caps);

        // Owned heat tag survives; forged one is gone.
        let surviving_heat: Vec<_> = caps
            .tags
            .iter()
            .filter_map(|t| match t {
                Tag::Reserved { prefix, body } if prefix == "heat:" => Some(body.clone()),
                _ => None,
            })
            .collect();
        assert_eq!(surviving_heat.len(), 1);
        assert!(surviving_heat[0].starts_with(&owned_hex));
        // Scope tag survived; causal tag survived.
        assert!(caps.tags.iter().any(|t| matches!(
            t,
            Tag::Reserved { prefix, .. } if prefix == "scope:"
        )));
        assert!(caps
            .tags
            .iter()
            .any(|t| MeshNode::is_causal_for(t, &owned_hex)));
    }

    /// Regression for the heat:blob DoS surface. A peer injects
    /// more than `MAX_BLOB_HEAT_TAGS_PER_ANNOUNCE` blob-heat tags
    /// into a single announcement; the filter drops the overflow.
    /// The cap bounds the migration-controller amplification
    /// (each surviving heat tag drives an `adapter.prefetch`
    /// attempt).
    #[cfg(feature = "dataforts")]
    #[test]
    fn filter_unauthorized_heat_tags_caps_blob_heat_flood_per_announce() {
        let mut caps = CapabilitySet::default();
        // Stuff in 2× the cap of distinct blob-heat tags.
        let flood = MAX_BLOB_HEAT_TAGS_PER_ANNOUNCE * 2;
        for i in 0..flood {
            let mut hash = [0u8; 32];
            // Pack the index into bytes 0..8 so each hash is
            // distinct without needing a hash function.
            hash[..8].copy_from_slice(&(i as u64).to_le_bytes());
            let hex = MeshNode::blob_hex(&hash);
            caps.tags.insert(Tag::Reserved {
                prefix: "heat:".to_string(),
                body: format!("blob:{hex}=1.00"),
            });
        }
        // Sanity: every distinct tag landed in the HashSet.
        let pre_filter = caps
            .tags
            .iter()
            .filter(|t| {
                matches!(t, Tag::Reserved { prefix, body }
                if prefix == "heat:" && body.starts_with("blob:"))
            })
            .count();
        assert_eq!(pre_filter, flood);

        MeshNode::filter_unauthorized_heat_tags(&mut caps);

        let post_filter = caps
            .tags
            .iter()
            .filter(|t| {
                matches!(t, Tag::Reserved { prefix, body }
                if prefix == "heat:" && body.starts_with("blob:"))
            })
            .count();
        assert_eq!(
            post_filter, MAX_BLOB_HEAT_TAGS_PER_ANNOUNCE,
            "filter must drop blob-heat tags past the per-announce cap"
        );
    }
}

#[cfg(test)]
#[cfg(feature = "cortex")]
mod route_cache_tests {
    //! Coverage for `MeshNode::rpc_route_for_service` — the
    //! per-service nRPC route cache landed in T1.3 of the
    //! 2026-05-19 perf audit. Pins:
    //!
    //!   - cache hits return the same `Arc<RpcRoute>` (so the
    //!     refcount-bump fast path is real, not silently
    //!     rebuilding);
    //!   - the cached route is byte-for-byte equivalent to what
    //!     the removed per-call code produced (any future tweak
    //!     to channel-name derivation can't silently diverge from
    //!     server-side service lookup);
    //!   - distinct services don't alias (the obvious safety
    //!     property);
    //!   - the [`RPC_ROUTE_CACHE_SOFT_CAP`] is honored — past
    //!     the cap, the lookup still returns a correct route but
    //!     stops growing the cache.
    use super::*;
    use std::net::SocketAddr;

    async fn build_node_for_test() -> Arc<MeshNode> {
        let addr: SocketAddr = "127.0.0.1:0".parse().unwrap();
        let cfg = MeshNodeConfig::new(addr, [0x17u8; 32]);
        Arc::new(
            MeshNode::new(EntityKeypair::generate(), cfg)
                .await
                .expect("MeshNode::new"),
        )
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn cached_lookup_returns_same_arc() {
        let node = build_node_for_test().await;
        let a = node.rpc_route_for_service("svc.alpha").expect("first");
        let b = node.rpc_route_for_service("svc.alpha").expect("second");
        assert!(
            Arc::ptr_eq(&a, &b),
            "repeat lookup must hit the cache (same Arc), not rebuild"
        );
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn cached_route_matches_freshly_computed() {
        let node = build_node_for_test().await;
        let service = "svc.beta";
        let cached = node.rpc_route_for_service(service).expect("cached");

        // Re-derive everything from scratch the way the pre-cache
        // code path did. Any future refactor of channel-name
        // derivation that diverges from server-side service
        // lookup will surface here.
        let expected_request =
            ChannelName::new(&format!("{service}.requests")).expect("request name");
        let expected_request_id = ChannelId::new(expected_request.clone());
        let expected_request_hash = expected_request_id.hash();
        let expected_stream_id = MeshNode::publish_stream_id(&expected_request_id);
        let self_origin = node.public_key_origin_hash();
        let expected_reply =
            ChannelName::new(&format!("{service}.replies.{self_origin:016x}")).expect("reply name");
        let expected_reply_hash = expected_reply.hash();

        assert_eq!(cached.request_channel.as_str(), expected_request.as_str());
        assert_eq!(cached.request_channel_hash, expected_request_hash);
        assert_eq!(cached.request_stream_id, expected_stream_id);
        assert_eq!(cached.reply_channel.as_str(), expected_reply.as_str());
        assert_eq!(cached.reply_hash, expected_reply_hash);
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn distinct_services_get_distinct_routes() {
        let node = build_node_for_test().await;
        let a = node.rpc_route_for_service("svc.one").expect("one");
        let b = node.rpc_route_for_service("svc.two").expect("two");
        assert_ne!(a.request_channel.as_str(), b.request_channel.as_str());
        assert_ne!(a.request_channel_hash, b.request_channel_hash);
        assert_ne!(a.reply_channel.as_str(), b.reply_channel.as_str());
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn invalid_service_name_returns_err() {
        let node = build_node_for_test().await;
        // Uppercase is rejected by `ChannelName::validate`.
        assert!(node.rpc_route_for_service("SVC.Bad").is_err());
        // And nothing got cached for the rejected name.
        assert!(node.rpc_route_cache.get("SVC.Bad").is_none());
    }

    #[tokio::test(flavor = "multi_thread", worker_threads = 2)]
    async fn cache_respects_soft_cap() {
        let node = build_node_for_test().await;
        // Push well past the cap, single-threaded, so the
        // size-then-insert check is non-racy.
        let overflow = 64usize;
        for i in 0..(RPC_ROUTE_CACHE_SOFT_CAP + overflow) {
            let svc = format!("svc.cap.{i:04}");
            let route = node
                .rpc_route_for_service(&svc)
                .expect("build must succeed regardless of cap");
            // Overflow callers still get a correct route — just
            // not a cached one.
            assert_eq!(
                route.request_channel.as_str(),
                format!("{svc}.requests").as_str()
            );
        }
        assert!(
            node.rpc_route_cache.len() <= RPC_ROUTE_CACHE_SOFT_CAP,
            "cache size {} exceeds soft cap {}",
            node.rpc_route_cache.len(),
            RPC_ROUTE_CACHE_SOFT_CAP,
        );
        // Past the cap, lookups for new services should *not*
        // grow the map (they bypass the insert branch). Lookups
        // for already-cached services still hit.
        let len_before = node.rpc_route_cache.len();
        let _ = node.rpc_route_for_service("svc.overflow.new").unwrap();
        assert_eq!(
            node.rpc_route_cache.len(),
            len_before,
            "post-cap insert must be a no-op for new services"
        );
        // And a previously-cached service still returns the same Arc.
        let first = node.rpc_route_for_service("svc.cap.0000").unwrap();
        let second = node.rpc_route_for_service("svc.cap.0000").unwrap();
        assert!(Arc::ptr_eq(&first, &second));
    }
}

#[cfg(test)]
mod routed_forward_tests {
    //! PERF_AUDIT §2.5 — the routed-forward branch of
    //! `dispatch_packet` patches the routing header in place via
    //! `try_into_mut` + `write_at` when the inbound `Bytes` is
    //! sole-owned, and falls back to the legacy rebuild when a
    //! clone is outstanding. Both branches MUST produce identical
    //! wire bytes: the header re-serialized with the bumped
    //! hop_count / decremented ttl, the body untouched.
    use super::*;
    use bytes::Bytes;

    /// Replicates `dispatch_packet`'s forward-branch logic on a
    /// synthetic routed packet, exercising BOTH match arms, and
    /// asserts byte equality. A drift in `write_at` offsets (fast
    /// path) versus `to_bytes` layout (slow path) — or a branch
    /// forgetting `forward()` — fails here without standing up a
    /// three-node mesh.
    #[test]
    fn forward_fast_and_slow_paths_produce_identical_wire_bytes() {
        let header = RoutingHeader::new(0xDDDD_EEEE_FFFF_0001, 0xABCD_1234, 7);
        let body: &[u8] = b"opaque-encrypted-inner-packet-bytes-not-touched-by-forwarding";
        let mut packet = bytes::BytesMut::with_capacity(ROUTING_HEADER_SIZE + body.len());
        packet.extend_from_slice(&header.to_bytes());
        packet.extend_from_slice(body);
        let original = packet.freeze();

        // Parse the way dispatch_packet does, then forward().
        let routing_header =
            RoutingHeader::from_bytes(&original[..ROUTING_HEADER_SIZE]).expect("header parses");
        let mut fwd_header = routing_header;
        assert!(fwd_header.forward(), "ttl=7 must be forwardable");

        // Slow path (refcount > 1): hold a clone so try_into_mut
        // must fail, then rebuild like the Err arm.
        let data_shared = original.clone();
        let outstanding_clone = original.clone();
        let slow = match data_shared.try_into_mut() {
            Ok(_) => panic!("refcount > 1 must take the slow path"),
            Err(orig_data) => {
                let mut new_data = bytes::BytesMut::with_capacity(orig_data.len());
                new_data.extend_from_slice(&fwd_header.to_bytes());
                new_data.extend_from_slice(&orig_data[ROUTING_HEADER_SIZE..]);
                new_data.freeze()
            }
        };
        drop(outstanding_clone);

        // Fast path (sole owner): in-place write_at.
        let fast = match original.try_into_mut() {
            Ok(mut mut_data) => {
                fwd_header.write_at(&mut mut_data[..ROUTING_HEADER_SIZE]);
                mut_data.freeze()
            }
            Err(_) => panic!("sole-owned Bytes must take the fast path"),
        };

        assert_eq!(
            fast, slow,
            "fast (in-place write_at) and slow (rebuild) forward paths must be wire-identical"
        );
        // Pin the semantic deltas: ttl decremented (byte 2),
        // hop_count incremented (byte 3), body untouched.
        let reparsed = RoutingHeader::from_bytes(&fast[..ROUTING_HEADER_SIZE]).unwrap();
        assert_eq!(reparsed.ttl, 6, "forward() must decrement ttl");
        assert_eq!(reparsed.hop_count, 1, "forward() must increment hop_count");
        assert_eq!(reparsed.dest_id, routing_header.dest_id);
        assert_eq!(reparsed.src_id, routing_header.src_id);
        assert_eq!(
            &fast[ROUTING_HEADER_SIZE..],
            body,
            "forwarding must never touch the encrypted body"
        );
    }

    /// The fast path requires the inbound `Bytes` to be truly
    /// sole-owned. A `Bytes` produced by `BytesMut::split()` whose
    /// parent handle is still alive (the default `PacketReceiver`
    /// shape — `recv_buf.split().freeze()` with `recv_buf`
    /// retaining the allocation tail) is NOT unique, and must fall
    /// back to the copying path rather than corrupt shared memory.
    #[test]
    fn split_with_live_parent_takes_slow_path() {
        let mut parent = bytes::BytesMut::with_capacity(256);
        parent.extend_from_slice(&RoutingHeader::new(1, 2, 3).to_bytes());
        parent.extend_from_slice(b"body");
        let child: Bytes = parent.split().freeze();
        // `parent` still holds the allocation tail — the frozen
        // child must not be considered unique.
        assert!(
            child.try_into_mut().is_err(),
            "split().freeze() with the parent BytesMut alive must take the slow path — \
             if this ever starts succeeding, re-evaluate PERF_AUDIT §2.2/§2.5: the \
             in-place forward fast path would then fire on the default ingress too"
        );
        drop(parent);
    }
}

// NOTE: this test module lives at the END of the file ON PURPOSE. The
// heartbeat drift check in session.rs treats the FIRST column-0
// `#[cfg(test)] mod` as the production/test boundary, so a test module
// placed earlier would hide the real `session.build_heartbeat()` caller
// from `mesh_rs_production_callers_match_allowlist`.
#[cfg(test)]
mod committed_flush_stall_tests {
    use super::*;

    /// #4: the committed-prefix retry must be bounded. Against a receiver
    /// that never grants credit, `await_credit_or_stall` returns a
    /// terminal `Transport` error once `COMMITTED_FLUSH_STALL_BUDGET`
    /// elapses instead of looping forever. Paused time auto-advances as
    /// the backoff sleeps complete, so this runs instantly.
    #[tokio::test(start_paused = true)]
    async fn committed_flush_retry_is_bounded_by_stall_budget() {
        let cap = Duration::from_millis(200);
        let deadline = tokio::time::Instant::now() + COMMITTED_FLUSH_STALL_BUDGET;
        let mut delay = Duration::from_millis(5);
        let mut iters = 0u32;
        loop {
            match await_credit_or_stall(&mut delay, cap, deadline).await {
                Ok(()) => {
                    iters += 1;
                    assert!(iters < 100_000, "retry must be bounded, not spin forever");
                }
                Err(StreamError::Transport(msg)) => {
                    assert!(
                        msg.contains("credit stalled"),
                        "terminal stall error: {msg}"
                    );
                    break;
                }
                Err(other) => panic!("unexpected error variant: {other}"),
            }
        }
        // Backoff caps at 200ms, so reaching the 30s budget takes on the
        // order of ~150 iterations — bounded, never the spin guard.
        assert!(iters > 0, "should back off at least once before giving up");
        assert!(
            iters < 10_000,
            "should reach the budget via capped backoff, got {iters}"
        );
    }

    /// A still-fresh deadline lets the retry continue (`Ok`) and doubles
    /// the backoff toward the cap.
    #[tokio::test(start_paused = true)]
    async fn await_credit_backs_off_while_under_deadline() {
        let cap = Duration::from_millis(200);
        let deadline = tokio::time::Instant::now() + Duration::from_secs(60);
        let mut delay = Duration::from_millis(5);
        match await_credit_or_stall(&mut delay, cap, deadline).await {
            Ok(()) => {}
            Err(e) => panic!("under deadline must continue (Ok), got {e}"),
        }
        assert_eq!(delay, Duration::from_millis(10), "backoff must double");
    }
}

#[cfg(test)]
mod stream_ack_batching_tests {
    //! STREAM_ACK_BATCHING Phase 1 (B-1..B-5): grouping-key contract,
    //! payload-budget chunk math, and multi-event control-frame
    //! round-trips. The wire-cadence bound ("M streams to one session
    //! ⇒ one grant packet per drain cycle, plus spill") follows from
    //! `group_grants_by_session` + `chunks(GRANT_EVENTS_PER_PACKET)`,
    //! both pinned here without spinning real sockets.
    use super::*;
    use crate::adapter::net::crypto::{NoiseHandshake, PacketCipher, StaticKeypair};
    use crate::adapter::net::protocol::NetHeader;
    use crate::adapter::net::subprotocol::stream_window::{STREAM_NACK_SIZE, STREAM_RESET_SIZE};

    /// Fixed-count framing budget for the fixed-size `StreamNack` /
    /// `StreamReset` frames — the reference the codec round-trip tests
    /// fill "a full packet's worth" against. Production packs these by
    /// actual size via [`pack_control_events`] (see `GRANT_EVENTS_PER_
    /// PACKET`), so the constants live here with their tests rather
    /// than in the module body.
    const NACK_EVENTS_PER_PACKET: usize =
        protocol::MAX_PAYLOAD_SIZE / (EventFrame::LEN_SIZE + STREAM_NACK_SIZE);
    const RESET_EVENTS_PER_PACKET: usize =
        protocol::MAX_PAYLOAD_SIZE / (EventFrame::LEN_SIZE + STREAM_RESET_SIZE);

    fn make_session_keys() -> (
        crate::adapter::net::crypto::SessionKeys,
        crate::adapter::net::crypto::SessionKeys,
    ) {
        let psk = [0x42u8; 32];
        let responder_kp = StaticKeypair::generate();
        let mut initiator = NoiseHandshake::initiator(&psk, &responder_kp.public).unwrap();
        let mut responder = NoiseHandshake::responder(&psk, &responder_kp).unwrap();
        let msg1 = initiator.write_message(&[]).unwrap();
        responder.read_message(&msg1).unwrap();
        let msg2 = responder.write_message(&[]).unwrap();
        initiator.read_message(&msg2).unwrap();
        (
            initiator.into_session_keys().unwrap(),
            responder.into_session_keys().unwrap(),
        )
    }

    fn session_at(addr: &str) -> Arc<NetSession> {
        let (_init, resp) = make_session_keys();
        Arc::new(NetSession::new(resp, addr.parse().unwrap(), 4, false))
    }

    fn pending(session: &Arc<NetSession>, addr: &str, consumed: u64) -> PendingStreamGrant {
        PendingStreamGrant {
            session: session.clone(),
            peer_addr: addr.parse().unwrap(),
            total_consumed: consumed,
        }
    }

    /// The chunk constants must (a) actually batch, (b) fill a packet
    /// without overflowing the payload budget, and (c) stay under the
    /// header's event-count cap — the payload budget must be the
    /// binding constraint.
    #[test]
    fn chunk_constants_fit_payload_and_event_caps() {
        for (per_packet, event_size) in [
            (GRANT_EVENTS_PER_PACKET, STREAM_WINDOW_SIZE),
            (NACK_EVENTS_PER_PACKET, STREAM_NACK_SIZE),
            (RESET_EVENTS_PER_PACKET, STREAM_RESET_SIZE),
        ] {
            assert!(per_packet > 1, "batching must batch");
            let frame = EventFrame::LEN_SIZE + event_size;
            assert!(
                per_packet * frame <= protocol::MAX_PAYLOAD_SIZE,
                "a full chunk must fit the payload budget"
            );
            assert!(
                (per_packet + 1) * frame > protocol::MAX_PAYLOAD_SIZE,
                "chunk must fill the packet (one more event would overflow)"
            );
            assert!(
                per_packet <= NetHeader::MAX_EVENTS_PER_PACKET as usize,
                "payload budget, not the event-count cap, must bind"
            );
        }
    }

    /// B-1 grouping-key contract: two DIFFERENT sessions behind the
    /// SAME peer address (e.g. a rotation mid-drain) must not share a
    /// batch — each owns its own AEAD cipher + control-seq counter.
    #[test]
    fn grouping_is_by_session_not_peer_addr() {
        let addr = "127.0.0.1:7001";
        let s1 = session_at(addr);
        let s2 = session_at(addr);
        let mut drained = HashMap::new();
        drained.insert((s1.session_id(), 10u64), pending(&s1, addr, 100));
        drained.insert((s2.session_id(), 10u64), pending(&s2, addr, 200));
        let grouped = group_grants_by_session(drained);
        assert_eq!(grouped.len(), 2, "distinct sessions must stay separate");
    }

    /// All streams of one session collapse into one batch, each
    /// exactly once, with its own `total_consumed`.
    #[test]
    fn grouping_collects_all_streams_of_one_session() {
        let addr = "127.0.0.1:7002";
        let s = session_at(addr);
        let mut drained = HashMap::new();
        for stream_id in 0..100u64 {
            drained.insert(
                (s.session_id(), stream_id),
                pending(&s, addr, stream_id * 10),
            );
        }
        let grouped = group_grants_by_session(drained);
        assert_eq!(grouped.len(), 1, "one session ⇒ one batch");
        let (_, peer_addr, grants) = &grouped[&s.session_id()];
        assert_eq!(*peer_addr, addr.parse().unwrap());
        let mut seen: Vec<(u64, u64)> = grants.clone();
        seen.sort_unstable();
        assert_eq!(
            seen,
            (0..100u64).map(|i| (i, i * 10)).collect::<Vec<_>>(),
            "every stream survives grouping exactly once with its value"
        );
    }

    /// The build step must NOT bump `credit_grants_sent` — that
    /// counter means "grant datagram sent", and the drainer bumps it
    /// per covered stream only after the chunk clears `send_to`.
    /// Pre-fix the bump ran at build time, overcounting whenever the
    /// send failed (review P2).
    #[test]
    fn build_session_control_events_does_not_bump_grants_sent() {
        let addr = "127.0.0.1:7005";
        let s = session_at(addr);
        let sid = 42u64;
        s.get_or_create_stream_for_packet(sid, true);

        let grants = vec![(sid, 1000u64)];
        let (entries, _nacks, _acks) = build_session_control_events(&s, &grants, false);
        assert_eq!(entries.len(), 1);

        let state = s.try_stream(sid).expect("stream exists");
        assert_eq!(
            state.credit_grants_sent(),
            0,
            "building the grant event must not count it as sent"
        );
        // The post-send bump is the drainer's job — one per grant
        // that actually cleared the socket.
        state.note_grant_sent();
        assert_eq!(state.credit_grants_sent(), 1);
    }

    /// Grant entries stay paired (stream id ↔ encoded event) so the
    /// post-send accounting hits the right streams, and NACK / SACK
    /// events are built only for gapped streams (SACK only when the
    /// peer supports ranges).
    #[test]
    fn build_session_control_events_pairs_ids_and_gates_gap_events() {
        use crate::adapter::net::subprotocol::stream_window::StreamAckRanges;

        let addr = "127.0.0.1:7006";
        let s = session_at(addr);
        // Stream 1: clean in-order receive. Stream 2: gapped (0
        // received, 5 out of order → head gap at 1).
        s.get_or_create_stream_for_packet(1, true)
            .with_reliability(|r| {
                assert!(r.on_receive(0));
            });
        s.get_or_create_stream_for_packet(2, true)
            .with_reliability(|r| {
                assert!(r.on_receive(0));
                assert!(r.on_receive(5));
            });

        let grants = vec![(1u64, 10u64), (2u64, 20u64)];
        let (entries, nacks, acks) = build_session_control_events(&s, &grants, true);

        assert_eq!(entries.len(), 2);
        for (sid, event) in &entries {
            let g = StreamWindow::decode(event).expect("grant event decodes");
            assert_eq!(g.stream_id, *sid, "entry id must match its encoded event");
        }

        assert_eq!(nacks.len(), 1, "only the gapped stream NACKs");
        let n = StreamNack::decode(&nacks[0]).expect("nack decodes");
        assert_eq!(n.stream_id, 2);
        assert_eq!(n.next_expected, 1);

        assert_eq!(acks.len(), 1, "only the gapped stream has SACK ranges");
        let a = StreamAckRanges::decode(&acks[0]).expect("ack ranges decode");
        assert_eq!(a.stream_id, 2);
        assert_eq!(a.ack_seq, 1);
        assert_eq!(a.ranges, vec![(5, 6)]);

        // Capability gate off ⇒ no SACK events, everything else same.
        let (_, _, acks_off) = build_session_control_events(&s, &grants, false);
        assert!(acks_off.is_empty(), "no ranges to a non-advertising peer");
    }

    /// The capability-gate cache sweep drops entries past the age
    /// bound and keeps fresh ones — the backstop that keeps the
    /// insert-on-lookup cache bounded under peer churn (review P2).
    #[test]
    fn ack_ranges_cache_sweep_drops_only_stale_entries() {
        let cache: DashMap<u64, (bool, Instant)> = DashMap::new();
        let stale_at = Instant::now() - ACK_RANGES_CAP_CACHE_MAX_AGE - Duration::from_secs(1);
        cache.insert(1, (true, stale_at));
        cache.insert(2, (false, stale_at));
        cache.insert(3, (true, Instant::now()));

        sweep_ack_ranges_cache(&cache, ACK_RANGES_CAP_CACHE_MAX_AGE);

        assert!(!cache.contains_key(&1), "stale positive entry swept");
        assert!(!cache.contains_key(&2), "stale negative entry swept");
        assert!(
            cache.contains_key(&3),
            "fresh entry survives — active peers keep their cached verdict"
        );
    }

    /// R-5 gate-cache invalidation (review CAPCACHE): a verdict cached
    /// before a peer's capability announcement is folded is stale for
    /// the whole TTL, so the drainer keeps the legacy path during the
    /// opening loss episode of a fresh transfer. `handle_capability_
    /// announcement` removes the peer's cache entry the instant the
    /// announcement folds; this pins that removal is what lets the
    /// next gate check re-resolve to `true` (rather than waiting for
    /// the TTL). Drives the real `peer_supports_ack_ranges` + fold.
    #[test]
    fn ack_ranges_gate_reresolves_after_announcement_invalidation() {
        use crate::adapter::net::behavior::capability::{CapabilityAnnouncement, CapabilitySet};
        use crate::adapter::net::behavior::fold::capability::CapabilityFold;
        use crate::adapter::net::behavior::fold::capability_bridge::translate_announcement;
        use crate::adapter::net::behavior::fold::Fold;

        let cache: DashMap<u64, (bool, Instant)> = DashMap::new();
        let session_id_to_node: DashMap<u64, u64> = DashMap::new();
        let fold: Fold<CapabilityFold> = Fold::new();

        let kp = crate::adapter::net::EntityKeypair::generate();
        let node_id = kp.node_id();
        let session_id = 0x5E5510_u64; // arbitrary session id
        session_id_to_node.insert(session_id, node_id);

        // Fold empty ⇒ gate resolves false and CACHES (false, now).
        assert!(!peer_supports_ack_ranges(
            &cache,
            &session_id_to_node,
            &fold,
            session_id
        ));
        assert_eq!(cache.get(&node_id).map(|e| e.value().0), Some(false));

        // Peer now advertises the tag; fold updated (as the dispatch
        // handler does before invalidating the cache).
        let caps = CapabilitySet::new().add_tag(ACK_RANGES_CAPABILITY_TAG.to_string());
        let ann = CapabilityAnnouncement::new(node_id, kp.entity_id().clone(), 1, caps);
        fold.apply(translate_announcement(&ann))
            .expect("fold apply");

        // Without invalidation the stale `false` still wins (the bug).
        assert!(
            !peer_supports_ack_ranges(&cache, &session_id_to_node, &fold, session_id),
            "cached false shadows the freshly-folded capability"
        );

        // The invalidation `handle_capability_announcement` now performs.
        cache.remove(&node_id);

        // Next check re-resolves through the fold ⇒ true.
        assert!(
            peer_supports_ack_ranges(&cache, &session_id_to_node, &fold, session_id),
            "after invalidation the gate must see the announced capability"
        );
    }

    /// R-5 (review DORMANT/CAPCACHE): the peer's advertisement — not
    /// local support — controls the SACK-range path. With an empty fold
    /// (the peer never announced `ACK_RANGES_CAPABILITY_TAG`) the gate
    /// resolves `false`, and the drainer ANDs that into `emit_ack_ranges`;
    /// so a gapped stream produces the legacy grant + NACK and NO
    /// `StreamAckRanges`, even though this node's own support is on.
    #[test]
    fn no_advertised_capability_keeps_sender_on_legacy_path() {
        use crate::adapter::net::behavior::fold::capability::CapabilityFold;
        use crate::adapter::net::behavior::fold::Fold;

        let cache: DashMap<u64, (bool, Instant)> = DashMap::new();
        let session_id_to_node: DashMap<u64, u64> = DashMap::new();
        let fold: Fold<CapabilityFold> = Fold::new();

        let session = session_at("127.0.0.1:7011");
        session_id_to_node.insert(session.session_id(), 0xBEEF_u64);

        // Peer never advertised ⇒ gate false. This is exactly the value
        // the drainer ANDs with `enable_stream_ack_ranges` to decide
        // whether to emit ranges.
        let supported =
            peer_supports_ack_ranges(&cache, &session_id_to_node, &fold, session.session_id());
        assert!(
            !supported,
            "no advertisement ⇒ legacy path even with local support enabled"
        );

        // A gapped receive stream: 0 received, 5 out of order ⇒ head gap
        // at 1 (so there IS a NACK and there WOULD be SACK ranges).
        session
            .get_or_create_stream_for_packet(3, true)
            .with_reliability(|r| {
                assert!(r.on_receive(0));
                assert!(r.on_receive(5));
            });

        let (grants, nacks, acks) =
            build_session_control_events(&session, &[(3u64, 10u64)], supported);
        assert_eq!(grants.len(), 1, "grant still emitted");
        assert_eq!(nacks.len(), 1, "legacy NACK still emitted for the gap");
        assert!(
            acks.is_empty(),
            "no StreamAckRanges to a peer that has not advertised support"
        );
    }

    /// Grants for different peers (different sessions) route to their
    /// own batches with their own addresses.
    #[test]
    fn grouping_keeps_peers_separate() {
        let a1 = "127.0.0.1:7003";
        let a2 = "127.0.0.1:7004";
        let s1 = session_at(a1);
        let s2 = session_at(a2);
        let mut drained = HashMap::new();
        drained.insert((s1.session_id(), 1u64), pending(&s1, a1, 11));
        drained.insert((s2.session_id(), 1u64), pending(&s2, a2, 22));
        let grouped = group_grants_by_session(drained);
        assert_eq!(grouped.len(), 2);
        assert_eq!(grouped[&s1.session_id()].1, a1.parse().unwrap());
        assert_eq!(grouped[&s2.session_id()].1, a2.parse().unwrap());
    }

    /// Decrypt-side pin for `chunk` → `build_subprotocol` framing:
    /// a maximal batched frame fits one wire packet and every event
    /// decodes back to its message. The receive path has always
    /// iterated the full event vector (`mesh.rs` StreamWindow /
    /// StreamNack / StreamReset arms), so this is the whole wire-
    /// compatibility story for B-2/B-3.
    fn roundtrip_full_chunk(payloads: Vec<Vec<u8>>, subprotocol_id: u16) -> Vec<Bytes> {
        let key = [0x5Au8; 32];
        let session_id = 0xACE0_FACEu64;
        let mut builder = PacketBuilder::new(&key, session_id);
        let events: Vec<Bytes> = payloads.iter().map(|p| Bytes::copy_from_slice(p)).collect();
        let pkt = builder.build_subprotocol(
            CONTROL_STREAM_ID,
            1,
            &events,
            PacketFlags::NONE,
            subprotocol_id,
        );
        assert!(
            pkt.len() <= protocol::MAX_PACKET_SIZE,
            "full chunk must fit one wire packet ({} > {})",
            pkt.len(),
            protocol::MAX_PACKET_SIZE
        );
        let header = NetHeader::from_bytes(&pkt[..HEADER_SIZE]).expect("header parses");
        assert_eq!(header.event_count as usize, events.len());
        assert_eq!(header.subprotocol_id, subprotocol_id);
        let rx = PacketCipher::new(&key, session_id);
        let nonce = u64::from_le_bytes(pkt[16..24].try_into().unwrap());
        let aad = header.aad();
        let mut buf = bytes::BytesMut::from(&pkt[HEADER_SIZE..]);
        let n = rx
            .decrypt_in_place(nonce, &aad, &mut buf[..])
            .expect("decrypt succeeds");
        EventFrame::read_events(buf.split_to(n).freeze(), header.event_count)
    }

    #[test]
    fn full_grant_chunk_roundtrips_as_one_packet() {
        let grants: Vec<StreamWindow> = (0..GRANT_EVENTS_PER_PACKET as u64)
            .map(|i| StreamWindow {
                stream_id: i,
                total_consumed: i * 7,
                ack_seq: i * 3,
            })
            .collect();
        let recovered = roundtrip_full_chunk(
            grants.iter().map(|g| g.encode().to_vec()).collect(),
            SUBPROTOCOL_STREAM_WINDOW,
        );
        assert_eq!(
            recovered.len(),
            grants.len(),
            "every grant survives framing"
        );
        for (event, g) in recovered.iter().zip(&grants) {
            assert_eq!(StreamWindow::decode(event).unwrap(), *g);
        }
    }

    #[test]
    fn full_nack_chunk_roundtrips_as_one_packet() {
        let nacks: Vec<StreamNack> = (0..NACK_EVENTS_PER_PACKET as u64)
            .map(|i| StreamNack {
                stream_id: i,
                next_expected: i + 1,
                missing_bitmap: i | 1,
            })
            .collect();
        let recovered = roundtrip_full_chunk(
            nacks.iter().map(|n| n.encode().to_vec()).collect(),
            SUBPROTOCOL_STREAM_NACK,
        );
        assert_eq!(recovered.len(), nacks.len());
        for (event, n) in recovered.iter().zip(&nacks) {
            assert_eq!(StreamNack::decode(event).unwrap(), *n);
        }
    }

    #[test]
    fn full_reset_chunk_roundtrips_as_one_packet() {
        let resets: Vec<StreamReset> = (0..RESET_EVENTS_PER_PACKET as u64)
            .map(|i| StreamReset { stream_id: i })
            .collect();
        let recovered = roundtrip_full_chunk(
            resets.iter().map(|r| r.encode().to_vec()).collect(),
            SUBPROTOCOL_STREAM_RESET,
        );
        assert_eq!(recovered.len(), resets.len());
        for (event, r) in recovered.iter().zip(&resets) {
            assert_eq!(StreamReset::decode(event).unwrap(), *r);
        }
    }

    /// Overflow spill (B-5): a batch larger than one packet's budget
    /// splits into ceil(N / per-packet) chunks, none over budget,
    /// with no event dropped.
    #[test]
    fn oversized_grant_batch_spills_without_loss() {
        let total = GRANT_EVENTS_PER_PACKET * 2 + 122;
        let events: Vec<Bytes> = (0..total as u64)
            .map(|i| {
                Bytes::copy_from_slice(
                    &StreamWindow {
                        stream_id: i,
                        total_consumed: i,
                        ack_seq: 0,
                    }
                    .encode(),
                )
            })
            .collect();
        let chunks: Vec<&[Bytes]> = events.chunks(GRANT_EVENTS_PER_PACKET).collect();
        assert_eq!(chunks.len(), 3, "ceil(2N+122 / N) = 3 packets");
        assert_eq!(
            chunks.iter().map(|c| c.len()).sum::<usize>(),
            total,
            "no grant dropped by the spill"
        );
        for c in &chunks {
            assert!(EventFrame::calculate_size(c) <= protocol::MAX_PAYLOAD_SIZE);
        }
    }

    /// R-4 size-aware packing (review ACKCHUNK/H5): variable-size
    /// `StreamAckRanges` events pack by ACTUAL size, so a batch of
    /// small one-range events fills far fewer packets than the old
    /// worst-case count (payload / 272 B ≈ 29 events/packet) — while
    /// every chunk still fits the payload budget and no event is lost.
    #[test]
    fn pack_control_events_fills_by_size_not_worst_case() {
        // 200 single-range SACK events (one range each → 32 wire B,
        // 36 B framed). Worst-case chunking (StreamAckRanges::MAX_SIZE
        // = 272 B) would have shipped ~29/packet ⇒ ≥7 packets.
        let events: Vec<Bytes> = (0..200u64)
            .map(|i| {
                Bytes::from(
                    StreamAckRanges {
                        stream_id: i,
                        ack_seq: 0,
                        ranges: vec![(10 * i + 1, 10 * i + 2)],
                    }
                    .encode(),
                )
            })
            .collect();

        let ranges = pack_control_events(&events);

        // Every event covered exactly once, in order, no gaps/overlap.
        let covered: usize = ranges.iter().map(|r| r.len()).sum();
        assert_eq!(covered, events.len(), "no event dropped by packing");
        let mut next = 0usize;
        for r in &ranges {
            assert_eq!(r.start, next, "chunks are contiguous and in order");
            next = r.end;
        }
        // Each chunk fits the payload budget.
        for r in &ranges {
            assert!(
                EventFrame::calculate_size(&events[r.clone()]) <= protocol::MAX_PAYLOAD_SIZE,
                "a packed chunk must fit the payload budget"
            );
        }
        // Density: small events pack far below the worst-case bound.
        // 200 × 36 B ≈ 7.2 KiB ⇒ one packet at an ~8 KiB budget.
        let worst_case_packets = events.len().div_ceil(
            protocol::MAX_PAYLOAD_SIZE / (EventFrame::LEN_SIZE + StreamAckRanges::MAX_SIZE),
        );
        assert!(
            ranges.len() < worst_case_packets,
            "size packing ({} packets) must beat worst-case count ({})",
            ranges.len(),
            worst_case_packets
        );
    }

    /// A single event larger than the budget still ships alone rather
    /// than producing an empty chunk (the `i > start` guard).
    #[test]
    fn pack_control_events_lone_oversized_event_ships_alone() {
        let big = Bytes::from(vec![0u8; protocol::MAX_PAYLOAD_SIZE + 10]);
        let small = Bytes::from_static(b"x");
        let events = vec![small.clone(), big, small];
        let ranges = pack_control_events(&events);
        // small | big-alone | small — three chunks, none empty.
        assert_eq!(ranges.len(), 3);
        assert!(ranges.iter().all(|r| !r.is_empty()));
    }
}
